import { Logger } from '@nestjs/common';
import { OnEvent } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { AppConfigService } from 'src/app-config/app-config.service';
import { User } from 'src/users/entities/user.entity';
import { DataSource, Repository } from 'typeorm';
import { AuthService } from '../auth.service';

export class CreateAdminEvent {
	private readonly logger = new Logger(CreateAdminEvent.name);
	constructor(
		private readonly authService: AuthService,
		private readonly appConfigService: AppConfigService,
		@InjectRepository(User)
		private readonly userRepository: Repository<User>,
		private readonly dataSource: DataSource,
	) {}

	@OnEvent('app.ready')
	async handle() {
		try {
			const queryRunner = this.dataSource.createQueryRunner('master');
			const userEmail = this.appConfigService.adminInfo.email;
			const userPassword = this.appConfigService.adminInfo.password;
			if (!userEmail || !userPassword) {
				this.logger.debug(
					'Admin credentials not configured, skipping admin creation',
				);
				return;
			}

			const user = await queryRunner.connect().then(() => {
				return this.userRepository.manager.findOne(User, {
					where: { email: userEmail },
				});
			});

			if (user) {
				this.logger.debug(`Admin user already exists: ${userEmail}`);
				return;
			}
			const newUser = await this.authService.signUp(
				userEmail,
				userPassword,
				true,
			);
			this.logger.log(`Admin user created: ${newUser?.email}`);
		} catch (error) {
			this.logger.error(
				`Error creating admin user: ${error.message}`,
				error.stack,
			);
		}
	}
}

import {
	ExecutionContext,
	Injectable,
	Logger,
	UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { AuthGuard } from '@nestjs/passport';
import { Request } from 'express';
import { ROLES_KEY } from '../decorator/roles.decorator';

interface JwtPayload {
	roles?: string[];
}

@Injectable()
export class JwtAuthGuard extends AuthGuard('jwt') {
	private readonly logger = new Logger(JwtAuthGuard.name);
	constructor(
		private readonly reflector: Reflector,
		private readonly jwtService: JwtService,
	) {
		super();
	}

	async canActivate(context: ExecutionContext) {
		const canActivate = await super.canActivate(context);
		if (!canActivate) {
			this.logger.error('User is not authenticated');
			return false;
		}

		const requiredRoles = this.reflector.getAllAndOverride<string[]>(
			ROLES_KEY,
			[context.getHandler(), context.getClass()],
		);

		if (!requiredRoles) {
			return true;
		}

		const request = context.switchToHttp().getRequest<Request>();

		const authHeader = request.headers.authorization;
		const token = authHeader?.split(' ')[1];
		if (!token) {
			throw new UnauthorizedException('No token provided');
		}

		const payload = this.jwtService.verify(token);

		const userRoles: string[] = payload.roles || [];

		const hasRole = () =>
			requiredRoles
				? requiredRoles.some((role) => userRoles.includes(role))
				: true;

		if (!hasRole()) {
			throw new UnauthorizedException('Insufficient permissions');
		}
		return true;
	}
}

import { Injectable } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';

@Injectable()
export class OptionalAuthGuard extends AuthGuard('jwt') {
	handleRequest(err, user) {
		return user || null;
	}
}

import {
	CanActivate,
	ExecutionContext,
	Injectable,
	Logger,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { WsException } from '@nestjs/websockets';
import { Socket } from 'socket.io';
import { ROLES_KEY } from '../decorator/roles.decorator';

interface WsJwtPayload {
	sub?: string;
	roles?: string[];
	[key: string]: any;
}

/**
 * Guard WebSocket para autenticação JWT
 * Valida token no handshake e verifica roles quando necessário
 */
@Injectable()
export class WsJwtGuard implements CanActivate {
	private readonly logger = new Logger(WsJwtGuard.name);

	constructor(
		private readonly jwtService: JwtService,
		private readonly reflector: Reflector,
	) {}

	canActivate(context: ExecutionContext): boolean {
		try {
			const client: Socket = context.switchToWs().getClient<Socket>();
			const token = this.extractTokenFromHandshake(client);

			if (!token) {
				throw new WsException('Token not provided');
			}

			const payload = this.jwtService.verify(token);

			// Anexa o payload ao client para uso posterior
			client.data.user = payload;

			// Verifica roles se necessário
			const requiredRoles = this.reflector.getAllAndOverride<string[]>(
				ROLES_KEY,
				[context.getHandler(), context.getClass()],
			);

			if (requiredRoles) {
				const userRoles: string[] = payload.roles || [];
				const hasRole = requiredRoles.some((role: string) =>
					userRoles.includes(role),
				);

				if (!hasRole) {
					this.logger.warn(
						`User ${String(payload.sub)} lacks required roles: ${requiredRoles.join(', ')}`,
					);
					throw new WsException('Insufficient permissions');
				}
			}

			return true;
		} catch (error: any) {
			this.logger.error(
				`WebSocket authentication failed: ${error instanceof Error ? error.message : String(error)}`,
			);
			throw new WsException('Authentication failed');
		}
	}

	private extractTokenFromHandshake(client: Socket): string | null {
		// Tenta extrair token de várias fontes
		const authHeader = client.handshake.headers.authorization;
		const queryToken = client.handshake.auth?.token;
		const queryParam = client.handshake.query?.token;

		if (authHeader && typeof authHeader === 'string') {
			const [type, token] = authHeader.split(' ');
			return type === 'Bearer' ? token : null;
		}

		return (queryToken || queryParam) as string | null;
	}
}

import { Controller, Get, Logger, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiTags } from '@nestjs/swagger';
import { SWAGGER_AUTH_SCHEME } from 'src/common/swagger/swagger-auth.constants';
import { Roles } from './decorator/roles.decorator';
import { JwtAuthGuard } from './guard/jwt-auth.guard';
import { PasswordEncryption } from 'src/encryption/password-encryption.provider';
import { PasswordMigrationService } from 'src/encryption/password-migration.service';
import { RolesEnum } from 'src/users/enum/roles.enum';

@ApiTags('Auth Password Migration')
@Controller('auth/password-migration')
@UseGuards(JwtAuthGuard)
@Roles(RolesEnum.ADMIN)
@ApiBearerAuth(SWAGGER_AUTH_SCHEME)
export class PasswordMigrationController {
	private readonly logger = new Logger(PasswordMigrationController.name);

	constructor(
		private readonly passwordMigration: PasswordMigrationService,
		private readonly passwordEncryption: PasswordEncryption,
	) {}

	@Get('status')
	async getMigrationStatus() {
		const stats = await this.passwordMigration.getHashingStatistics();
		const currentAlgorithm = this.passwordEncryption.getAlgorithm();

		const totalUsers = Object.values(stats).reduce(
			(sum, count) => sum + count,
			0,
		);

		const needsMigration = Object.entries(stats)
			.filter(([algo]) => algo !== currentAlgorithm)
			.reduce((sum, [, count]) => sum + count, 0);

		const migrationProgress =
			totalUsers > 0
				? ((totalUsers - needsMigration) / totalUsers) * 100
				: 100;

		this.logger.log(
			`Migration status requested: ${migrationProgress.toFixed(1)}% complete`,
		);

		return {
			currentAlgorithm,
			totalUsers,
			needsMigration,
			migrationProgress: `${migrationProgress.toFixed(1)}%`,
			statistics: stats,
			details: {
				scrypt: {
					count: stats.scrypt,
					status:
						currentAlgorithm === 'scrypt' ? 'current' : 'legacy',
					description: 'Algoritmo nativo do Node.js, memory-hard',
				},
				bcrypt: {
					count: stats.bcrypt,
					status:
						currentAlgorithm === 'bcrypt' ? 'current' : 'legacy',
					description: 'Algoritmo amplamente testado e utilizado',
				},
				argon2: {
					count: stats.argon2,
					status:
						currentAlgorithm === 'argon2' ? 'current' : 'future',
					description: 'Estado da arte em segurança (recomendado)',
				},
				unknown: {
					count: stats.unknown,
					status: 'error',
					description: 'Formato de hash não reconhecido',
				},
			},
			migrationStrategy: {
				type: 'lazy-migration',
				description:
					'Senhas são migradas automaticamente no próximo login bem-sucedido',
				impact: 'zero-downtime',
			},
		};
	}

	@Get('current-algorithm')
	getCurrentAlgorithm() {
		const algorithm = this.passwordEncryption.getAlgorithm();

		const algorithmInfo = {
			scrypt: {
				name: 'Scrypt',
				security: 'Alta',
				performance: 'Média',
				memoryUsage: 'Alto',
				dependencies: 'Nativo (sem dependências)',
				recommendation: 'Boa escolha padrão',
			},
			bcrypt: {
				name: 'Bcrypt',
				security: 'Alta',
				performance: 'Lenta',
				memoryUsage: 'Baixo',
				dependencies: 'npm install bcrypt',
				recommendation: 'Padrão da indústria',
			},
			argon2: {
				name: 'Argon2',
				security: 'Muito Alta',
				performance: 'Configurável',
				memoryUsage: 'Configurável',
				dependencies: 'npm install argon2',
				recommendation: 'Máxima segurança (recomendado)',
			},
		};

		return {
			algorithm,
			info: algorithmInfo[algorithm] || { name: 'Unknown' },
		};
	}
}

import { Injectable, Logger, NotFoundException } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { AppConfigService } from 'src/app-config/app-config.service';
import { In, Repository } from 'typeorm';
import { ChapterRead } from '../entities/chapter-read.entity';
import { Chapter } from '../entities/chapter.entity';
import { ContentType } from '../enum/content-type.enum';
import { ScrapingStatus } from '../enum/scrapingStatus.enum';
import { ChapterUpdatedEvent } from './events/chapter-updated.event';

@Injectable()
export class ChapterService {
	private readonly logger = new Logger(ChapterService.name);
	constructor(
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		@InjectRepository(ChapterRead)
		private readonly chapterReadRepository: Repository<ChapterRead>,
		private readonly appConfig: AppConfigService,
		private readonly eventEmitter: EventEmitter2,
	) {}

	private urlImage(url: string): string {
		if (!url || url.startsWith('null') || url.startsWith('undefined'))
			return '';
		const appUrl = this.appConfig.apiUrl;
		return `${appUrl}${url}`;
	}

	async getChapter(idChapter: string, userId?: string) {
		const chapter = await this.chapterRepository
			.createQueryBuilder('chapter')
			.leftJoinAndSelect('chapter.book', 'book')
			.leftJoinAndSelect('chapter.pages', 'pages')
			.where('chapter.id = :id', { id: idChapter })
			.getOne();

		if (!chapter) {
			this.logger.warn(`Chapter with id ${idChapter} not found`);
			throw new NotFoundException(
				`Chapter with id ${idChapter} not found`,
			);
		}

		const previousChapter = await this.chapterRepository
			.createQueryBuilder('chapter')
			.where('chapter.bookId = :bookId', { bookId: chapter.book.id })
			.andWhere('chapter.index < :currentIndex', {
				currentIndex: chapter.index,
			})
			.orderBy('chapter.index', 'DESC')
			.select(['chapter.id'])
			.getOne();
		const nextChapter = await this.chapterRepository
			.createQueryBuilder('chapter')
			.where('chapter.bookId = :bookId', { bookId: chapter.book.id })
			.andWhere('chapter.index > :currentIndex', {
				currentIndex: chapter.index,
			})
			.orderBy('chapter.index', 'ASC')
			.select(['chapter.id'])
			.getOne();
		const maxIndexChapter = await this.chapterRepository
			.createQueryBuilder('chapter')
			.where('chapter.bookId = :bookId', { bookId: chapter.book.id })
			.select('MAX(chapter.index)', 'max')
			.getRawOne<any>();
		const totalChapters = maxIndexChapter?.max
			? Number(maxIndexChapter.max)
			: 0;
		const { book, ...chapterWithoutBook } = chapter;

		// Monta resposta baseada no tipo de conteúdo
		const baseResponse: Omit<Chapter, 'book'> & {
			previous?: string;
			next?: string;
			bookId: string;
			bookTitle: string;
			totalChapters: number;
			documentPath?: string | null;
		} = {
			...chapterWithoutBook,
			previous: previousChapter?.id,
			next: nextChapter?.id,
			bookId: book.id,
			bookTitle: book.title,
			totalChapters,
		};

		// Para IMAGE: retorna pages com URLs completas
		if (chapter.contentType === ContentType.IMAGE) {
			if (chapterWithoutBook.pages) {
				for (const page of chapterWithoutBook.pages) {
					page.path = this.urlImage(page.path);
				}
			}
		} else {
			// Remove pages para outros tipos para economizar banda
			(baseResponse as Partial<Chapter>).pages = undefined;
		}

		// Para DOCUMENT: converte documentPath para URL completa
		if (
			chapter.contentType === ContentType.DOCUMENT &&
			chapter.documentPath
		) {
			baseResponse.documentPath = this.urlImage(chapter.documentPath);
		}

		// Para TEXT: content já está no objeto, não precisa modificar

		if (userId) {
			this.markChapterAsRead(idChapter, userId).catch((err) =>
				this.logger.error(err),
			);
		}

		return baseResponse;
	}

	async resetChapter(idChapter: string) {
		const chapter = await this.chapterRepository.findOne({
			where: { id: idChapter },
			relations: ['book'],
		});
		if (!chapter) {
			throw new NotFoundException(
				`Chapter with id ${idChapter} not found`,
			);
		}
		chapter.scrapingStatus = ScrapingStatus.PROCESS;
		await this.chapterRepository.save(chapter);
		this.eventEmitter.emit('chapters.updated', chapter);
		this.eventEmitter.emit(
			'chapter.updated',
			new ChapterUpdatedEvent(chapter.id, chapter.book.id),
		);
		return chapter;
	}

	async markChapterAsRead(chapterId: string, userId: string) {
		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
		});
		if (!chapter) {
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}

		// Verificar se já está marcado como lido
		const existing = await this.chapterReadRepository.findOne({
			where: {
				chapter: { id: chapterId },
				user: { id: userId },
			},
		});

		if (existing) {
			this.logger.log(
				`Chapter ${chapterId} already marked as read by user ${userId}`,
			);
			return existing;
		}

		const chapterRead = this.chapterReadRepository.create({
			chapter,
			user: { id: userId },
		});
		await this.chapterReadRepository.save(chapterRead);
		this.logger.log(
			`Chapter ${chapterId} marked as read by user ${userId}`,
		);
		return chapterRead;
	}

	async markChapterAsUnread(chapterId: string, userId: string) {
		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
		});
		if (!chapter) {
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}
		const result = await this.chapterReadRepository.delete({
			chapter: { id: chapterId },
			user: { id: userId },
		});
		this.logger.log(
			`Chapter ${chapterId} marked as unread by user ${userId}`,
		);
		return result;
	}

	async markChaptersAsRead(chapterIds: string[], userId: string) {
		const results: {
			chapterId: string;
			success: boolean;
			result?: ChapterRead;
			error?: string;
		}[] = [];
		for (const chapterId of chapterIds) {
			try {
				const result = await this.markChapterAsRead(chapterId, userId);
				results.push({ chapterId, success: true, result });
			} catch (error: any) {
				results.push({
					chapterId,
					success: false,
					error: error.message || 'Unknown error',
				});
			}
		}
		this.logger.log(
			`Marked ${results.filter((r) => r.success).length}/${chapterIds.length} chapters as read for user ${userId}`,
		);
		return results;
	}

	async markChaptersAsUnread(chapterIds: string[], userId: string) {
		const results: {
			chapterId: string;
			success: boolean;
			result?: import('typeorm').DeleteResult;
			error?: string;
		}[] = [];
		for (const chapterId of chapterIds) {
			try {
				const result = await this.markChapterAsUnread(
					chapterId,
					userId,
				);
				results.push({ chapterId, success: true, result });
			} catch (error: any) {
				results.push({
					chapterId,
					success: false,
					error: error.message || 'Unknown error',
				});
			}
		}
		this.logger.log(
			`Marked ${results.filter((r) => r.success).length}/${chapterIds.length} chapters as unread for user ${userId}`,
		);
		return results;
	}

	async listLessPages(pages: number) {
		const chapters = await this.chapterRepository
			.createQueryBuilder('chapter')
			.leftJoinAndSelect('chapter.pages', 'page')
			.loadRelationCountAndMap('chapter.pageCount', 'chapter.pages')
			.getMany();

		return (chapters as Array<Chapter & { pageCount: number }>)
			.filter((chapter) => chapter.pageCount < pages)
			.map((chapter) => {
				const { pages: _pages, ...rest } = chapter;
				return { ...rest, pageCount: chapter.pageCount };
			});
	}

	async resetAllChapters(ids: string[]) {
		const chapters = await this.chapterRepository.find({
			where: { id: In(ids) },
			relations: ['book'],
		});
		for (const chapter of chapters) {
			chapter.scrapingStatus = ScrapingStatus.PROCESS;
		}
		await this.chapterRepository.save(chapters);
		this.eventEmitter.emit('chapters.updated', chapters);
		for (const chapter of chapters) {
			this.eventEmitter.emit(
				'chapter.updated',
				new ChapterUpdatedEvent(chapter.id, chapter.book.id),
			);
		}
		return chapters;
	}

	/**
	 * Busca dados de múltiplos capítulos de uma vez para facilitar o download offline.
	 * Inclui páginas, URLs completas e referências de navegação (anterior/próximo).
	 */
	async getChaptersBatch(ids: string[]) {
		if (!ids || ids.length === 0) return [];

		const chapters = await this.chapterRepository.find({
			where: { id: In(ids) },
			relations: ['pages', 'book'],
		});

		if (chapters.length === 0) return [];

		// Agrupa capítulos por livro para calcular anterior/próximo eficientemente
		const bookIds = [...new Set(chapters.map((c) => c.book.id))];

		const allChaptersOfBooks = await this.chapterRepository.find({
			where: { book: { id: In(bookIds) } },
			select: ['id', 'index', 'book'],
			relations: ['book'],
			order: { index: 'ASC' },
		});

		const chaptersByBook = new Map<string, Chapter[]>();
		for (const ch of allChaptersOfBooks) {
			const bId = ch.book.id;
			if (!chaptersByBook.has(bId)) {
				chaptersByBook.set(bId, []);
			}
			chaptersByBook.get(bId)?.push(ch);
		}

		return chapters.map((chapter) => {
			const bookChapters = chaptersByBook.get(chapter.book.id) || [];
			const currentIndex = bookChapters.findIndex(
				(c) => c.id === chapter.id,
			);

			const previousChapter =
				currentIndex > 0 ? bookChapters[currentIndex - 1] : null;
			const nextChapter =
				currentIndex !== -1 && currentIndex < bookChapters.length - 1
					? bookChapters[currentIndex + 1]
					: null;

			const { book, ...chapterWithoutBook } = chapter;

			const baseResponse = {
				...chapterWithoutBook,
				previous: previousChapter?.id,
				next: nextChapter?.id,
				bookId: book.id,
				bookTitle: book.title,
				totalChapters:
					bookChapters.length > 0
						? Number(bookChapters[bookChapters.length - 1].index)
						: 0,
				documentPath:
					chapter.contentType === ContentType.DOCUMENT &&
					chapter.documentPath
						? this.urlImage(chapter.documentPath)
						: undefined,
			};

			// Converte caminhos para URLs completas
			if (
				chapter.contentType === ContentType.IMAGE &&
				baseResponse.pages
			) {
				for (const page of baseResponse.pages) {
					page.path = this.urlImage(page.path);
				}
			}

			return baseResponse;
		});
	}
}

import { createHash } from 'node:crypto';
import { promises as fs } from 'node:fs';
import { join } from 'node:path';
import { Readable } from 'node:stream';
import { Inject, Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { OnEvent } from '@nestjs/event-emitter';
import { Cron, CronExpression } from '@nestjs/schedule';
import { Redis } from 'ioredis';
import { ChapterUpdatedEvent } from 'src/books/chapters/events/chapter-updated.event';
import { BookEvents } from 'src/books/constants/events.constant';
import { REDIS_CLIENT } from 'src/redis/redis.constants';

@Injectable()
export class DownloadCacheService implements OnModuleInit {
	private readonly logger = new Logger(DownloadCacheService.name);
	private readonly CACHE_DIR = '/usr/src/app/data/cache/downloads';
	public readonly REDIS_PREFIX = 'download:cache:';
	public readonly TTL_SECONDS = 24 * 60 * 60; // 24 horas

	constructor(@Inject(REDIS_CLIENT) public readonly redis: Redis) {}

	async onModuleInit() {
		// Criar diretório de cache se não existir
		try {
			await fs.mkdir(this.CACHE_DIR, { recursive: true });
			this.logger.log(`Cache directory initialized: ${this.CACHE_DIR}`);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(
				`Failed to create cache directory: ${errorMessage}`,
			);
		}
	}

	/**
	 * Gera uma chave de cache baseada nos capítulos e formato
	 */
	public generateCacheKey(chapterIds: string[], format: string): string {
		// Ordenar IDs para garantir consistência
		const sortedIds = [...chapterIds].sort();
		const hashInput = `${sortedIds.join(',')}:${format}`;
		return createHash('sha256').update(hashInput).digest('hex');
	}

	/**
	 * Gera o caminho completo do arquivo no cache com sharding (2 caracteres)
	 */
	public getCacheFilePath(cacheKey: string, extension: string): string {
		const shard = cacheKey.substring(0, 2);
		return join(this.CACHE_DIR, shard, `${cacheKey}.${extension}`);
	}

	/**
	 * Garante que o diretório de shard existe
	 * @private
	 */
	private async ensureShardDir(cacheKey: string): Promise<string> {
		const shard = cacheKey.substring(0, 2);
		const shardDir = join(this.CACHE_DIR, shard);
		await fs.mkdir(shardDir, { recursive: true });
		return shardDir;
	}

	/**
	 * Retorna um stream do arquivo em cache (mais eficiente que buffer)
	 */
	async getStream(
		chapterIds: string[],
		format: string,
		extension: string,
	): Promise<Readable | null> {
		const cacheKey = this.generateCacheKey(chapterIds, format);
		const redisKey = `${this.REDIS_PREFIX}${cacheKey}`;

		try {
			// Verificar se a chave existe no Redis
			const cachedPath = await this.redis.get(redisKey);
			if (!cachedPath) {
				return null;
			}

			// Verificar se o arquivo existe (usando sharding)
			const filePath = this.getCacheFilePath(cacheKey, extension);
			try {
				await fs.access(filePath);
			} catch {
				this.logger.warn(
					`Cache file not found, removing Redis key: ${filePath}`,
				);
				await this.redis.del(redisKey);
				return null;
			}

			// Retornar stream do arquivo
			const { createReadStream } = await import('node:fs');
			return createReadStream(filePath);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(`Failed to get cache stream: ${errorMessage}`);
			return null;
		}
	}

	/**
	 * Verifica se existe um arquivo em cache válido
	 */
	async get(
		chapterIds: string[],
		format: string,
		extension: string,
	): Promise<Buffer | null> {
		const cacheKey = this.generateCacheKey(chapterIds, format);
		const redisKey = `${this.REDIS_PREFIX}${cacheKey}`;

		try {
			// Verificar se a chave existe no Redis
			const cachedPath = await this.redis.get(redisKey);
			if (!cachedPath) {
				return null;
			}

			// Verificar se o arquivo existe
			const filePath = this.getCacheFilePath(cacheKey, extension);
			try {
				await fs.access(filePath);
			} catch {
				this.logger.warn(
					`Cache file not found, removing Redis key: ${filePath}`,
				);
				await this.redis.del(redisKey);
				return null;
			}

			// Ler e retornar o arquivo
			return await fs.readFile(filePath);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(`Failed to get cache: ${errorMessage}`);
			return null;
		}
	}

	/**
	 * Armazena um arquivo no cache (com proteção contra corrupção)
	 */
	async set(
		chapterIds: string[],
		format: string,
		extension: string,
		data: Buffer,
	): Promise<void> {
		const cacheKey = this.generateCacheKey(chapterIds, format);
		const redisKey = `${this.REDIS_PREFIX}${cacheKey}`;

		try {
			await this.ensureShardDir(cacheKey);
			const filePath = this.getCacheFilePath(cacheKey, extension);
			const tempPath = `${filePath}.tmp`;

			// Salvar em arquivo temporário primeiro
			await fs.writeFile(tempPath, data);

			// Renomear para arquivo final (operação atômica)
			await fs.rename(tempPath, filePath);

			// Salvar referência no Redis com TTL
			await this.redis.set(redisKey, filePath, 'EX', this.TTL_SECONDS);

			this.logger.debug(
				`Cached file: ${filePath} (TTL: ${this.TTL_SECONDS}s)`,
			);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(`Failed to set cache: ${errorMessage}`);
		}
	}

	/**
	 * Invalida cache de um capítulo específico
	 */
	@OnEvent(BookEvents.CHAPTER_UPDATED)
	async invalidateChapter(event: ChapterUpdatedEvent): Promise<void> {
		this.logger.log(
			`Invalidating cache for chapter ${event.chapterId} (book ${event.bookId})`,
		);

		try {
			// Buscar todas as chaves no Redis que contêm este capítulo
			const pattern = `${this.REDIS_PREFIX}*`;
			const keys = await this.redis.keys(pattern);

			for (const key of keys) {
				// Extrair o hash da chave
				const cacheKey = key.replace(this.REDIS_PREFIX, '');

				// Ler o caminho do arquivo
				const filePath = await this.redis.get(key);
				if (!filePath) continue;

				// Verificar se o arquivo contém dados deste capítulo
				// Como não temos como saber diretamente, vamos invalidar baseado no bookId
				// Uma melhoria futura seria armazenar metadados no Redis

				// Deletar arquivo
				await fs.unlink(filePath).catch(() => {
					// Ignorar erro se arquivo não existe
				});

				// Remover do Redis
				await this.redis.del(key);

				this.logger.debug(`Removed cache: ${cacheKey}`);
			}
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(
				`Failed to invalidate chapter cache: ${errorMessage}`,
			);
		}
	}

	/**
	 * Auxiliar recursivo para listar arquivos de cache (Generator para RAM)
	 * @private
	 */
	private async *listCacheFiles(dir: string): AsyncGenerator<string> {
		let entries: import('node:fs').Dirent[];
		try {
			entries = await fs.readdir(dir, { withFileTypes: true });
		} catch (error) {
			return;
		}

		for (const entry of entries) {
			const res = join(dir, entry.name);
			if (entry.isDirectory()) {
				yield* this.listCacheFiles(res);
			} else if (!entry.name.endsWith('.tmp')) {
				yield res;
			}
		}
	}

	/**
	 * Limpa arquivos de cache expirados (cron job diário às 03:30 para evitar conflito)
	 */
	@Cron('30 3 * * *')
	async cleanExpiredCache(): Promise<void> {
		this.logger.log('Starting cache cleanup job (Memory-Safe)...');

		try {
			// Buscar todas as chaves no Redis
			const pattern = `${this.REDIS_PREFIX}*`;
			const keys = await this.redis.keys(pattern);

			// Criar set de caminhos válidos do Redis
			const validPaths = new Set<string>();
			if (keys.length > 0) {
				const values = await this.redis.mget(...keys);
				for (const val of values) {
					if (val) validPaths.add(val);
				}
			}

			// Deletar arquivos órfãos no disco
			let deletedCount = 0;
			for await (const filePath of this.listCacheFiles(this.CACHE_DIR)) {
				if (!validPaths.has(filePath)) {
					await fs.unlink(filePath).catch(() => {});
					deletedCount++;
				}
			}

			this.logger.log(
				`Cache cleanup completed. Deleted ${deletedCount} orphan files.`,
			);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(`Cache cleanup failed: ${errorMessage}`);
		}
	}

	/**
	 * Limpa todo o cache (útil para testes ou manutenção)
	 */
	async clearAll(): Promise<void> {
		this.logger.warn('Clearing all download cache');

		try {
			// Deletar todas as chaves do Redis
			const pattern = `${this.REDIS_PREFIX}*`;
			const keys = await this.redis.keys(pattern);
			if (keys.length > 0) {
				await this.redis.del(...keys);
			}

			// Deletar todos os arquivos do diretório de cache
			const files = await fs.readdir(this.CACHE_DIR);
			for (const file of files) {
				const filePath = join(this.CACHE_DIR, file);
				await fs.unlink(filePath);
			}

			this.logger.log(`Cleared ${keys.length} cache entries`);
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(`Failed to clear cache: ${errorMessage}`);
		}
	}
}

import { promises as fs } from 'node:fs';
import { PassThrough, Readable, pipeline } from 'node:stream';
import { promisify } from 'node:util';
import {
	Injectable,
	Logger,
	NotFoundException,
	StreamableFile,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { AppConfigService } from 'src/app-config/app-config.service';
import { In, Repository } from 'typeorm';
import { Book } from '../entities/book.entity';
import { Chapter } from '../entities/chapter.entity';
import { DownloadCacheService } from './download-cache.service';
import {
	BookDownloadFormat,
	DownloadBookBodyDto,
} from './dto/download-book-body.dto';
import {
	ChapterDownloadFormat,
	DownloadChapterQueryDto,
} from './dto/download-chapter-query.dto';
import { DownloadStrategy } from './strategies/download.strategy';
import { PdfStrategy } from './strategies/pdf.strategy';
import { PdfsZipStrategy } from './strategies/pdfs-zip.strategy';
import { ZipStrategy } from './strategies/zip.strategy';

const pipelineAsync = promisify(pipeline);

@Injectable()
export class DownloadService {
	private readonly logger = new Logger(DownloadService.name);
	private readonly CACHE_THRESHOLD_BYTES: number;

	constructor(
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		private readonly cacheService: DownloadCacheService,
		private readonly zipStrategy: ZipStrategy,
		private readonly pdfStrategy: PdfStrategy,
		private readonly pdfsZipStrategy: PdfsZipStrategy,
		private readonly configService: AppConfigService,
	) {
		// Converter MB para bytes
		const thresholdMB = this.configService.downloadCacheThresholdMB;
		this.CACHE_THRESHOLD_BYTES = thresholdMB * 1024 * 1024;
		this.logger.log(`Download cache threshold: ${thresholdMB}MB`);
	}

	/**
	 * Download de um capítulo individual
	 */
	async downloadChapter(
		chapterId: string,
		query: DownloadChapterQueryDto,
	): Promise<{
		file: StreamableFile;
		fileName: string;
		contentType: string;
	}> {
		this.logger.log(`Downloading chapter ${chapterId} as ${query.format}`);

		// Buscar capítulo com páginas e livro
		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
			relations: ['pages', 'book'],
		});

		if (!chapter) {
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}

		if (!chapter.pages || chapter.pages.length === 0) {
			throw new NotFoundException(
				`Chapter ${chapterId} has no pages available`,
			);
		}

		// Selecionar estratégia baseada no formato
		const strategy =
			query.format === ChapterDownloadFormat.PDF
				? this.pdfStrategy
				: this.zipStrategy;

		const fileName = this.generateFileName(
			[chapter],
			strategy.getExtension(),
		);

		// Verificar cache usando stream
		const cachedStream = await this.cacheService.getStream(
			[chapterId],
			query.format,
			strategy.getExtension(),
		);

		if (cachedStream) {
			this.logger.log(`Returning cached file for chapter ${chapterId}`);
			return {
				file: new StreamableFile(cachedStream, {
					type: strategy.getContentType(),
					disposition: `attachment; filename="${fileName}"`,
				}),
				fileName,
				contentType: strategy.getContentType(),
			};
		}

		// Estimar tamanho
		const estimatedSize = this.estimateSize([chapter]);
		this.logger.log(
			`Estimated size: ${(estimatedSize / 1024 / 1024).toFixed(2)}MB`,
		);

		// Decidir estratégia: buffer (pequeno) ou streaming (grande)
		if (estimatedSize < this.CACHE_THRESHOLD_BYTES) {
			return this.downloadWithBufferCache(
				[chapter],
				strategy,
				[chapterId],
				query.format,
				fileName,
			);
		}
		return this.downloadWithStreamCache(
			[chapter],
			strategy,
			[chapterId],
			query.format,
			fileName,
		);
	}

	/**
	 * Download de um livro com capítulos selecionados
	 */
	async downloadBook(
		bookId: string,
		dto: DownloadBookBodyDto,
	): Promise<{
		file: StreamableFile;
		fileName: string;
		contentType: string;
	}> {
		const requestedIds = dto.chapterIds || [];
		const downloadAll = requestedIds.length === 0;
		this.logger.log(
			`Downloading book ${bookId} with ${downloadAll ? 'all' : requestedIds.length} chapters as ${dto.format}`,
		);

		// Buscar livro
		const book = await this.bookRepository.findOne({
			where: { id: bookId },
		});

		if (!book) {
			throw new NotFoundException(`Book with id ${bookId} not found`);
		}

		// Buscar capítulos (todos ou selecionados)
		let chapters: Chapter[];
		if (downloadAll) {
			// Buscar todos os capítulos do livro
			chapters = await this.chapterRepository.find({
				where: { book: { id: bookId } },
				relations: ['pages'],
				order: { index: 'ASC' },
			});
		} else {
			// Buscar capítulos selecionados
			chapters = await this.chapterRepository.find({
				where: {
					id: In(requestedIds),
					book: { id: bookId },
				},
				relations: ['pages'],
				order: { index: 'ASC' },
			});

			if (chapters.length !== requestedIds.length) {
				this.logger.warn(
					`Requested ${requestedIds.length} chapters, but only ${chapters.length} were found`,
				);
			}
		}

		// Verificar se há páginas
		const totalPages = chapters.reduce(
			(sum, ch) => sum + (ch.pages?.length || 0),
			0,
		);
		if (totalPages === 0) {
			throw new NotFoundException(
				'No pages available for the selected chapters',
			);
		}

		// Determinar estratégia baseada no formato
		let strategy: ZipStrategy | PdfsZipStrategy;
		let formatKey: string;

		if (dto.format === BookDownloadFormat.PDFS_ZIP) {
			// ZIP de PDFs: gerar PDF para cada capítulo e empacotar
			formatKey = 'pdfs_zip';
			strategy = this.pdfsZipStrategy;
			this.logger.log('Using PDFs ZIP strategy');
		} else {
			// ZIP de imagens
			formatKey = 'images_zip';
			strategy = this.zipStrategy;
		}

		// Obter IDs dos capítulos para cache
		const chapterIdsForCache = chapters.map((ch) => ch.id);

		const fileName = this.generateFileName(
			chapters,
			strategy.getExtension(),
			book.title,
		);

		// Verificar cache usando stream
		const cachedStream = await this.cacheService.getStream(
			chapterIdsForCache,
			formatKey,
			strategy.getExtension(),
		);

		if (cachedStream) {
			this.logger.log(`Returning cached file for book ${bookId}`);
			return {
				file: new StreamableFile(cachedStream, {
					type: strategy.getContentType(),
					disposition: `attachment; filename="${fileName}"`,
				}),
				fileName,
				contentType: strategy.getContentType(),
			};
		}

		// Estimar tamanho
		const estimatedSize = this.estimateSize(chapters);
		this.logger.log(
			`Estimated size: ${(estimatedSize / 1024 / 1024).toFixed(2)}MB for ${chapters.length} chapters`,
		);

		// Decidir estratégia: buffer (pequeno) ou streaming (grande)
		if (estimatedSize < this.CACHE_THRESHOLD_BYTES) {
			return this.downloadWithBufferCache(
				chapters,
				strategy,
				chapterIdsForCache,
				formatKey,
				fileName,
			);
		}
		return this.downloadWithStreamCache(
			chapters,
			strategy,
			chapterIdsForCache,
			formatKey,
			fileName,
		);
	}

	/**
	 * Gera um nome de arquivo descritivo
	 */
	private generateFileName(
		chapters: Chapter[],
		extension: string,
		bookTitle?: string,
	): string {
		if (chapters.length === 1) {
			const chapter = chapters[0];
			const sanitized = this.sanitizeFileName(
				`Cap_${chapter.index}_${chapter.title}`,
			);
			return `${sanitized}.${extension}`;
		}

		const sanitized = this.sanitizeFileName(bookTitle || 'Full_Book');
		return `${sanitized}_${chapters.length}_cap.${extension}`;
	}

	/**
	 * Remove caracteres inválidos de nomes de arquivo
	 */
	private sanitizeFileName(name: string): string {
		// biome-ignore lint/suspicious/noControlCharactersInRegex: intentional sanitization of control characters
		// eslint-disable-next-line no-control-regex
		return name.replace(/[<>:"/\\|?*\x00-\x1F]/g, '_').trim();
	}

	/**
	 * Converte um stream em buffer
	 */
	private async streamToBuffer(stream: Readable): Promise<Buffer> {
		const chunks: Uint8Array[] = [];
		for await (const chunk of stream) {
			chunks.push(Buffer.from(chunk));
		}
		return Buffer.concat(chunks);
	}

	/**
	 * Estima o tamanho do arquivo baseado nas páginas
	 */
	private estimateSize(chapters: Chapter[]): number {
		const totalPages = chapters.reduce(
			(sum, ch) => sum + (ch.pages?.length || 0),
			0,
		);
		const avgPageSize = 2 * 1024 * 1024; // 2MB por página (estimativa conservadora)
		return totalPages * avgPageSize;
	}

	/**
	 * Download com estratégia de buffer (arquivos pequenos)
	 */
	private async downloadWithBufferCache(
		chapters: Chapter[],
		strategy: DownloadStrategy,
		cacheKey: string[],
		formatKey: string,
		fileName: string,
	): Promise<{
		file: StreamableFile;
		fileName: string;
		contentType: string;
	}> {
		this.logger.log('Using buffer cache strategy');

		// Gerar arquivo
		const bookTitle = chapters[0]?.book?.title || 'Livro';
		const file = await strategy.generate(chapters, bookTitle);

		// Converter para buffer
		const buffer = await this.streamToBuffer(file.getStream());

		// Cachear (fire-and-forget)
		this.cacheService
			.set(cacheKey, formatKey, strategy.getExtension(), buffer)
			.catch((err) =>
				this.logger.error(`Cache save failed: ${err.message}`),
			);

		// Retornar buffer
		const stream = Readable.from(buffer);
		return {
			file: new StreamableFile(stream, {
				type: strategy.getContentType(),
				disposition: `attachment; filename="${fileName}"`,
			}),
			fileName,
			contentType: strategy.getContentType(),
		};
	}

	/**
	 * Download com estratégia de streaming (arquivos grandes)
	 */
	private async downloadWithStreamCache(
		chapters: Chapter[],
		strategy: DownloadStrategy,
		cacheKey: string[],
		formatKey: string,
		fileName: string,
	): Promise<{
		file: StreamableFile;
		fileName: string;
		contentType: string;
	}> {
		this.logger.log('Using streaming cache strategy');

		// Gerar stream do arquivo
		const bookTitle = chapters[0]?.book?.title || 'Livro';
		const file = await strategy.generate(chapters, bookTitle);
		const sourceStream = file.getStream();

		// Criar streams duplicados: um para cliente, outro para cache
		const toClient = new PassThrough();
		const toCache = new PassThrough();

		// Configurar error handling
		sourceStream.on('error', (err) => {
			this.logger.error(`Stream generation failed: ${err.message}`);
			toClient.destroy(err);
			toCache.destroy(err);
		});

		// Duplicar stream
		sourceStream.pipe(toClient);
		sourceStream.pipe(toCache);

		// Salvar no cache em background
		this.saveToCacheAsync(
			cacheKey,
			formatKey,
			strategy.getExtension(),
			toCache,
		).catch((err) =>
			this.logger.error(`Async cache save failed: ${err.message}`),
		);

		// Retornar stream para cliente
		return {
			file: new StreamableFile(toClient, {
				type: strategy.getContentType(),
				disposition: `attachment; filename="${fileName}"`,
			}),
			fileName,
			contentType: strategy.getContentType(),
		};
	}

	/**
	 * Salva stream no cache de forma assíncrona
	 */
	private async saveToCacheAsync(
		cacheKey: string[],
		format: string,
		extension: string,
		stream: Readable,
	): Promise<void> {
		const key = this.cacheService.generateCacheKey(cacheKey, format);
		const filePath = this.cacheService.getCacheFilePath(key, extension);
		const tempPath = `${filePath}.tmp`;

		try {
			// Criar write stream para arquivo temporário
			const fileStream = (await import('node:fs')).createWriteStream(
				tempPath,
			);

			// Pipeline: stream -> arquivo temporário
			await pipelineAsync(stream, fileStream);

			// Renomear para arquivo final (atômico)
			await fs.rename(tempPath, filePath);

			// Registrar no Redis
			const redisKey = `${this.cacheService.REDIS_PREFIX}${key}`;
			const ttl = this.cacheService.TTL_SECONDS;
			await this.cacheService.redis.set(redisKey, filePath, 'EX', ttl);

			this.logger.log(`Async cache saved: ${key}`);
		} catch (error) {
			// Limpar arquivo temporário se falhou
			await fs.unlink(tempPath).catch(() => {});
			throw error;
		}
	}
}

import { promises as fs } from 'node:fs';
import { join } from 'node:path';
import { PassThrough } from 'node:stream';
import { Injectable, Logger, StreamableFile } from '@nestjs/common';
import PDFDocument from 'pdfkit';
import sharp from 'sharp';
import { Chapter } from 'src/books/entities/chapter.entity';
import { DownloadStrategy } from './download.strategy';

// Caminho base onde o volume de dados está montado no container
const DATA_BASE_PATH = '/usr/src/app/data';

@Injectable()
export class PdfStrategy implements DownloadStrategy {
	private readonly logger = new Logger(PdfStrategy.name);

	getContentType(): string {
		return 'application/pdf';
	}

	getExtension(): string {
		return 'pdf';
	}

	generate(chapters: Chapter[], fileName: string): Promise<StreamableFile> {
		this.logger.log(
			`Generating PDF for ${chapters.length} chapters: ${fileName}`,
		);

		// Stream de passagem para enviar dados enquanto gera
		const outputStream = new PassThrough();

		// Criar documento PDF
		const doc = new PDFDocument({
			autoFirstPage: false,
			bufferPages: false, // Desabilitar buffer de páginas para streaming
		});

		// Pipe do PDFKit para o output stream
		doc.pipe(outputStream);

		// Error handling
		doc.on('error', (err: Error) => {
			this.logger.error(`PDF error: ${err.message}`);
			outputStream.destroy(err);
		});

		// Gerar PDF em background
		this.generatePdfAsync(doc, chapters)
			.then(() => {
				this.logger.debug('PDF generation complete');
			})
			.catch((err) => {
				this.logger.error(`PDF generation failed: ${err.message}`);
				outputStream.destroy(err);
			});

		// Retornar imediatamente o stream
		return new StreamableFile(outputStream);
	}

	/**
	 * Gera o conteúdo do PDF de forma assíncrona
	 */
	private async generatePdfAsync(
		doc: PDFKit.PDFDocument,
		chapters: Chapter[],
	): Promise<void> {
		let totalPagesAdded = 0;

		for (const chapter of chapters) {
			if (!chapter.pages || chapter.pages.length === 0) {
				this.logger.warn(
					`Chapter ${chapter.id} (${chapter.title}) has no pages`,
				);
				continue;
			}

			// Adicionar página de título do capítulo
			doc.addPage()
				.fontSize(24)
				.font('Helvetica-Bold')
				.text(`Capítulo ${chapter.index}`, { align: 'center' })
				.moveDown()
				.fontSize(18)
				.font('Helvetica')
				.text(chapter.title || '', { align: 'center' });

			// Adicionar imagens das páginas
			for (const page of chapter.pages.sort(
				(a, b) => a.index - b.index,
			)) {
				try {
					// O path no banco é /data/filename.ext (caminho público)
					const cleanPath = page.path.startsWith('/data/')
						? page.path.substring(6)
						: page.path;

					const filePath = join(DATA_BASE_PATH, cleanPath);

					// Ler o arquivo da imagem
					const rawImageBuffer = await fs.readFile(filePath);

					// Converter para PNG (PDFKit não suporta WebP nativamente)
					const sharpInstance = sharp(rawImageBuffer);
					const metadata = await sharpInstance.metadata();
					const imageBuffer = await sharpInstance.png().toBuffer();

					if (!metadata.width || !metadata.height) {
						this.logger.warn(
							`Could not determine dimensions for page ${page.id}`,
						);
						continue;
					}

					// Usar o tamanho original da imagem para a página
					const width = metadata.width;
					const height = metadata.height;

					// Adicionar nova página com o tamanho exato da imagem
					doc.addPage({ size: [width, height] }).image(
						imageBuffer,
						0,
						0,
						{
							width,
							height,
						},
					);

					totalPagesAdded++;
				} catch (error) {
					const errorMessage =
						error instanceof Error
							? error.message
							: 'Unknown error';
					this.logger.error(
						`Failed to process page ${page.id}: ${errorMessage}`,
					);
				}
			}
		}

		this.logger.log(`Finalizing PDF with ${totalPagesAdded} pages`);

		// Finalizar o documento
		doc.end();
	}
}

import { PassThrough, Readable } from 'node:stream';
import { Injectable, Logger, StreamableFile } from '@nestjs/common';
import archiver from 'archiver';
import { Chapter } from 'src/books/entities/chapter.entity';
import { DownloadStrategy } from './download.strategy';
import { PdfStrategy } from './pdf.strategy';

// Configuração de paralelismo para PDFs
const PARALLEL_PDF_GENERATION = 3; // PDFs gerados em paralelo (mais pesado que imagens)

interface PdfData {
	chapterIndex: number;
	fileName: string;
	buffer: Buffer;
}

@Injectable()
export class PdfsZipStrategy implements DownloadStrategy {
	private readonly logger = new Logger(PdfsZipStrategy.name);

	constructor(private readonly pdfStrategy: PdfStrategy) {}

	getContentType(): string {
		return 'application/zip';
	}

	getExtension(): string {
		return 'zip';
	}

	generate(chapters: Chapter[], fileName: string): Promise<StreamableFile> {
		this.logger.log(
			`Generating ZIP of PDFs for ${chapters.length} chapters: ${fileName} (parallel: ${PARALLEL_PDF_GENERATION})`,
		);

		// Stream de passagem para enviar dados enquanto gera
		const outputStream = new PassThrough();

		// Criar archiver com streaming
		const archive = archiver('zip', {
			zlib: { level: 6 },
		});

		// Pipe do archiver para o output stream
		archive.pipe(outputStream);

		// Error handling
		archive.on('error', (err: Error) => {
			this.logger.error(`Archive error: ${err.message}`);
			outputStream.destroy(err);
		});

		archive.on('warning', (err: Error) => {
			this.logger.warn(`Archive warning: ${err.message}`);
		});

		// Gerar PDFs em paralelo e adicionar ao ZIP
		this.generatePdfsParallel(archive, chapters)
			.then(() => {
				this.logger.debug('All PDFs added, archive finalized');
			})
			.catch((err) => {
				this.logger.error(`PDF generation failed: ${err.message}`);
				outputStream.destroy(err);
			});

		// Retornar imediatamente o stream
		return new StreamableFile(outputStream);
	}

	/**
	 * Gera PDFs em paralelo e adiciona ao archive
	 */
	private async generatePdfsParallel(
		archive: archiver.Archiver,
		chapters: Chapter[],
	): Promise<void> {
		const startTime = Date.now();
		let totalPdfsAdded = 0;

		// Filtrar capítulos válidos
		const validChapters = chapters.filter(
			(ch) => ch.pages && ch.pages.length > 0,
		);

		// Processar em lotes paralelos
		for (
			let i = 0;
			i < validChapters.length;
			i += PARALLEL_PDF_GENERATION
		) {
			const batch = validChapters.slice(i, i + PARALLEL_PDF_GENERATION);

			this.logger.debug(
				`Processing PDF batch ${Math.floor(i / PARALLEL_PDF_GENERATION) + 1}/${Math.ceil(validChapters.length / PARALLEL_PDF_GENERATION)}`,
			);

			// Gerar PDFs em paralelo
			const batchResults = await Promise.all(
				batch.map((chapter) => this.generateSinglePdf(chapter)),
			);

			// Ordenar por índice do capítulo e adicionar ao archive
			const sortedResults = batchResults
				.filter((r): r is PdfData => r !== null)
				.sort((a, b) => a.chapterIndex - b.chapterIndex);

			for (const pdfData of sortedResults) {
				archive.append(pdfData.buffer, { name: pdfData.fileName });
				totalPdfsAdded++;
			}
		}

		const duration = ((Date.now() - startTime) / 1000).toFixed(1);
		this.logger.log(
			`Finalizing archive with ${totalPdfsAdded} PDFs (processed in ${duration}s)`,
		);

		// Finalizar o arquivo
		await archive.finalize();
	}

	/**
	 * Gera um único PDF para um capítulo
	 */
	private async generateSinglePdf(chapter: Chapter): Promise<PdfData | null> {
		try {
			this.logger.debug(
				`Generating PDF for chapter ${chapter.index}: ${chapter.title}`,
			);

			// Gerar PDF do capítulo
			const pdfFile = await this.pdfStrategy.generate(
				[chapter],
				chapter.title || `Capitulo_${chapter.index}`,
			);

			// Converter stream para buffer
			const buffer = await this.streamToBuffer(pdfFile.getStream());

			// Nome do arquivo
			const fileName = this.sanitizeFileName(
				`Capitulo_${String(chapter.index).padStart(3, '0')}_${chapter.title || 'Sem_Titulo'}.pdf`,
			);

			this.logger.debug(
				`Generated PDF: ${fileName} (${(buffer.length / 1024 / 1024).toFixed(1)}MB)`,
			);

			return {
				chapterIndex: chapter.index,
				fileName,
				buffer,
			};
		} catch (error) {
			const errorMessage =
				error instanceof Error ? error.message : 'Unknown error';
			this.logger.error(
				`Failed to generate PDF for chapter ${chapter.id}: ${errorMessage}`,
			);
			return null;
		}
	}

	private sanitizeFileName(name: string): string {
		// biome-ignore lint/suspicious/noControlCharactersInRegex: intentional sanitization of control characters
		// eslint-disable-next-line no-control-regex
		return name.replace(/[<>:"/\\|?*\x00-\x1F]/g, '_').trim();
	}

	private async streamToBuffer(stream: Readable): Promise<Buffer> {
		const chunks: Uint8Array[] = [];
		for await (const chunk of stream) {
			chunks.push(Buffer.from(chunk));
		}
		return Buffer.concat(chunks);
	}
}

import { promises as fs } from 'node:fs';
import { join } from 'node:path';
import { PassThrough } from 'node:stream';
import { Injectable, Logger, StreamableFile } from '@nestjs/common';
import archiver from 'archiver';
import { Chapter } from 'src/books/entities/chapter.entity';
import { DownloadStrategy } from './download.strategy';

// Caminho base onde o volume de dados está montado no container
const DATA_BASE_PATH = '/usr/src/app/data';

// Configuração de paralelismo
const PARALLEL_CHAPTERS = 4; // Capítulos processados em paralelo
const PARALLEL_PAGES = 8; // Páginas por capítulo em paralelo

interface PageData {
	chapterIndex: number;
	chapterFolder: string;
	pageIndex: number;
	fileName: string;
	buffer: Buffer;
}

@Injectable()
export class ZipStrategy implements DownloadStrategy {
	private readonly logger = new Logger(ZipStrategy.name);

	getContentType(): string {
		return 'application/zip';
	}

	getExtension(): string {
		return 'zip';
	}

	generate(chapters: Chapter[], fileName: string): Promise<StreamableFile> {
		this.logger.log(
			`Generating ZIP for ${chapters.length} chapters: ${fileName} (parallel: ${PARALLEL_CHAPTERS} chapters, ${PARALLEL_PAGES} pages)`,
		);

		// Stream de passagem para enviar dados enquanto gera
		const outputStream = new PassThrough();

		// Criar archiver com streaming
		const archive = archiver('zip', {
			zlib: { level: 6 },
		});

		// Pipe do archiver para o output stream
		archive.pipe(outputStream);

		// Error handling
		archive.on('error', (err: Error) => {
			this.logger.error(`Archive error: ${err.message}`);
			outputStream.destroy(err);
		});

		archive.on('warning', (err: Error) => {
			this.logger.warn(`Archive warning: ${err.message}`);
		});

		// Gerar ZIP em background com paralelismo
		this.generateZipParallel(archive, chapters)
			.then(() => {
				this.logger.debug('All files added, archive finalized');
			})
			.catch((err) => {
				this.logger.error(`ZIP generation failed: ${err.message}`);
				outputStream.destroy(err);
			});

		// Retornar imediatamente o stream
		return new StreamableFile(outputStream);
	}

	/**
	 * Gera ZIP com processamento paralelo de capítulos
	 */
	private async generateZipParallel(
		archive: archiver.Archiver,
		chapters: Chapter[],
	): Promise<void> {
		const startTime = Date.now();
		let totalPagesAdded = 0;

		// Processar capítulos em lotes paralelos
		for (let i = 0; i < chapters.length; i += PARALLEL_CHAPTERS) {
			const batch = chapters.slice(i, i + PARALLEL_CHAPTERS);

			this.logger.debug(
				`Processing chapter batch ${Math.floor(i / PARALLEL_CHAPTERS) + 1}/${Math.ceil(chapters.length / PARALLEL_CHAPTERS)}`,
			);

			// Processar lote em paralelo
			const batchResults = await Promise.all(
				batch.map((chapter) => this.processChapterParallel(chapter)),
			);

			// Adicionar ao archive na ordem correta (já ordenado por chapterIndex e pageIndex)
			for (const chapterPages of batchResults) {
				for (const pageData of chapterPages) {
					archive.append(pageData.buffer, {
						name: `${pageData.chapterFolder}/${pageData.fileName}`,
					});
					totalPagesAdded++;
				}
			}
		}

		const duration = ((Date.now() - startTime) / 1000).toFixed(1);
		this.logger.log(
			`Finalizing archive with ${totalPagesAdded} pages (processed in ${duration}s)`,
		);

		// Finalizar o arquivo
		await archive.finalize();
	}

	/**
	 * Processa um capítulo com páginas em paralelo
	 */
	private async processChapterParallel(
		chapter: Chapter,
	): Promise<PageData[]> {
		if (!chapter.pages || chapter.pages.length === 0) {
			this.logger.warn(
				`Chapter ${chapter.id} (${chapter.title}) has no pages`,
			);
			return [];
		}

		const chapterFolder = this.sanitizeFileName(
			`Capitulo ${chapter.index} - ${chapter.title}`,
		);

		const sortedPages = chapter.pages.sort((a, b) => a.index - b.index);
		const results: PageData[] = [];

		// Processar páginas em lotes paralelos
		for (let i = 0; i < sortedPages.length; i += PARALLEL_PAGES) {
			const pageBatch = sortedPages.slice(i, i + PARALLEL_PAGES);

			const batchResults = await Promise.all(
				pageBatch.map(async (page) => {
					try {
						const cleanPath = page.path.startsWith('/data/')
							? page.path.substring(6)
							: page.path;
						const filePath = join(DATA_BASE_PATH, cleanPath);

						// Ler arquivo
						const buffer = await fs.readFile(filePath);

						// Extrair extensão
						const ext = cleanPath.split('.').pop() || 'webp';
						const fileName = `${String(page.index).padStart(3, '0')}.${ext}`;

						return {
							chapterIndex: chapter.index,
							chapterFolder,
							pageIndex: page.index,
							fileName,
							buffer,
						} as PageData;
					} catch (error) {
						const errorMessage =
							error instanceof Error
								? error.message
								: 'Unknown error';
						this.logger.error(
							`Failed to read page ${page.id}: ${errorMessage}`,
						);
						return null;
					}
				}),
			);

			// Filtrar nulls e adicionar resultados
			results.push(
				...batchResults.filter((r): r is PageData => r !== null),
			);
		}

		// Ordenar por índice da página (garantir ordem)
		return results.sort((a, b) => a.pageIndex - b.pageIndex);
	}

	private sanitizeFileName(name: string): string {
		// biome-ignore lint/suspicious/noControlCharactersInRegex: intentional sanitization of control characters
		// eslint-disable-next-line no-control-regex
		return name.replace(/[<>:"/\\|?*\x00-\x1F]/g, '_').trim();
	}
}

import { Logger, UseGuards } from '@nestjs/common';
import { OnEvent } from '@nestjs/event-emitter';
import {
	ConnectedSocket,
	MessageBody,
	OnGatewayConnection,
	OnGatewayDisconnect,
	OnGatewayInit,
	SubscribeMessage,
	WebSocketGateway,
	WebSocketServer,
} from '@nestjs/websockets';
import { Server, Socket } from 'socket.io';
import { WsJwtGuard } from '../../auth/guard/ws-jwt.guard';
import { RolesEnum } from '../../users/enum/roles.enum';
import { BookEvents } from '../constants/events.constant';
import { Book } from '../entities/book.entity';
import { Chapter } from '../entities/chapter.entity';

interface WsUser {
	id: string;
	roles: string[];
}

/**
 * Gateway WebSocket para comunicação em tempo real de eventos de livros
 * Implementa o padrão Observer para notificar clientes sobre mudanças
 */
@UseGuards(WsJwtGuard)
@WebSocketGateway({
	cors: {
		origin: process.env.ALLOWED_URL?.split(',') || [
			'http://localhost:4200',
			'http://gatuno.barbosa.local',
		],
		credentials: true,
	},
	namespace: '/books',
	transports: ['websocket', 'polling'],
})
export class BooksGateway
	implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect
{
	@WebSocketServer()
	server: Server;

	private readonly logger = new Logger(BooksGateway.name);
	private connectedClients = new Map<
		string,
		{ bookIds: Set<string>; chapterIds: Set<string>; isAdmin: boolean }
	>();

	afterInit(server: Server) {
		this.logger.log('WebSocket Gateway initialized on namespace /books');
		this.logger.log(
			`CORS origin: ${process.env.ALLOWED_URL || 'localhost:4200'}`,
		);
	}

	handleConnection(client: Socket) {
		try {
			const user = client.data.user as WsUser;
			const isAdmin = user?.roles?.includes(RolesEnum.ADMIN) || false;

			this.logger.log(
				`Client connected: ${client.id} from ${client.handshake.address} (Admin: ${isAdmin})`,
			);

			// Inicializa tracking do cliente
			this.connectedClients.set(client.id, {
				bookIds: new Set(),
				chapterIds: new Set(),
				isAdmin,
			});

			// Se for admin, adiciona à room admin
			if (isAdmin) {
				client.join('admin');
				this.logger.debug(`Admin ${client.id} joined admin room`);
			}
		} catch (error: any) {
			this.logger.error(`Error in handleConnection: ${error.message}`);
			client.disconnect();
		}
	}

	handleDisconnect(client: Socket) {
		try {
			const clientData = this.connectedClients.get(client.id);
			this.logger.log(
				`Client disconnected: ${client.id} (Books: ${clientData?.bookIds.size || 0}, Chapters: ${clientData?.chapterIds.size || 0})`,
			);
			this.connectedClients.delete(client.id);
		} catch (error: any) {
			this.logger.error(`Error in handleDisconnect: ${error.message}`);
		}
	}

	/**
	 * Helper para broadcasting seguro de eventos
	 */
	private broadcast(
		rooms: string | string[],
		event: string,
		payload: unknown,
	) {
		try {
			const roomList = Array.isArray(rooms) ? rooms : [rooms];
			this.logger.debug(
				`Broadcasting ${event} to rooms: ${roomList.join(', ')}`,
			);

			let broadcastOperator = this.server.to(roomList[0]);
			for (const room of roomList.slice(1)) {
				broadcastOperator = broadcastOperator.to(room);
			}
			broadcastOperator.emit(event, payload);
		} catch (error: any) {
			this.logger.error(`Failed to broadcast ${event}: ${error.message}`);
		}
	}

	// ==================== EVENTOS DE INSCRIÇÃO ====================

	@SubscribeMessage(BookEvents.SUBSCRIBE_BOOK)
	handleSubscribeBook(
		@ConnectedSocket() client: Socket,
		@MessageBody() bookId: string,
	) {
		try {
			if (!bookId || typeof bookId !== 'string') {
				client.emit('error', { message: 'Invalid bookId' });
				return;
			}

			client.join(`book:${bookId}`);
			this.connectedClients.get(client.id)?.bookIds.add(bookId);

			this.logger.debug(
				`Client ${client.id} subscribed to book:${bookId}`,
			);
			client.emit('subscribed', {
				type: 'book',
				id: bookId,
				success: true,
			});
		} catch (error: any) {
			this.logger.error(
				`Failed to subscribe client ${client.id} to book ${bookId}: ${error.message}`,
			);
			client.emit('subscribed', {
				type: 'book',
				id: bookId,
				success: false,
				error: error.message,
			});
		}
	}

	@SubscribeMessage(BookEvents.SUBSCRIBE_CHAPTER)
	handleSubscribeChapter(
		@ConnectedSocket() client: Socket,
		@MessageBody() chapterId: string,
	) {
		try {
			if (!chapterId || typeof chapterId !== 'string') {
				client.emit('error', { message: 'Invalid chapterId' });
				return;
			}

			client.join(`chapter:${chapterId}`);
			this.connectedClients.get(client.id)?.chapterIds.add(chapterId);

			this.logger.debug(
				`Client ${client.id} subscribed to chapter:${chapterId}`,
			);
			client.emit('subscribed', {
				type: 'chapter',
				id: chapterId,
				success: true,
			});
		} catch (error: any) {
			this.logger.error(
				`Failed to subscribe client ${client.id} to chapter ${chapterId}: ${error.message}`,
			);
			client.emit('subscribed', {
				type: 'chapter',
				id: chapterId,
				success: false,
				error: error.message,
			});
		}
	}

	@SubscribeMessage(BookEvents.UNSUBSCRIBE_BOOK)
	handleUnsubscribeBook(
		@ConnectedSocket() client: Socket,
		@MessageBody() bookId: string,
	) {
		try {
			client.leave(`book:${bookId}`);
			this.connectedClients.get(client.id)?.bookIds.delete(bookId);

			this.logger.debug(
				`Client ${client.id} unsubscribed from book:${bookId}`,
			);
			client.emit('unsubscribed', {
				type: 'book',
				id: bookId,
				success: true,
			});
		} catch (error: any) {
			this.logger.error(
				`Failed to unsubscribe client ${client.id} from book ${bookId}: ${error.message}`,
			);
		}
	}

	@SubscribeMessage(BookEvents.UNSUBSCRIBE_CHAPTER)
	handleUnsubscribeChapter(
		@ConnectedSocket() client: Socket,
		@MessageBody() chapterId: string,
	) {
		try {
			client.leave(`chapter:${chapterId}`);
			this.connectedClients.get(client.id)?.chapterIds.delete(chapterId);

			this.logger.debug(
				`Client ${client.id} unsubscribed from chapter:${chapterId}`,
			);
			client.emit('unsubscribed', {
				type: 'chapter',
				id: chapterId,
				success: true,
			});
		} catch (error: any) {
			this.logger.error(
				`Failed to unsubscribe client ${client.id} from chapter ${chapterId}: ${error.message}`,
			);
		}
	}

	@SubscribeMessage(BookEvents.LIST_SUBSCRIPTIONS)
	handleListSubscriptions(@ConnectedSocket() client: Socket) {
		try {
			const clientData = this.connectedClients.get(client.id);
			client.emit('subscriptions', {
				books: Array.from(clientData?.bookIds || []),
				chapters: Array.from(clientData?.chapterIds || []),
				isAdmin: clientData?.isAdmin || false,
			});
		} catch (error: any) {
			this.logger.error(
				`Failed to list subscriptions for client ${client.id}: ${error.message}`,
			);
		}
	}

	// ==================== EVENTOS DE LIVROS ====================

	@OnEvent(BookEvents.CREATED)
	handleBookCreated(book: Book) {
		// Apenas admins recebem eventos de criação
		this.broadcast('admin', BookEvents.CREATED, {
			id: book.id,
			title: book.title,
			type: book.type,
			createdAt: book.createdAt,
		});
	}

	@OnEvent(BookEvents.UPDATED)
	handleBookUpdated(book: Book) {
		// Envia para room específica do livro
		this.broadcast(`book:${book.id}`, BookEvents.UPDATED, {
			id: book.id,
			title: book.title,
			updatedAt: book.updatedAt,
		});
	}

	// ==================== EVENTOS DE CAPÍTULOS ====================

	@OnEvent(BookEvents.CHAPTERS_UPDATED)
	handleChaptersUpdated(payload: Chapter | Chapter[]) {
		// Normaliza para sempre trabalhar com array
		const chapters = Array.isArray(payload) ? payload : [payload];

		if (!chapters || chapters.length === 0) return;

		const bookId = chapters[0]?.book?.id;

		const chapterData = chapters.map((ch) => ({
			id: ch.id,
			title: ch.title,
			index: ch.index,
			scrapingStatus: ch.scrapingStatus,
		}));

		// Envia para room do livro e admins
		this.broadcast(
			[`book:${bookId}`, 'admin'],
			BookEvents.CHAPTERS_UPDATED,
			{
				bookId,
				chapters: chapterData,
			},
		);

		// Envia para rooms específicas de cada capítulo
		for (const chapter of chapters) {
			this.broadcast(
				`chapter:${chapter.id}`,
				BookEvents.CHAPTER_UPDATED,
				{
					bookId,
					chapter: {
						id: chapter.id,
						title: chapter.title,
						index: chapter.index,
						scrapingStatus: chapter.scrapingStatus,
					},
				},
			);
		}
	}

	@OnEvent(BookEvents.CHAPTERS_FIX)
	handleChaptersFix(chapters: Chapter[]) {
		if (!chapters || chapters.length === 0) return;

		const bookId = chapters[0]?.book?.id;

		// Apenas admins recebem eventos de correção
		this.broadcast('admin', BookEvents.CHAPTERS_FIX, {
			bookId,
			chapterIds: chapters.map((ch) => ch.id),
		});
	}

	// ==================== EVENTOS DE SCRAPING ====================

	@OnEvent(BookEvents.SCRAPING_STARTED)
	handleChapterScrapingStarted(data: { chapterId: string; bookId: string }) {
		this.broadcast(
			[`book:${data.bookId}`, `chapter:${data.chapterId}`, 'admin'],
			BookEvents.SCRAPING_STARTED,
			data,
		);
	}

	@OnEvent(BookEvents.SCRAPING_COMPLETED)
	handleChapterScrapingCompleted(data: {
		chapterId: string;
		bookId: string;
		pagesCount: number;
	}) {
		this.broadcast(
			[`book:${data.bookId}`, `chapter:${data.chapterId}`, 'admin'],
			BookEvents.SCRAPING_COMPLETED,
			data,
		);
	}

	@OnEvent(BookEvents.SCRAPING_FAILED)
	handleChapterScrapingFailed(data: {
		chapterId: string;
		bookId: string;
		error: string;
	}) {
		this.broadcast(
			[`book:${data.bookId}`, `chapter:${data.chapterId}`, 'admin'],
			BookEvents.SCRAPING_FAILED,
