import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { SchedulerRegistry } from '@nestjs/schedule';
import { InjectRepository } from '@nestjs/typeorm';
import { CronJob } from 'cron';
import { AppConfigService } from 'src/app-config/app-config.service';
import { IsNull, Repository } from 'typeorm';
import { Book } from '../entities/book.entity';
import { BookUpdateJobService } from './book-update.service';

const CRON_JOB_NAME = 'book-update-cron';

/**
 * Job agendado para verificar atualizações de livros periodicamente.
 * Usa a variável de ambiente BOOK_UPDATE_CRON para configurar o intervalo.
 */
@Injectable()
export class BookUpdateScheduler implements OnModuleInit {
	private readonly logger = new Logger(BookUpdateScheduler.name);

	constructor(
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		private readonly bookUpdateJobService: BookUpdateJobService,
		private readonly configService: AppConfigService,
		private readonly schedulerRegistry: SchedulerRegistry,
	) {}

	onModuleInit() {
		if (!this.configService.bookUpdate?.enabled) {
			this.logger.log('Book auto-update is disabled');
			return;
		}

		const cronExpression = this.configService.bookUpdate.cronExpression;
		this.logger.log(
			`Registering book update cron job with expression: ${cronExpression}`,
		);

		const job = new CronJob(cronExpression, () => {
			this.handleScheduledUpdate();
		});

		this.schedulerRegistry.addCronJob(CRON_JOB_NAME, job);
		job.start();

		this.logger.log('Book update cron job registered and started');
	}

	/**
	 * Executa a verificação de atualizações.
	 * Apenas livros com URLs originais e autoUpdate habilitado são verificados.
	 */
	async handleScheduledUpdate(): Promise<void> {
		if (!this.configService.bookUpdate?.enabled) {
			this.logger.debug('Book auto-update is disabled');
			return;
		}

		this.logger.log('Starting scheduled book update check...');

		try {
			// Busca livros que possuem URL original, autoUpdate habilitado e não foram deletados
			const books = await this.bookRepository.find({
				where: {
					deletedAt: IsNull(),
					autoUpdate: true,
				},
				select: ['id', 'title', 'originalUrl', 'autoUpdate'],
			});

			// Filtra apenas livros com URL original válida
			const booksWithUrls = books.filter(
				(book) => book.originalUrl && book.originalUrl.length > 0,
			);

			if (booksWithUrls.length === 0) {
				this.logger.debug('No books with autoUpdate enabled to check');
				return;
			}

			this.logger.log(
				`Scheduling update check for ${booksWithUrls.length} books with autoUpdate enabled`,
			);

			// Adiciona todos os livros à fila de atualização
			const bookIds = booksWithUrls.map((book) => book.id);
			await this.bookUpdateJobService.addBooksToUpdateQueue(bookIds);

			this.logger.log(
				`Scheduled ${bookIds.length} books for update check`,
			);
		} catch (error) {
			this.logger.error(
				`Error during scheduled book update: ${error.message}`,
				error.stack,
			);
		}
	}

	/**
	 * Força a verificação de atualização de um livro específico.
	 */
	async forceUpdateBook(bookId: string): Promise<void> {
		await this.bookUpdateJobService.addBookToUpdateQueue(bookId);
		this.logger.log(`Force update scheduled for book: ${bookId}`);
	}

	/**
	 * Força a verificação de atualização de todos os livros.
	 */
	async forceUpdateAllBooks(): Promise<void> {
		await this.handleScheduledUpdate();
	}
}

import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Queue } from 'bullmq';

const QUEUE_NAME = 'book-update-queue';
const JOB_NAME = 'update-book';

@Injectable()
export class BookUpdateJobService {
	private readonly logger = new Logger(BookUpdateJobService.name);

	constructor(
		@InjectQueue(QUEUE_NAME)
		private readonly bookUpdateQueue: Queue<{ bookId: string }>,
	) {}

	/**
	 * Adiciona um livro à fila de atualização.
	 * Remove job anterior (se existir) para permitir re-execução.
	 */
	async addBookToUpdateQueue(bookId: string): Promise<void> {
		const jobId = `book-update-${bookId}`;

		try {
			// Remove job anterior se existir (para permitir re-execução)
			const existingJob = await this.bookUpdateQueue.getJob(jobId);
			if (existingJob) {
				const state = await existingJob.getState();
				// Remove apenas se já foi processado (completed, failed) ou está parado (stalled)
				if (['completed', 'failed'].includes(state)) {
					await existingJob.remove();
					this.logger.debug(
						`Removed previous job for book ${bookId} (state: ${state})`,
					);
				} else if (
					state === 'active' ||
					state === 'waiting' ||
					state === 'delayed'
				) {
					this.logger.debug(
						`Book ${bookId} already has a pending job (state: ${state})`,
					);
					return;
				}
			}

			await this.bookUpdateQueue.add(JOB_NAME, { bookId }, { jobId });
			this.logger.debug(`Book ${bookId} added to update queue`);
		} catch (error) {
			this.logger.error(
				`Error adding book ${bookId} to queue: ${error.message}`,
			);
			throw error;
		}
	}

	/**
	 * Adiciona múltiplos livros à fila de atualização
	 */
	async addBooksToUpdateQueue(bookIds: string[]): Promise<void> {
		for (const bookId of bookIds) {
			await this.addBookToUpdateQueue(bookId);
		}
		this.logger.log(`Added ${bookIds.length} books to update queue`);
	}
}

import { OnWorkerEvent, Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger, OnModuleInit } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Job } from 'bullmq';
import { AppConfigService } from 'src/app-config/app-config.service';
import { DataSource, Repository } from 'typeorm';
import { Chapter } from '../entities/chapter.entity';
import { ChapterScrapingSharedService } from './chapter-scraping.shared';

const QUEUE_NAME = 'chapter-scraping';

@Processor(QUEUE_NAME, { lockDuration: 120000 })
export class ChapterScrapingJob extends WorkerHost implements OnModuleInit {
	private readonly logger = new Logger(ChapterScrapingJob.name);

	constructor(
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		private readonly dataSource: DataSource,
		private readonly configService: AppConfigService,
		private readonly chapterScrapingShared: ChapterScrapingSharedService,
	) {
		super();
	}

	onModuleInit() {
		const concurrency = this.configService.queueConcurrency.chapterScraping;
		this.worker.concurrency = concurrency;
		this.logger.log(`Worker initialized with concurrency: ${concurrency}`);
	}

	@OnWorkerEvent('ready')
	onReady() {
		this.logger.log('Worker is ready and listening for jobs');
	}

	@OnWorkerEvent('error')
	onError(error: Error) {
		this.logger.error(`Worker error: ${error.message}`, error.stack);
	}

	async process(job: Job<string>): Promise<void> {
		const chapterId = job.data;
		this.logger.debug(
			`Iniciando processamento do job: ${job.id} para o capítulo: ${chapterId}`,
		);
		const startTime = Date.now();

		const chapter = await this.getChapter(chapterId);

		if (!chapter) {
			this.logger.error(
				`Capítulo com ID ${chapterId} não encontrado. Job ${job.id} falhará.`,
			);
			throw new Error(`Capítulo com ID ${chapterId} não encontrado.`);
		}

		await this.chapterScrapingShared.processChapterPages(chapter);

		const endTime = Date.now();
		this.logger.debug(
			`Job ${job.id} finalizado. Tempo total: ${(endTime - startTime) / 1000}s`,
		);
	}

	private async getChapter(chapterId: string): Promise<Chapter | null> {
		const queryRunner = this.dataSource.createQueryRunner('master');
		try {
			await queryRunner.connect();
			return await queryRunner.manager.findOne(Chapter, {
				where: { id: chapterId },
				relations: ['book', 'pages'],
			});
		} finally {
			await queryRunner.release();
		}
	}

	@OnWorkerEvent('active')
	async onActive(job: Job<string>): Promise<void> {
		const chapterId = job.data;
		const queryRunner = this.dataSource.createQueryRunner('master');

		try {
			await queryRunner.connect();
			const chapter = await queryRunner.manager.findOne(Chapter, {
				where: { id: chapterId },
				relations: ['book'],
			});

			if (chapter) {
				// Emite evento de scraping iniciado
				this.chapterScrapingShared.emitStartedEvent(chapter);

				// Incrementa contador de tentativas
				chapter.retries += 1;
				await queryRunner.manager.save(chapter);
			}
		} catch (error) {
			this.logger.error(
				`Erro ao incrementar retentativa para o capítulo ${chapterId}: ${error.message}`,
			);
		} finally {
			await queryRunner.release();
		}
	}

	@OnWorkerEvent('failed')
	async onFailed(job: Job<string>): Promise<void> {
		const chapterId = job.data;
		this.logger.error(
			`Job with id ${job.id} FAILED! Attempt Number ${job.attemptsMade} for chapter ID: ${chapterId}`,
		);

		const queryRunner = this.dataSource.createQueryRunner('master');

		try {
			await queryRunner.connect();
			const chapter = await queryRunner.manager.findOne(Chapter, {
				where: { id: chapterId },
				relations: ['book'],
			});

			if (chapter) {
				this.chapterScrapingShared.emitFailedEvent(
					chapter,
					job.failedReason || 'Unknown error',
				);
			}
		} catch (error) {
			this.logger.error(
				`Erro ao emitir evento de falha para o capítulo ${chapterId}: ${error.message}`,
			);
		} finally {
			await queryRunner.release();
		}
	}
}

import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Queue } from 'bullmq';
import { Not, Repository } from 'typeorm';
import { Chapter } from '../entities/chapter.entity';
import { ContentType } from '../enum/content-type.enum';
import { ScrapingStatus } from '../enum/scrapingStatus.enum';

const QUEUE_NAME = 'chapter-scraping';
const JOB_NAME = 'process-chapter';

@Injectable()
export class ChapterScrapingService {
	private readonly logger = new Logger(ChapterScrapingService.name);

	constructor(
		@InjectQueue(QUEUE_NAME)
		private readonly chapterScrapingQueue: Queue<string>,
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
	) {}

	/**
	 * Adiciona um capítulo à fila de scraping.
	 * Remove jobs antigos (completados/falhos) antes de adicionar para permitir reprocessamento.
	 */
	public async addChapterToQueue(chapterId: string): Promise<void> {
		const jobId = `chapter-scraping-${chapterId}`;

		try {
			// Remove job anterior se existir (completado ou falho)
			const existingJob = await this.chapterScrapingQueue.getJob(jobId);
			if (existingJob) {
				const state = await existingJob.getState();
				if (state === 'completed' || state === 'failed') {
					await existingJob.remove();
					this.logger.debug(
						`Job anterior removido para capítulo: ${chapterId} (estado: ${state})`,
					);
				} else if (
					state === 'active' ||
					state === 'waiting' ||
					state === 'delayed'
				) {
					this.logger.debug(
						`Job para capítulo ${chapterId} já está ${state}, ignorando`,
					);
					return;
				}
			}

			await this.chapterScrapingQueue.add(JOB_NAME, chapterId, { jobId });
			this.logger.debug(`Adicionando job para o capítulo: ${chapterId}`);
		} catch (error) {
			// Job com mesmo ID já existe na fila
			if (error.message?.includes('Job with this id already exists')) {
				this.logger.debug(
					`Job para o capítulo ${chapterId} já está na fila.`,
				);
			} else {
				this.logger.error(
					`Erro ao adicionar job para capítulo ${chapterId}: ${error.message}`,
				);
				throw error;
			}
		}
	}

	public async scheduleAllPendingChapters(): Promise<void> {
		this.logger.log(
			'Buscando todos os capítulos pendentes para enfileirar...',
		);

		// Apenas capítulos do tipo IMAGE precisam de scraping
		// Capítulos TEXT e DOCUMENT têm conteúdo enviado manualmente
		const pendingChapters = await this.chapterRepository.find({
			where: {
				scrapingStatus: Not(ScrapingStatus.READY),
				contentType: ContentType.IMAGE,
			},
			select: ['id'],
		});

		for (const chapter of pendingChapters) {
			await this.addChapterToQueue(chapter.id);
		}

		this.logger.log(
			`${pendingChapters.length} capítulos pendentes foram adicionados à fila.`,
		);
	}
}

import { Injectable, Logger } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { ScrapingService } from 'src/scraping/scraping.service';
import { Repository } from 'typeorm';
import { Chapter } from '../entities/chapter.entity';
import { Page } from '../entities/page.entity';
import { ScrapingStatus } from '../enum/scrapingStatus.enum';

/**
 * Serviço compartilhado para processamento de scraping de capítulos.
 * Elimina duplicação de código entre ChapterScrapingJob e FixChapterProcessor.
 */
@Injectable()
export class ChapterScrapingSharedService {
	private readonly logger = new Logger(ChapterScrapingSharedService.name);

	constructor(
		@InjectRepository(Page)
		private readonly pageRepository: Repository<Page>,
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		private readonly scrapingService: ScrapingService,
		private readonly eventEmitter: EventEmitter2,
	) {}

	/**
	 * Processa o scraping de páginas de um capítulo.
	 * @param chapter O capítulo a ser processado
	 * @param minPages Número mínimo de páginas esperadas (opcional, usado para fix)
	 * @returns true se o processamento foi bem-sucedido
	 */
	async processChapterPages(
		chapter: Chapter,
		minPages?: number,
	): Promise<boolean> {
		const startTime = Date.now();
		const chapterInfo = `${chapter.book?.title || 'Unknown'} (${chapter.index})`;

		this.logger.debug(`Iniciando scraping para capítulo: ${chapterInfo}`);

		try {
			// Delete páginas existentes
			await this.pageRepository.delete({ chapter: { id: chapter.id } });

			// Faz o scraping
			const pages = await this.scrapingService.scrapePages(
				chapter.originalUrl,
				minPages,
			);

			if (!pages || pages.length === 0) {
				chapter.scrapingStatus = ScrapingStatus.ERROR;
				await this.chapterRepository.save(chapter);
				this.logger.warn(
					`Nenhuma página encontrada para o capítulo: ${chapterInfo}`,
				);

				this.emitFailedEvent(chapter, 'Nenhuma página encontrada');
				return false;
			}

			// Cria as novas páginas
			let index = 1;
			const newPages = pages.map((pageContent) =>
				this.pageRepository.create({
					path: pageContent,
					index: index++,
				}),
			);

			chapter.pages = newPages;
			chapter.scrapingStatus = ScrapingStatus.READY;
			await this.chapterRepository.save(chapter);

			// Emite eventos de sucesso
			this.emitCompletedEvent(chapter, pages.length);

			const endTime = Date.now();
			this.logger.log(
				`Páginas salvas para o capítulo: ${chapterInfo} em ${(endTime - startTime) / 1000}s`,
			);

			return true;
		} catch (error) {
			this.logger.error(
				`Falha no scraping do capítulo ${chapter.id}: ${error.message}`,
				error.stack,
			);

			chapter.scrapingStatus = ScrapingStatus.ERROR;
			await this.chapterRepository.save(chapter);

			this.emitFailedEvent(chapter, error.message);

			throw error;
		}
	}

	/**
	 * Emite evento de início do scraping
	 */
	emitStartedEvent(chapter: Chapter): void {
		this.eventEmitter.emit('chapter.scraping.started', {
			chapterId: chapter.id,
			bookId: chapter.book?.id,
		});
	}

	/**
	 * Emite evento de scraping completado
	 */
	private emitCompletedEvent(chapter: Chapter, pagesCount: number): void {
		this.eventEmitter.emit('chapter.scraping.completed', {
			chapterId: chapter.id,
			bookId: chapter.book?.id,
			pagesCount,
		});

		// Emite evento de atualização de capítulo
		this.eventEmitter.emit('chapters.updated', chapter);
	}

	/**
	 * Emite evento de falha no scraping
	 */
	emitFailedEvent(chapter: Chapter, error: string): void {
		this.eventEmitter.emit('chapter.scraping.failed', {
			chapterId: chapter.id,
			bookId: chapter.book?.id,
			error,
		});

		// Emite evento de atualização de capítulo (status ERROR)
		this.eventEmitter.emit('chapters.updated', chapter);
	}
}

import { OnWorkerEvent, Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger, OnModuleInit } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
