const QUEUE_NAME = 'cover-image-queue';
const JOB_NAME = 'process-cover';

@Processor(QUEUE_NAME, { lockDuration: 120000 })
export class CoverImageProcessor extends WorkerHost implements OnModuleInit {
	private readonly logger = new Logger(CoverImageProcessor.name);

	constructor(
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		@InjectRepository(Cover)
		private readonly coverRepository: Repository<Cover>,
		private readonly scrapingService: ScrapingService,
		private readonly dataSource: DataSource,
		private readonly configService: AppConfigService,
		private readonly eventEmitter: EventEmitter2,
	) {
		super();
	}

	onModuleInit() {
		this.worker.concurrency =
			this.configService.queueConcurrency.coverImage;
	}

	async process(job: Job<QueueCoverProcessorDto>): Promise<void> {
		const { bookId, urlOrigin } = job.data;
		// support both legacy single-cover jobs and new batch jobs
		const jobData = job.data as QueueCoverProcessorDto & {
			cover?: { url: string; title?: string };
		};
		const covers: { url: string; title?: string }[] = jobData.covers?.length
			? jobData.covers
			: jobData.cover
				? [jobData.cover]
				: [];
		this.logger.debug(
			`Processando ${covers.length} capa(s) para o livro: ${bookId}`,
		);

		const book = await this.getBook(bookId);
		if (!book) {
			this.logger.warn(
				`Livro com id ${bookId} não encontrado para processar capa.`,
			);
			return;
		}

		try {
			// group covers by hostname so we can scrape multiple images from the same site in one driver
			const groups = new Map<string, { covers: typeof covers }>();
			for (const c of covers) {
				try {
					const host = new URL(c.url).hostname;
					const g = groups.get(host) ?? { covers: [] };
					g.covers.push(c);
					groups.set(host, g);
				} catch (e) {
					this.logger.warn(`URL inválida para capa: ${c.url}`, e);
				}
			}

			for (const [host, group] of groups) {
				const imageUrls = group.covers.map((c) => c.url);
				try {
					const savedPaths =
						await this.scrapingService.scrapeMultipleImages(
							urlOrigin,
							imageUrls,
						);
					// savedPaths are in same order as imageUrls
					for (let i = 0; i < savedPaths.length; i++) {
						const saved = savedPaths[i];
						const original = group.covers[i];
						if (!saved || saved === 'null') {
							this.logger.warn(
								`Falha ao salvar capa ${original.url} para livro ${book.title}`,
							);
							continue;
						}

						// Procura uma capa existente pela originalUrl para atualizar
						const existingCover =
							await this.coverRepository.findOne({
								where: {
									originalUrl: original.url,
									book: { id: book.id },
								},
							});

						let savedCover: Cover;
						if (existingCover) {
							// Atualiza a capa existente com o caminho local
							existingCover.url = saved;
							savedCover =
								await this.coverRepository.save(existingCover);
							this.logger.log(
								`Capa atualizada para o livro: ${book.title}`,
							);
						} else {
							// Cria nova capa (fluxo legado)
							const coverBook = this.coverRepository.create({
								title: original.title || 'Cover Image',
								url: saved,
								originalUrl: original.url,
								book: book,
								index: book.covers.length,
								selected: book.covers.length === 0,
							});
							savedCover =
								await this.coverRepository.save(coverBook);
							book.covers.push(savedCover); // Update in-memory list for subsequent iterations
							this.logger.log(
								`Capa salva para o livro: ${book.title}`,
							);
						}

						// Emite evento de capa processada
						this.eventEmitter.emit('cover.processed', {
							bookId: book.id,
							coverId: savedCover.id,
							url: saved,
						});
					}
				} catch (err) {
					this.logger.warn(
						`Falha ao baixar capas do host ${host} para o livro: ${book.title}`,
						err,
					);
				}
			}
		} catch (err) {
			this.logger.warn(
				`Erro ao processar capas para o livro: ${book.title}`,
				err,
			);
		}
	}

	private async getBook(bookId: string) {
		const queryRunner = this.dataSource.createQueryRunner('master');
		await queryRunner.connect();
		const book = await queryRunner.manager.findOne(Book, {
			where: { id: bookId },
			relations: ['covers'],
		});
		await queryRunner.release();
		return book;
	}

	@OnWorkerEvent('failed')
	onFailed(job: Job<QueueCoverProcessorDto>) {
		this.logger.error(
			`Job de capa com id ${job.id} FAILED!`,
			job.failedReason,
		);
	}
}

import { createHash } from 'node:crypto';
import { readFile } from 'node:fs/promises';
import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Queue } from 'bullmq';
import { ScrapingService } from 'src/scraping/scraping.service';
import { IsNull, Repository } from 'typeorm';
import { QueueCoverProcessorDto } from '../dto/queue-cover-processor.dto';
import { UrlImageDto } from '../dto/url-image.dto';
import { Cover } from '../entities/cover.entity';

const QUEUE_NAME = 'cover-image-queue';
const JOB_NAME = 'process-cover';

@Injectable()
export class CoverImageService {
	private readonly logger = new Logger(CoverImageService.name);

	constructor(
		@InjectQueue(QUEUE_NAME)
		private readonly coverImageQueue: Queue<QueueCoverProcessorDto>,
		@InjectRepository(Cover)
		private readonly coverRepository: Repository<Cover>,
		private readonly scrapingService: ScrapingService,
	) {}

	/**
	 * Adiciona um job de capa à fila.
	 * Usa jobId único com timestamp para permitir reprocessamento.
	 */
	public async addCoverToQueue(
		bookId: string,
		urlOrigin: string,
		covers: UrlImageDto[],
	): Promise<void> {
		const jobId = `cover-image-${bookId}-${Date.now()}`;

		try {
			await this.coverImageQueue.add(
				JOB_NAME,
				{ bookId, urlOrigin, covers },
				{ jobId },
			);
			this.logger.debug(
				`Adicionando job de capa (batch) para o livro: ${bookId}`,
			);
		} catch (error) {
			if (error.message?.includes('Job with this id already exists')) {
				this.logger.debug(
					`Job de capa para o livro ${bookId} já está na fila.`,
				);
			} else {
				throw error;
			}
		}
	}

	/**
	 * Calcula o hash SHA-256 do conteúdo de uma imagem.
	 * Suporta tanto URLs HTTP/HTTPS quanto caminhos de arquivo locais.
	 * @param imageSource URL ou caminho local da imagem
	 * @param refererUrl URL de origem para usar como referer (opcional)
	 * @returns Hash da imagem em hexadecimal
	 */
	async calculateImageHash(
		imageSource: string,
		refererUrl?: string,
	): Promise<string> {
		let buffer: Buffer;

		if (
			imageSource.startsWith('http://') ||
			imageSource.startsWith('https://')
		) {
			const pageUrl = refererUrl || new URL(imageSource).origin;

			try {
				buffer = await this.scrapingService.fetchImageBuffer(
					pageUrl,
					imageSource,
				);
			} catch (error) {
				this.logger.error(
					`Failed to download image for hash calculation: ${imageSource} (referer: ${pageUrl})`,
					error,
				);
				throw error;
			}
		} else {
			const realPath = imageSource.startsWith('/data/')
				? imageSource.replace('/data/', '/usr/src/app/data/')
				: imageSource;

			buffer = await readFile(realPath);
		}

		return createHash('sha256').update(buffer).digest('hex');
	}

	/**
	 * Recalcula o hash das capas existentes que ainda não têm imageHash preenchido.
	 * Isso é necessário para capas que foram cadastradas antes da implementação do sistema de deduplicação.
	 */
	async recalculateMissingCoverHashes(): Promise<void> {
		const coversWithoutHash = await this.coverRepository.find({
			where: { imageHash: IsNull() },
			relations: ['book'],
		});

		if (coversWithoutHash.length === 0) {
			this.logger.debug('No covers without hash found');
			return;
		}

		this.logger.log(
			`Found ${coversWithoutHash.length} covers without hash. Recalculating...`,
		);

		let successCount = 0;
		let errorCount = 0;

		for (const cover of coversWithoutHash) {
			try {
				const refererUrl = cover.book?.originalUrl?.[0];
				const imageHash = await this.calculateImageHash(
					cover.url,
					refererUrl,
				);
				cover.imageHash = imageHash;
				await this.coverRepository.save(cover);
				successCount++;
			} catch (error) {
				this.logger.warn(
					`Failed to calculate hash for cover ${cover.id} (${cover.url}): ${error.message}`,
				);
				errorCount++;
			}
		}

		this.logger.log(
			`Cover hash recalculation complete: ${successCount} success, ${errorCount} errors`,
		);
	}
}

import { OnWorkerEvent, Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger, OnModuleInit } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Job } from 'bullmq';
import { AppConfigService } from 'src/app-config/app-config.service';
import { Repository } from 'typeorm';
import { Chapter } from '../entities/chapter.entity';
import { ChapterScrapingSharedService } from './chapter-scraping.shared';

const QUEUE_NAME = 'fix-chapter-queue';

@Processor(QUEUE_NAME, { lockDuration: 120000 })
export class FixChapterProcessor extends WorkerHost implements OnModuleInit {
	private readonly logger = new Logger(FixChapterProcessor.name);

	constructor(
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		private readonly configService: AppConfigService,
		private readonly chapterScrapingShared: ChapterScrapingSharedService,
	) {
		super();
	}

	onModuleInit() {
		this.worker.concurrency =
			this.configService.queueConcurrency.fixChapter;
	}

	async process(job: Job<{ chapterId: string }>): Promise<void> {
		const { chapterId } = job.data;
		this.logger.debug(`Processando conserto para o capítulo: ${chapterId}`);

		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
			relations: ['book', 'pages'],
		});

		if (!chapter) {
			this.logger.warn(`Capítulo com ID ${chapterId} não encontrado.`);
			throw new Error(`Capítulo com ID ${chapterId} não encontrado.`);
		}

		// Emite evento de início
		this.chapterScrapingShared.emitStartedEvent(chapter);

		// Processa usando o serviço compartilhado com minPages
		const minPages = chapter.pages?.length || undefined;
		await this.chapterScrapingShared.processChapterPages(chapter, minPages);

		this.logger.log(`Capítulo ${chapterId} processado para conserto.`);
	}

	@OnWorkerEvent('failed')
	async onFailed(job: Job<{ chapterId: string }>): Promise<void> {
		const { chapterId } = job.data;
		this.logger.error(
			`Job de conserto com id ${job.id} FAILED! Attempt ${job.attemptsMade} for chapter ID: ${chapterId}`,
		);

		try {
			const chapter = await this.chapterRepository.findOne({
				where: { id: chapterId },
				relations: ['book'],
			});

			if (chapter) {
				this.chapterScrapingShared.emitFailedEvent(
					chapter,
					job.failedReason || 'Unknown error',
				);
			}
		} catch (error) {
			this.logger.error(
				`Erro ao emitir evento de falha para o capítulo ${chapterId}: ${error.message}`,
			);
		}
	}
}

import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Queue } from 'bullmq';

const QUEUE_NAME = 'fix-chapter-queue';
const JOB_NAME = 'fix-chapter';

@Injectable()
export class FixChapterService {
	private readonly logger = new Logger(FixChapterService.name);

	constructor(
		@InjectQueue(QUEUE_NAME)
		private readonly fixChapterQueue: Queue<{ chapterId: string }>,
	) {}

	/**
	 * Adiciona um capítulo à fila de conserto.
	 * Usa jobId único para deduplicação eficiente O(1).
	 */
	public async addChapterToFixQueue(chapterId: string): Promise<void> {
		const jobId = `fix-chapter-${chapterId}`;

		try {
			await this.fixChapterQueue.add(JOB_NAME, { chapterId }, { jobId });
			this.logger.debug(
				`Adicionando job de conserto para o capítulo: ${chapterId}`,
			);
		} catch (error) {
			// Job com mesmo ID já existe na fila
			if (error.message?.includes('Job with this id already exists')) {
				this.logger.debug(
					`Job de conserto para o capítulo ${chapterId} já está na fila.`,
				);
			} else {
				throw error;
			}
		}
	}
}

import { Injectable, Logger, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import {
	In,
	LessThanOrEqual,
	MoreThanOrEqual,
	Repository,
	SelectQueryBuilder,
} from 'typeorm';
import { Book } from '../entities/book.entity';
import { SensitiveContent } from '../entities/sensitive-content.entity';
import { CreateSensitiveContentDto } from './dto/create-sensitive-content.dto';
import { UpdateSensitiveContentDto } from './dto/update-sensitive-content.dto';

@Injectable()
export class SensitiveContentService {
	private readonly logger = new Logger(SensitiveContentService.name);
	constructor(
		@InjectRepository(SensitiveContent)
		private readonly sensitiveContentRepository: Repository<SensitiveContent>,
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
	) {}

	async getAll(maxWeightSensitiveContent = 0): Promise<SensitiveContent[]> {
		return this.sensitiveContentRepository.find({
			select: ['id', 'name', 'altNames'],
			order: { weight: 'ASC' },
			where: { weight: LessThanOrEqual(maxWeightSensitiveContent) },
		});
	}

	async getOne(id: string): Promise<SensitiveContent> {
		const sensitiveContent = await this.sensitiveContentRepository.findOne({
			where: { id },
		});
		if (!sensitiveContent) {
			throw new NotFoundException(
				`Sensitive content with id ${id} not found`,
			);
		}
		return sensitiveContent;
	}

	async create(dto: CreateSensitiveContentDto): Promise<SensitiveContent> {
		const sensitiveContent = this.sensitiveContentRepository.create(dto);
		return this.sensitiveContentRepository.save(sensitiveContent);
	}

	async update(
		id: string,
		dto: UpdateSensitiveContentDto,
	): Promise<SensitiveContent> {
		const sensitiveContent = await this.getOne(id);
		Object.assign(sensitiveContent, dto);
		return this.sensitiveContentRepository.save(sensitiveContent);
	}

	async remove(id: string): Promise<void> {
		const sensitiveContent = await this.getOne(id);
		await this.sensitiveContentRepository.remove(sensitiveContent);
	}

	async mergeSensitiveContent(id: string, copy: string[]) {
		const sensitiveContent = await this.sensitiveContentRepository.findOne({
			where: { id },
		});
		if (!sensitiveContent) {
			this.logger.warn(`Sensitive content with id ${id} not found`);
			throw new NotFoundException(
				`Sensitive content with id ${id} not found`,
			);
		}
		const copyContents = await this.sensitiveContentRepository.find({
			where: { id: In(copy) },
		});
		if (copyContents.length === 0) {
			this.logger.warn(
				`No sensitive content found for names: ${copy.join(', ')}`,
			);
			throw new NotFoundException(
				`No sensitive content found for names: ${copy.join(', ')}`,
			);
		}
		const books = await this.bookRepository
			.createQueryBuilder('book')
			.leftJoinAndSelect('book.sensitiveContent', 'sensitiveContent')
			.where('sensitiveContent.id IN (:...copyIds)', { copyIds: copy })
			.getMany();

		for (const book of books) {
			book.sensitiveContent = book.sensitiveContent.filter(
				(sc) => !copy.includes(sc.id),
			);
			if (!book.sensitiveContent.some((sc) => sc.id === id)) {
				book.sensitiveContent.push(sensitiveContent);
			}
			await this.bookRepository.save(book);
		}
		sensitiveContent.altNames = Array.from(
			new Set([
				...(sensitiveContent.altNames || []),
				...copyContents.flatMap((sc) => sc.altNames || []),
				...copyContents.map((sc) => sc.name),
			]),
		);
		await this.sensitiveContentRepository.save(sensitiveContent);
		await this.sensitiveContentRepository.remove(copyContents);
		return sensitiveContent;
	}

	async filterBooksSensitiveContent(
		queryBuilder: SelectQueryBuilder<Book>,
		names?: string[],
		weight = 0,
	): Promise<void> {
		let filterSafe = false;
		let maxWeight: number | undefined = undefined;
		let sensitiveContentNames: string[] = [];
		if (names) {
			filterSafe = names.includes('safe');
			sensitiveContentNames = names.filter((name) => name !== 'safe');
		}
		if (sensitiveContentNames.length === 0) {
			queryBuilder.andWhere('sensitiveContent.name IS NULL');
		} else if (sensitiveContentNames.length > 0) {
			const sensitiveContents =
				await this.sensitiveContentRepository.find({
					where: [
						{
							name: In(sensitiveContentNames),
							weight: LessThanOrEqual(weight),
						},
					],
				});
			if (sensitiveContents.length > 0) {
				maxWeight = Math.max(
					...sensitiveContents.map((sc) => sc.weight),
				);
				if (filterSafe) {
					queryBuilder.andWhere(
						'(sensitiveContent.name IN (:...sensitiveContents) OR sensitiveContent.name IS NULL)',
						{ sensitiveContents: sensitiveContentNames },
					);
				} else {
					queryBuilder.andWhere(
						'sensitiveContent.name IN (:...sensitiveContents)',
						{ sensitiveContents: sensitiveContentNames },
					);
				}
				queryBuilder.andWhere(
					'((SELECT MAX(sc.weight) FROM books_sensitive_content_sensitive_content ssc INNER JOIN sensitive_content sc ON sc.id = ssc.sensitiveContentId WHERE ssc.booksId = book.id) <= :maxWeight OR sensitiveContent.name IS NULL)',
					{ maxWeight },
				);
			} else {
				queryBuilder.andWhere('sensitiveContent.name IS NULL');
			}
		}
	}
}

import { Injectable, Logger } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { normalizeUrl } from 'src/common/utils/url.utils';
import { ScrapingService } from 'src/scraping/scraping.service';
import { Repository } from 'typeorm';
import { Book } from '../entities/book.entity';
import { Chapter } from '../entities/chapter.entity';
import { Cover } from '../entities/cover.entity';
import { ScrapingStatus } from '../enum/scrapingStatus.enum';
import { CoverImageService } from '../jobs/cover-image.service';

interface ScrapedChapter {
	title: string;
	url: string;
	index?: number;
	isFinal?: boolean;
}

interface ScrapedCover {
	url: string;
	title?: string;
}

interface BookContentUpdateResult {
	newChapters: number;
	newCovers: number;
}

/**
 * Service responsável pela lógica de negócio de atualização de conteúdo de livros
 * (novos capítulos e capas detectados via scraping)
 */
@Injectable()
export class BookContentUpdateService {
	private readonly logger = new Logger(BookContentUpdateService.name);

	constructor(
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		@InjectRepository(Cover)
		private readonly coverRepository: Repository<Cover>,
		private readonly scrapingService: ScrapingService,
		private readonly eventEmitter: EventEmitter2,
		private readonly coverImageService: CoverImageService,
	) {}

	/**
	 * Executa a atualização de conteúdo de um livro
	 */
	async performUpdate(bookId: string): Promise<BookContentUpdateResult> {
		this.logger.debug(`Processing book content update for: ${bookId}`);

		const book = await this.bookRepository.findOne({
			where: { id: bookId },
			relations: ['chapters', 'covers'],
		});

		if (!book) {
			this.logger.warn(`Book ${bookId} not found`);
			throw new Error(`Book ${bookId} not found`);
		}

		if (!book.originalUrl || book.originalUrl.length === 0) {
			this.logger.warn(`Book ${book.title} has no original URL`);
			return { newChapters: 0, newCovers: 0 };
		}

		let totalNewCovers = 0;
		let totalNewChapters = 0;
		const allCreatedChapters: Chapter[] = [];

		for (const bookUrl of book.originalUrl) {
			try {
				this.logger.debug(`Scraping book info from: ${bookUrl}`);

				const bookInfo =
					await this.scrapingService.scrapeBookInfo(bookUrl);

				const newCovers = await this.syncCovers(
					book,
					bookInfo.covers || [],
					bookUrl,
				);
				totalNewCovers += newCovers;

				if (bookInfo.chapters.length === 0) {
					this.logger.debug(`No chapters found from URL: ${bookUrl}`);
					continue;
				}

				const createdChapters = await this.syncChapters(
					book,
					bookInfo.chapters,
					allCreatedChapters,
				);
				allCreatedChapters.push(...createdChapters);
				totalNewChapters += createdChapters.length;
			} catch (error) {
				this.logger.warn(
					`Error scraping from URL ${bookUrl}: ${error.message}`,
				);
			}
		}

		if (allCreatedChapters.length > 0) {
			this.emitUpdateEvents(book, allCreatedChapters, totalNewCovers);
		}

		return { newChapters: totalNewChapters, newCovers: totalNewCovers };
	}

	/**
	 * Sincroniza capítulos: identifica novos capítulos e os cria no banco
	 */
	private async syncChapters(
		book: Book,
		scrapedChapters: ScrapedChapter[],
		alreadyCreatedChapters: Chapter[],
	): Promise<Chapter[]> {
		const existingUrls = new Set([
			...book.chapters.map((ch) => normalizeUrl(ch.originalUrl)),
			...alreadyCreatedChapters.map((ch) => normalizeUrl(ch.originalUrl)),
		]);

		const newChapters = scrapedChapters.filter(
			(ch) => !existingUrls.has(normalizeUrl(ch.url)),
		);

		if (newChapters.length === 0) {
			this.logger.debug('No new chapters found');
			return [];
		}

		this.logger.log(`Found ${newChapters.length} new chapters`);

		const existingIndexes = await this.getExistingChapterIndexes(
			book.id,
			alreadyCreatedChapters,
		);

		const createdChapters: Chapter[] = [];
		for (const scraped of newChapters) {
			const nextIndex = this.determineNextChapterIndex(
				scraped,
				existingIndexes,
			);

			const chapter = this.chapterRepository.create({
				title: scraped.title,
				originalUrl: normalizeUrl(scraped.url),
				index: nextIndex,
				isFinal: scraped.isFinal ?? false,
				book: book,
				scrapingStatus: ScrapingStatus.PROCESS,
			});

			const saved = await this.chapterRepository.save(chapter);
			createdChapters.push(saved);
			existingIndexes.add(nextIndex);
		}

		return createdChapters;
	}

	/**
	 * Busca todos os índices de capítulos existentes
	 */
	private async getExistingChapterIndexes(
		bookId: string,
		additionalChapters: Chapter[],
	): Promise<Set<number>> {
		const existingIndexesResult = await this.chapterRepository
			.createQueryBuilder('chapter')
			.withDeleted()
			.select('chapter.index', 'index')
			.where('chapter.bookId = :bookId', { bookId })
			.getRawMany();

		return new Set([
			...existingIndexesResult.map((r) => Number.parseFloat(r.index)),
			...additionalChapters.map((ch) => ch.index),
		]);
	}

	/**
	 * Determina o próximo índice disponível para um capítulo
	 */
	private determineNextChapterIndex(
		scrapedChapter: ScrapedChapter,
		existingIndexes: Set<number>,
	): number {
		if (
			typeof scrapedChapter.index === 'number' &&
			!Number.isNaN(scrapedChapter.index)
		) {
			return scrapedChapter.index;
		}

		let index = 1;
		while (existingIndexes.has(index)) {
			index++;
		}
		return index;
	}

	/**
	 * Sincroniza capas: identifica novas capas por hash e as cria
	 */
	private async syncCovers(
		book: Book,
		scrapedCovers: ScrapedCover[],
		refererUrl: string,
	): Promise<number> {
		if (scrapedCovers.length === 0) {
			return 0;
		}

		const existingHashes = new Set(
			book.covers.filter((c) => c.imageHash).map((c) => c.imageHash),
		);

		let newCoversCount = 0;

		for (const scrapedCover of scrapedCovers) {
			try {
				const imageHash =
					await this.coverImageService.calculateImageHash(
						scrapedCover.url,
						refererUrl,
					);

				if (existingHashes.has(imageHash)) {
					this.logger.debug(
						`Cover already exists (hash match): ${scrapedCover.url}`,
					);
					continue;
				}

				const cover = this.coverRepository.create({
					url: normalizeUrl(scrapedCover.url),
					originalUrl: normalizeUrl(scrapedCover.url),
					title:
						scrapedCover.title || `Capa ${book.covers.length + 1}`,
					index: book.covers.length,
					imageHash: imageHash,
					selected: book.covers.length === 0,
					book: book,
				});

				const savedCover = await this.coverRepository.save(cover);
				book.covers.push(savedCover);
				existingHashes.add(imageHash);
				newCoversCount++;

				await this.coverImageService.addCoverToQueue(
					book.id,
					refererUrl,
					[{ url: scrapedCover.url, title: savedCover.title }],
				);

				this.logger.debug(
					`Added new cover for book ${book.title}: ${scrapedCover.title || scrapedCover.url}`,
				);
			} catch (error) {
				this.logger.warn(
					`Failed to process cover ${scrapedCover.url}: ${error.message}`,
				);
			}
		}

		if (newCoversCount > 0) {
			this.logger.log(
				`Added ${newCoversCount} new covers to book: ${book.title}`,
			);
		}

		return newCoversCount;
	}

	/**
	 * Emite eventos de atualização
	 */
	private emitUpdateEvents(
		book: Book,
		newChapters: Chapter[],
		newCoversCount: number,
	): void {
		this.eventEmitter.emit('chapters.updated', newChapters);

		this.eventEmitter.emit('book.new-chapters', {
			bookId: book.id,
			newChaptersCount: newChapters.length,
			chapters: newChapters.map((ch) => ({
				id: ch.id,
				title: ch.title,
				index: ch.index,
				isFinal: ch.isFinal,
			})),
			newCoversCount: newCoversCount,
		});

		this.logger.log(
			`Added ${newChapters.length} new chapters to book: ${book.title}`,
		);
	}
}

import * as path from 'node:path';
import {
	BadRequestException,
	Injectable,
	NotFoundException,
} from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import pLimit from 'p-limit';
import { Counter, Histogram } from 'prom-client';
import { CustomLogger } from 'src/custom.logger';
import { FilesService } from 'src/files/files.service';
import { Repository } from 'typeorm';
import {
	FORMAT_TO_EXTENSION,
	MIMETYPE_TO_FORMAT,
} from '../constants/content-types.constants';
import { UploadTextContentDto } from '../dto/upload-text-content.dto';
import { Book } from '../entities/book.entity';
import { Chapter } from '../entities/chapter.entity';
import { Cover } from '../entities/cover.entity';
import { Page } from '../entities/page.entity';
import { ContentFormat } from '../enum/content-format.enum';
import { ContentType } from '../enum/content-type.enum';
import { DocumentFormat } from '../enum/document-format.enum';
import { ExportFormat } from '../enum/export-format.enum';

/**
 * Service responsável por upload de capas e páginas de capítulos
 */
@Injectable()
export class BookUploadService {
	constructor(
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		@InjectRepository(Cover)
		private readonly coverRepository: Repository<Cover>,
		@InjectRepository(Page)
		private readonly pageRepository: Repository<Page>,
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		private readonly filesService: FilesService,
		private readonly eventEmitter: EventEmitter2,
		private readonly logger: CustomLogger,
		@InjectMetric('file_uploads_total')
		private readonly uploadCounter: Counter,
		@InjectMetric('file_upload_size_bytes')
		private readonly uploadSize: Histogram,
		@InjectMetric('file_upload_duration_seconds')
		private readonly uploadDuration: Histogram,
	) {
		this.logger.setContext('BookUploadService');
	}

	/**
	 * Upload de uma única capa para um livro
	 */
	async uploadCover(
		bookId: string,
		file: Express.Multer.File,
		title?: string,
	): Promise<Cover> {
		const startTime = Date.now();

		this.logger.logFileUpload({
			fileName: file.originalname,
			message: 'Starting cover upload',
			metadata: {
				bookId,
				fileSize: file.size,
				mimeType: file.mimetype,
			},
		});

		this.uploadSize.observe({ type: 'cover' }, file.size);

		const book = await this.bookRepository.findOne({
			where: { id: bookId },
			relations: ['covers'],
		});

		if (!book) {
			this.logger.warn(
				`Book with id ${bookId} not found`,
				'BookUploadService',
			);
			this.uploadCounter.inc({ type: 'cover', status: 'error' });
			throw new NotFoundException(`Book with id ${bookId} not found`);
		}

		if (!file.mimetype.match(/^image\//)) {
			this.uploadCounter.inc({ type: 'cover', status: 'error' });
			throw new BadRequestException('Only image files are allowed');
		}

		try {
			const extension = path.extname(file.originalname) || '.jpg';

			const savedPath = await this.filesService.saveBufferFile(
				file.buffer,
				extension,
			);

			const cover = this.coverRepository.create({
				title: title || file.originalname,
				url: savedPath,
				book: book,
				index: book.covers.length,
				selected: book.covers.length === 0,
			});

			const savedCover = await this.coverRepository.save(cover);

			const duration = Date.now() - startTime;

			this.uploadCounter.inc({ type: 'cover', status: 'success' });
			this.uploadDuration.observe({ type: 'cover' }, duration / 1000);

			this.logger.logFileUpload({
				fileName: file.originalname,
				message: 'Cover uploaded successfully',
				metadata: {
					bookId: book.id,
					bookTitle: book.title,
					coverId: savedCover.id,
					duration,
				},
			});

			this.logger.logPerformance({
				operation: 'cover_upload',
				duration,
				metadata: {
					bookId,
					fileSize: file.size,
				},
			});

			this.eventEmitter.emit('cover.uploaded', {
				bookId: book.id,
				coverId: savedCover.id,
				url: savedPath,
			});

			return savedCover;
		} catch (error: any) {
			const duration = Date.now() - startTime;
			this.uploadCounter.inc({ type: 'cover', status: 'error' });
			this.uploadDuration.observe({ type: 'cover' }, duration / 1000);

			this.logger.error(error.message, 'BookUploadService', {
				bookId,
				fileName: file.originalname,
			});
			throw error;
		}
	}

	/**
	 * Substitui a imagem de uma capa existente
	 */
	async replaceCoverImage(
		bookId: string,
		coverId: string,
		file: Express.Multer.File,
		title?: string,
	): Promise<Cover> {
		const startTime = Date.now();

		this.logger.logFileUpload({
			fileName: file.originalname,
			message: 'Starting cover image replacement',
			metadata: {
				bookId,
				coverId,
				fileSize: file.size,
				mimeType: file.mimetype,
			},
		});

		this.uploadSize.observe({ type: 'cover_replace' }, file.size);

		const cover = await this.coverRepository.findOne({
			where: { id: coverId, book: { id: bookId } },
			relations: ['book'],
		});

		if (!cover) {
			this.logger.warn(
				`Cover with id ${coverId} not found for book ${bookId}`,
				'BookUploadService',
			);
			this.uploadCounter.inc({ type: 'cover_replace', status: 'error' });
			throw new NotFoundException(
				`Cover with id ${coverId} not found for book ${bookId}`,
			);
		}

		if (!file.mimetype.match(/^image\//)) {
			this.uploadCounter.inc({ type: 'cover_replace', status: 'error' });
			throw new BadRequestException('Only image files are allowed');
		}

		try {
			// Delete old image file if exists
			if (cover.url) {
				try {
					await this.filesService.deleteFile(cover.url);
				} catch (_deleteError: any) {
					this.logger.warn(
						`Failed to delete old cover image: ${cover.url}`,
						'BookUploadService',
					);
				}
			}

			const extension = path.extname(file.originalname) || '.jpg';
			const savedPath = await this.filesService.saveBufferFile(
				file.buffer,
				extension,
			);

			cover.url = savedPath;
			if (title !== undefined) {
				cover.title = title;
			}

			const updatedCover = await this.coverRepository.save(cover);

			const duration = Date.now() - startTime;

			this.uploadCounter.inc({
				type: 'cover_replace',
				status: 'success',
			});
			this.uploadDuration.observe(
				{ type: 'cover_replace' },
				duration / 1000,
			);

			this.logger.logFileUpload({
				fileName: file.originalname,
				message: 'Cover image replaced successfully',
				metadata: {
					bookId,
					coverId,
					duration,
				},
			});

			this.eventEmitter.emit('cover.updated', {
				bookId,
				coverId,
				url: savedPath,
			});

			return updatedCover;
		} catch (error: any) {
			const duration = Date.now() - startTime;
			this.uploadCounter.inc({ type: 'cover_replace', status: 'error' });
			this.uploadDuration.observe(
				{ type: 'cover_replace' },
				duration / 1000,
			);

			this.logger.error(error.message, 'BookUploadService', {
				bookId,
				coverId,
				fileName: file.originalname,
			});
			throw error;
		}
	}

	/**
	 * Upload de múltiplas capas para um livro
	 */
	async uploadMultipleCovers(
		bookId: string,
		files: Express.Multer.File[],
	): Promise<Cover[]> {
		const startTime = Date.now();

		this.logger.log(
			`Uploading ${files.length} covers for book: ${bookId}`,
			'BookUploadService',
		);

		if (files.length === 0) {
			throw new BadRequestException('No files provided');
		}

		if (files.length > 10) {
			throw new BadRequestException('Maximum 10 covers per upload');
		}

		const book = await this.bookRepository.findOne({
			where: { id: bookId },
			relations: ['covers'],
		});

		if (!book) {
			this.logger.warn(
				`Book with id ${bookId} not found`,
				'BookUploadService',
			);
			throw new NotFoundException(`Book with id ${bookId} not found`);
		}

		const savedPaths: string[] = [];

		try {
			const limit = pLimit(5);

			const covers = await Promise.all(
				files.map((file, index) =>
					limit(async () => {
						if (!file.mimetype.match(/^image\//)) {
							throw new BadRequestException(
								`File ${file.originalname} is not an image`,
							);
						}

						const extension =
							path.extname(file.originalname) || '.jpg';
						const savedPath =
							await this.filesService.saveBufferFile(
								file.buffer,
								extension,
							);
						savedPaths.push(savedPath);

						return this.coverRepository.create({
							title: file.originalname,
							url: savedPath,
							book: book,
							index: book.covers.length + index,
							selected: book.covers.length === 0 && index === 0,
						});
					}),
				),
			);

			const savedCovers = await this.coverRepository.save(covers);

			const duration = Date.now() - startTime;

			this.logger.logPerformance({
				operation: 'multiple_covers_upload',
				duration,
				metadata: {
					bookId,
					coversCount: savedCovers.length,
					totalSize: files.reduce((sum, f) => sum + f.size, 0),
				},
			});

			this.logger.log(
				`${savedCovers.length} covers uploaded successfully for book: ${book.title}`,
				'BookUploadService',
			);

			this.eventEmitter.emit('covers.uploaded', {
				bookId: book.id,
				count: savedCovers.length,
				coverIds: savedCovers.map((c) => c.id),
			});

			return savedCovers;
		} catch (error: any) {
			if (savedPaths.length > 0) {
				await Promise.all(
					savedPaths.map((p) =>
						this.filesService
							.deleteFile(p)
							.catch((e: any) =>
								this.logger.warn(
									`Failed to clean up file ${p} after upload error: ${e.message}`,
									'BookUploadService',
								),
							),
					),
				);
			}
			this.logger.error(error.message, 'BookUploadService', {
				bookId,
				filesCount: files.length,
			});
			throw error;
		}
	}

	/**
	 * Upload de páginas para um capítulo
	 */
	async uploadChapterPages(
		chapterId: string,
		files: Express.Multer.File[],
		indices: number[],
	): Promise<Page[]> {
		const startTime = Date.now();

		this.logger.logChapterProcessing({
			chapterId,
			message: `Starting upload of ${files.length} pages`,
			metadata: {
				filesCount: files.length,
				indicesCount: indices.length,
			},
		});

		if (files.length === 0) {
			throw new BadRequestException('No files provided');
		}

		if (files.length !== indices.length) {
			throw new BadRequestException(
				'Number of files must match number of indices',
			);
		}

		if (files.length > 100) {
			throw new BadRequestException('Maximum 100 pages per upload');
		}

		const uniqueIndices = new Set(indices);
		if (uniqueIndices.size !== indices.length) {
			throw new BadRequestException('Duplicate indices found');
		}

		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
			relations: ['pages', 'book'],
		});

		if (!chapter) {
			this.logger.warn(
				`Chapter with id ${chapterId} not found`,
				'BookUploadService',
			);
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}

		const existingIndices = chapter.pages.map((p) => p.index);
		const conflictingIndices = indices.filter((i) =>
			existingIndices.includes(i),
		);

		if (conflictingIndices.length > 0) {
			throw new BadRequestException(
				`Pages with indices ${conflictingIndices.join(', ')} already exist`,
			);
		}

		try {
			const pages = await Promise.all(
				files.map(async (file, i) => {
					if (!file.mimetype.match(/^image\//)) {
						throw new BadRequestException(
							`File ${file.originalname} is not an image`,
						);
					}

					const extension = path.extname(file.originalname) || '.jpg';
					const savedPath = await this.filesService.saveBufferFile(
						file.buffer,
						extension,
					);

					return this.pageRepository.create({
						index: indices[i],
						path: savedPath,
						chapter: chapter,
					});
				}),
			);

			const savedPages = await this.pageRepository.save(pages);

			const duration = Date.now() - startTime;

			this.logger.logChapterProcessing({
				chapterId,
				message: 'Pages uploaded successfully',
				metadata: {
					pagesCount: savedPages.length,
					duration,
					bookId: chapter.book?.id,
					totalSize: files.reduce((sum, f) => sum + f.size, 0),
				},
			});

			this.logger.logPerformance({
				operation: 'chapter_pages_upload',
				duration,
				metadata: {
					chapterId,
					pagesCount: savedPages.length,
				},
			});

			this.eventEmitter.emit('chapter.pages.uploaded', {
				chapterId: chapter.id,
				bookId: chapter.book?.id,
				count: savedPages.length,
			});

			return savedPages;
		} catch (error: any) {
			this.logger.error(error.message, 'BookUploadService', {
				chapterId,
				filesCount: files.length,
			});
			throw error;
		}
	}

	// ==================== UPLOAD DE DOCUMENTOS (PDF/EPUB) ====================

	/**
	 * Upload de um documento (PDF/EPUB) para um capítulo
	 * O documento é salvo sem compressão (já são formatos comprimidos)
	 */
	async uploadChapterDocument(
		chapterId: string,
		file: Express.Multer.File,
		title?: string,
	): Promise<Chapter> {
		const startTime = Date.now();

		this.logger.logChapterProcessing({
			chapterId,
			message: `Starting document upload: ${file.originalname}`,
			metadata: {
				fileSize: file.size,
				mimeType: file.mimetype,
			},
		});

		this.uploadSize.observe({ type: 'document' }, file.size);

		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
			relations: ['book'],
		});

		if (!chapter) {
			this.logger.warn(
				`Chapter with id ${chapterId} not found`,
				'BookUploadService',
			);
			this.uploadCounter.inc({ type: 'document', status: 'error' });
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}

		// Detecta formato baseado no mimetype
		const documentFormat = MIMETYPE_TO_FORMAT[file.mimetype];
		if (!documentFormat) {
			this.uploadCounter.inc({ type: 'document', status: 'error' });
			throw new BadRequestException(
				`Tipo de arquivo não suportado: ${file.mimetype}. Use PDF ou EPUB.`,
			);
		}

		try {
			// Deleta documento anterior se existir
			if (chapter.documentPath) {
				try {
					await this.filesService.deleteFile(chapter.documentPath);
				} catch (_deleteError: any) {
					this.logger.warn(
						`Falha ao deletar documento anterior: ${chapter.documentPath}`,
						'BookUploadService',
					);
				}
			}

			// Salva o documento (sem compressão - PDF/EPUB já são comprimidos)
			const extension = FORMAT_TO_EXTENSION[documentFormat];
			const savedPath = await this.filesService.saveBufferFile(
				file.buffer,
				extension,
			);

			// Atualiza o capítulo
			chapter.contentType = ContentType.DOCUMENT;
			chapter.documentPath = savedPath;
			chapter.documentFormat = documentFormat;
			chapter.scrapingStatus = null; // Documentos não precisam de scraping

			// Limpa campos não utilizados
			chapter.content = null;
			chapter.contentFormat = null;

			// Atualiza título se fornecido
			if (title) {
				chapter.title = title;
			}

			const savedChapter = await this.chapterRepository.save(chapter);

			// Atualiza formatos disponíveis no livro
			await this.updateBookAvailableFormats(
				chapter.book.id,
				documentFormat,
			);

			const duration = Date.now() - startTime;

			this.uploadCounter.inc({ type: 'document', status: 'success' });
			this.uploadDuration.observe({ type: 'document' }, duration / 1000);

			this.logger.logChapterProcessing({
				chapterId,
				message: 'Document uploaded successfully',
				metadata: {
					documentFormat,
					duration,
					bookId: chapter.book?.id,
					fileSize: file.size,
				},
			});

			this.eventEmitter.emit('chapter.document.uploaded', {
				chapterId: chapter.id,
				bookId: chapter.book?.id,
				format: documentFormat,
			});

			return savedChapter;
		} catch (error: any) {
			const duration = Date.now() - startTime;
			this.uploadCounter.inc({ type: 'document', status: 'error' });
			this.uploadDuration.observe({ type: 'document' }, duration / 1000);

			this.logger.error(error.message, 'BookUploadService', {
				chapterId,
				fileName: file.originalname,
			});
			throw error;
		}
	}

	// ==================== UPLOAD DE CONTEÚDO TEXTUAL ====================

	/**
	 * Upload de conteúdo textual (Markdown/HTML/Plain) para um capítulo
	 * Usado para Light Novels e conteúdo de texto
	 */
	async uploadChapterTextContent(
		chapterId: string,
		dto: UploadTextContentDto,
	): Promise<Chapter> {
		const startTime = Date.now();

		this.logger.logChapterProcessing({
			chapterId,
			message: 'Starting text content upload',
			metadata: {
				format: dto.format,
				contentLength: dto.content.length,
			},
		});

		const chapter = await this.chapterRepository.findOne({
			where: { id: chapterId },
			relations: ['book'],
		});

		if (!chapter) {
			this.logger.warn(
				`Chapter with id ${chapterId} not found`,
				'BookUploadService',
			);
			throw new NotFoundException(
				`Chapter with id ${chapterId} not found`,
			);
		}

		try {
			// Deleta documento anterior se existir (mudando de DOCUMENT para TEXT)
			if (chapter.documentPath) {
				try {
					await this.filesService.deleteFile(chapter.documentPath);
				} catch (_deleteError: any) {
					this.logger.warn(
						`Falha ao deletar documento anterior: ${chapter.documentPath}`,
						'BookUploadService',
					);
				}
			}

			// Atualiza o capítulo com conteúdo textual
			chapter.contentType = ContentType.TEXT;
			chapter.content = dto.content;
			chapter.contentFormat = dto.format;
			chapter.scrapingStatus = null; // Texto não precisa de scraping

			// Limpa campos não utilizados
			chapter.documentPath = null;
			chapter.documentFormat = null;

			const savedChapter = await this.chapterRepository.save(chapter);

			// Atualiza formatos disponíveis no livro
			const exportFormat = this.contentFormatToExportFormat(dto.format);
			await this.updateBookAvailableFormats(
				chapter.book.id,
				exportFormat,
			);

			const duration = Date.now() - startTime;

			this.logger.logChapterProcessing({
				chapterId,
				message: 'Text content uploaded successfully',
				metadata: {
					contentFormat: dto.format,
					duration,
					bookId: chapter.book?.id,
					contentLength: dto.content.length,
				},
			});

			this.eventEmitter.emit('chapter.content.uploaded', {
				chapterId: chapter.id,
				bookId: chapter.book?.id,
				format: dto.format,
			});

			return savedChapter;
		} catch (error: any) {
			this.logger.error(error.message, 'BookUploadService', {
				chapterId,
				contentFormat: dto.format,
			});
			throw error;
		}
	}

	// ==================== HELPERS ====================

	/**
	 * Atualiza a lista de formatos disponíveis para um livro
	 */
	private async updateBookAvailableFormats(
		bookId: string,
		newFormat: ExportFormat | DocumentFormat | string,
	): Promise<void> {
		const book = await this.bookRepository.findOne({
			where: { id: bookId },
		});

		if (!book) return;

		const currentFormats = book.availableFormats || [];
		const formatString = newFormat as ExportFormat;

		if (!currentFormats.includes(formatString)) {
			book.availableFormats = [...currentFormats, formatString];
			await this.bookRepository.save(book);

			this.logger.debug(
				`Updated book ${bookId} availableFormats: ${book.availableFormats.join(', ')}`,
			);
		}
	}

	/**
	 * Converte ContentFormat para ExportFormat
	 */
	private contentFormatToExportFormat(format: ContentFormat): ExportFormat {
		switch (format) {
			case ContentFormat.MARKDOWN:
				return ExportFormat.MARKDOWN;
			case ContentFormat.HTML:
			case ContentFormat.PLAIN:
				// HTML e PLAIN podem ser exportados como PDF
				return ExportFormat.PDF;
			default:
				return ExportFormat.PDF;
		}
	}
}

import { SelectQueryBuilder } from 'typeorm';
import { BookPageOptionsDto } from '../dto/book-page-options.dto';
import { Book } from '../entities/book.entity';
import { FilterStrategy } from './filter-strategy.interface';

export class PublicationFilterStrategy implements FilterStrategy {
	canApply(options: BookPageOptionsDto): boolean {
		return !!options.publication;
	}

	apply(
		queryBuilder: SelectQueryBuilder<Book>,
		options: BookPageOptionsDto,
	): void {
		const operator = options.publicationOperator || 'eq';
		const publication = options.publication ?? 0;

		switch (operator) {
			case 'eq':
				queryBuilder.andWhere('book.publication = :publication', {
					publication,
				});
				break;
			case 'gt':
				queryBuilder.andWhere('book.publication > :publication', {
					publication,
				});
				break;
			case 'lt':
				queryBuilder.andWhere('book.publication < :publication', {
					publication,
				});
				break;
			case 'gte':
				queryBuilder.andWhere('book.publication >= :publication', {
					publication,
				});
				break;
			case 'lte':
				queryBuilder.andWhere('book.publication <= :publication', {
					publication,
				});
				break;
		}
	}
}

import { Transform } from 'class-transformer';
import { normalizeUrl as normalizeUrlUtil } from '../utils/url.utils';

/**
 * Decorator that normalizes URLs by removing 'www.' subdomain
 * Applies to both single URLs and arrays of URLs
 *
 * @example
 * class MyDto {
 *   @NormalizeUrl()
 *   url: string;
 *
 *   @NormalizeUrl()
 *   urls: string[];
 * }
 */
export function NormalizeUrl() {
	return Transform(({ value }) => {
		if (!value) return value;

		// Handle array of URLs
		if (Array.isArray(value)) {
			return value.map((url) => normalizeUrlUtil(url));
		}

		// Handle single URL
		return normalizeUrlUtil(value);
	});
}

import {
	CallHandler,
	ExecutionContext,
	Injectable,
	NestInterceptor,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

@Injectable()
export class DataEnvelopeInterceptor implements NestInterceptor {
	intercept(
		_context: ExecutionContext,
		next: CallHandler,
	): Observable<unknown> {
		return next.handle().pipe(
			map((payload) => {
				if (
					payload &&
					typeof payload === 'object' &&
					'data' in payload &&
					'meta' in payload
				) {
					return payload;
				}

				return {
					data: payload,
					meta: null,
					links: null,
				};
			}),
		);
	}
}

import {
	CallHandler,
	ExecutionContext,
	Injectable,
	NestInterceptor,
} from '@nestjs/common';
import { Request, Response } from 'express';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { Counter, Histogram } from 'prom-client';
import { Observable, throwError } from 'rxjs';
import { catchError, tap } from 'rxjs/operators';

@Injectable()
export class MetricsInterceptor implements NestInterceptor {
	constructor(
		@InjectMetric('http_requests_total')
		private readonly requestCounter: Counter,
		@InjectMetric('http_request_duration_seconds')
		private readonly requestDuration: Histogram,
		@InjectMetric('http_request_size_bytes')
		private readonly requestSize: Histogram,
		@InjectMetric('http_response_size_bytes')
		private readonly responseSize: Histogram,
	) {}

	intercept(
		context: ExecutionContext,
		next: CallHandler,
	): Observable<unknown> {
		const httpContext = context.switchToHttp();
		const request = httpContext.getRequest<Request>();
		const response = httpContext.getResponse<Response>();

		const { method, body } = request;
		const routePath =
			(request.route as { path?: string } | undefined)?.path ||
			request.url;
		const startTime = Date.now();

		// Tamanho da requisição
		const reqSize = body ? JSON.stringify(body).length : 0;
		if (reqSize > 0) {
			this.requestSize.observe(
				{
					method,
					route: routePath,
				},
				reqSize,
			);
		}

		return next.handle().pipe(
			tap((data: unknown) => {
				const duration = (Date.now() - startTime) / 1000;
				const { statusCode } = response;

				// Incrementa contador de requisições
				this.requestCounter.inc({
					method,
					route: routePath,
					status: statusCode,
				});

				// Registra duração
				this.requestDuration.observe(
					{
						method,
						route: routePath,
						status: statusCode,
					},
					duration,
				);

				// Tamanho da resposta (com tratamento para referências circulares)
				let resSize = 0;
				try {
					resSize = data ? JSON.stringify(data).length : 0;
				} catch {
					// Ignora erro de referência circular
					resSize = 0;
				}
				if (resSize > 0) {
					this.responseSize.observe(
						{
							method,
							route: routePath,
							status: statusCode,
						},
						resSize,
					);
				}
			}),
			catchError((error: { status?: number }) => {
				const duration = (Date.now() - startTime) / 1000;
				const statusCode = error.status || 500;

				// Incrementa contador mesmo em caso de erro
				this.requestCounter.inc({
					method,
					route: routePath,
					status: statusCode,
				});

				// Registra duração do erro
				this.requestDuration.observe(
					{
						method,
						route: routePath,
						status: statusCode,
					},
					duration,
				);

				return throwError(() => error);
			}),
		);
	}
}

