import { Injectable } from '@nestjs/common';
import * as argon2 from 'argon2';
import { AppConfigService } from 'src/app-config/app-config.service';
import { PasswordHasher } from '../interfaces/password-hasher.interface';

@Injectable()
export class Argon2Strategy implements PasswordHasher {
	readonly algorithm = 'argon2';
	private options: argon2.Options = {};

	constructor(private readonly config: AppConfigService) {
		this.options = {
			type: argon2.argon2id,
			memoryCost: 65536, // 64 MB
			timeCost: 3, // 3 iterações
			parallelism: 4, // 4 threads
			hashLength: this.config.passwordKeyLength, // Tamanho do hash em bytes
		};
	}

	async hash(password: string): Promise<string> {
		return argon2.hash(password, this.options);
	}

	async compare(password: string, hash: string): Promise<boolean> {
		try {
			return argon2.verify(hash, password);
		} catch (error) {
			return false;
		}
	}
}

import { Injectable } from '@nestjs/common';
import * as bcrypt from 'bcrypt';
import { AppConfigService } from 'src/app-config/app-config.service';
import { PasswordHasher } from '../interfaces/password-hasher.interface';

@Injectable()
export class BcryptStrategy implements PasswordHasher {
	readonly algorithm = 'bcrypt';

	constructor(private readonly config: AppConfigService) {}

	async hash(password: string): Promise<string> {
		return bcrypt.hash(password, this.config.saltLength);
	}

	async compare(password: string, hash: string): Promise<boolean> {
		try {
			return bcrypt.compare(password, hash);
		} catch (error) {
			return false;
		}
	}
}

import { Injectable, Logger } from '@nestjs/common';
import { IFileCompressor } from '../interfaces/file-compressor.interface';

@Injectable()
export class NoCompressionAdapter implements IFileCompressor {
	private readonly logger = new Logger(NoCompressionAdapter.name);

	compress(buffer: Buffer): Promise<Buffer> {
		this.logger.debug('Arquivo sem compressão, retornando original');
		return Promise.resolve(buffer);
	}

	supports(extension: string): boolean {
		return true;
	}

	getOutputExtension(originalExtension: string): string {
		return originalExtension;
	}

	getSupportedExtensions(): string[] {
		return ['*'];
	}
}

import { Injectable } from '@nestjs/common';
import sharp from 'sharp';
import { IFileCompressor } from '../interfaces/file-compressor.interface';
import { IImageCompressor } from '../interfaces/image-compressor.interface';

// Disable libvips operation cache so it doesn't accumulate decoded images
// across processing sessions. Without this, libvips quietly grows outside
// the V8 heap and V8's GC never sees the pressure.
sharp.cache(false);

@Injectable()
export class SharpAdapter implements IImageCompressor, IFileCompressor {
	private readonly supportedExtensions = [
		'.jpg',
		'.jpeg',
		'.png',
		'.webp',
		'.bmp',
		'.tiff',
		'.gif',
		'.avif',
		'.heif',
	];

	async compress(buffer: Buffer): Promise<Buffer> {
		const sharpInstance = sharp(buffer);
		const pipeline = sharpInstance.webp({
			lossless: false,
			quality: 80,
		});
		return await pipeline.toBuffer();
	}

	supports(extension: string): boolean {
		return this.supportedExtensions.includes(extension.toLowerCase());
	}

	getOutputExtension(originalExtension: string): string {
		return '.webp';
	}

	getSupportedExtensions(): string[] {
		return [...this.supportedExtensions];
	}
}

import * as fs from 'node:fs/promises';
import * as path from 'node:path';
import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { LessThan, Repository } from 'typeorm';
import { Book } from '../books/entities/book.entity';
import { Chapter } from '../books/entities/chapter.entity';
import { Cover } from '../books/entities/cover.entity';
import { Page } from '../books/entities/page.entity';

export interface OrphanFile {
	filename: string;
	fullPath: string;
	size: number;
	lastModified: Date;
	reason: 'no_page_reference' | 'no_cover_reference';
}

export interface MissingFile {
	entityType: 'page' | 'cover';
	entityId: string | number;
	expectedPath: string;
	bookId?: string;
	chapterId?: string;
}

export interface CleanupReport {
	totalFilesScanned: number;
	orphanFilesFound: number;
	filesDeleted: number;
	spaceRecovered: number;
	errors: string[];
	dryRun: boolean;
}

@Injectable()
export class FileCleanupService {
	private readonly logger = new Logger(FileCleanupService.name);
	private readonly downloadDir = path.resolve('/usr/src/app/data');
	private readonly retentionDays: number;

	constructor(
		@InjectRepository(Page)
		private readonly pageRepository: Repository<Page>,
		@InjectRepository(Cover)
		private readonly coverRepository: Repository<Cover>,
		@InjectRepository(Book)
		private readonly bookRepository: Repository<Book>,
		@InjectRepository(Chapter)
		private readonly chapterRepository: Repository<Chapter>,
		private readonly configService: ConfigService,
	) {
		this.retentionDays = this.configService.get<number>(
			'SOFT_DELETE_RETENTION_DAYS',
			10,
		);
	}

	async deleteFile(filePath: string): Promise<void> {
		try {
			const filename = filePath.replace('/data/', '');
			const fullPath = path.join(this.downloadDir, filename);

			try {
				const stats = await fs.stat(fullPath);
				if (stats.isDirectory()) {
					this.logger.warn(`Skipping directory: ${filename}`);
					return;
				}
			} catch (statError: any) {
				if (statError.code === 'ENOENT') {
					this.logger.warn(
						`File not found (already deleted?): ${filePath}`,
					);
					return;
				}
			}

			await fs.unlink(fullPath);
			this.logger.log(`File deleted: ${filename}`);
		} catch (error: any) {
			if (error.code !== 'ENOENT') {
				this.logger.error(`Error deleting file ${filePath}:`, error);
				throw error;
			}
			this.logger.warn(`File not found (already deleted?): ${filePath}`);
		}
	}

	/**
	 * Obtém todos os arquivos recursivamente usando um Generator para economizar memória
	 * @private
	 */
	private async *getAllFilesGenerator(
		dir: string,
		baseDir?: string,
	): AsyncGenerator<{
		filename: string;
		fullPath: string;
		size: number;
		mtime: Date;
	}> {
		const effectiveBaseDir = baseDir || dir;
		let entries: import('node:fs').Dirent[];
		try {
			entries = await fs.readdir(dir, { withFileTypes: true });
		} catch (error) {
			this.logger.error(`Error reading directory ${dir}:`, error);
			return;
		}

		for (const entry of entries) {
			const fullPath = path.join(dir, entry.name);
			const relativePath = path.relative(effectiveBaseDir, fullPath);

			if (entry.isDirectory()) {
				if (entry.name === 'cache') continue;
				yield* this.getAllFilesGenerator(fullPath, effectiveBaseDir);
			} else {
				try {
					const stats = await fs.stat(fullPath);
					yield {
						filename: relativePath,
						fullPath,
						size: stats.size,
						mtime: stats.mtime,
					};
				} catch (error) {
					this.logger.error(
						`Error reading file stats for ${relativePath}:`,
						error,
					);
				}
			}
		}
	}

	async findOrphanFiles(): Promise<OrphanFile[]> {
		this.logger.log('Starting orphan file scan (Memory-Safe mode)...');

		try {
			const pages = await this.pageRepository.find({
				select: ['path'],
				withDeleted: true,
			});
			const covers = await this.coverRepository.find({
				select: ['url'],
				withDeleted: true,
			});

			const allReferencedFiles = new Set([
				...pages.map((p) => p.path.replace('/data/', '')),
				...covers.map((c) => c.url.replace('/data/', '')),
			]);

			const orphanFiles: OrphanFile[] = [];

			for await (const file of this.getAllFilesGenerator(
				this.downloadDir,
			)) {
				if (!allReferencedFiles.has(file.filename)) {
					orphanFiles.push({
						filename: file.filename,
						fullPath: file.fullPath,
						size: file.size,
						lastModified: file.mtime,
						reason: 'no_page_reference',
					});

					if (orphanFiles.length >= 10000) {
						this.logger.warn(
							'Too many orphan files found, truncating list at 10k items for safety.',
						);
						break;
					}
				}
			}

			this.logger.log(`Found ${orphanFiles.length} orphan files`);
			return orphanFiles;
		} catch (error) {
			this.logger.error('Error scanning for orphan files:', error);
			throw error;
		}
	}

	async cleanupOrphanFiles(dryRun = true): Promise<CleanupReport> {
		this.logger.log(`Starting orphan cleanup (dryRun: ${dryRun})...`);

		const orphanFiles = await this.findOrphanFiles();
		const report: CleanupReport = {
			totalFilesScanned: orphanFiles.length,
			orphanFilesFound: orphanFiles.length,
			filesDeleted: 0,
			spaceRecovered: 0,
			errors: [],
			dryRun,
		};

		if (dryRun) {
			this.logger.log('Dry run - no files will be deleted');
			return report;
		}

		for (const file of orphanFiles) {
			try {
				await fs.unlink(file.fullPath);
				report.filesDeleted++;
				report.spaceRecovered += file.size;
				this.logger.log(`Deleted orphan file: ${file.filename}`);
			} catch (error: any) {
				const errorMsg = `Failed to delete ${file.filename}: ${error.message}`;
				this.logger.error(errorMsg);
				report.errors.push(errorMsg);
			}
		}

		this.logger.log(
			`Cleanup completed: ${report.filesDeleted} files deleted, ${(report.spaceRecovered / 1024 / 1024).toFixed(2)} MB recovered`,
		);
		return report;
	}

	async cleanupOrphansImmediate(): Promise<CleanupReport> {
		this.logger.log('Starting immediate orphan cleanup...');
		return this.cleanupOrphanFiles(false);
	}

	async findMissingFiles(): Promise<MissingFile[]> {
		this.logger.log('Starting missing file check (Batch mode)...');

		const missingFiles: MissingFile[] = [];
		const batchSize = 1000;

		// Processa Pages em lotes
		let offset = 0;
		while (true) {
			const pages = await this.pageRepository.find({
				relations: ['chapter', 'chapter.book'],
				take: batchSize,
				skip: offset,
			});

			if (pages.length === 0) break;

			for (const page of pages) {
				const filename = page.path.replace('/data/', '');
				const fullPath = path.join(this.downloadDir, filename);

				try {
					await fs.access(fullPath);
				} catch {
					missingFiles.push({
						entityType: 'page',
						entityId: page.id,
						expectedPath: page.path,
						chapterId: page.chapter?.id,
						bookId: page.chapter?.book?.id,
					});
				}
			}

			offset += batchSize;
			if (missingFiles.length >= 1000) {
				this.logger.warn(
					'Too many missing files found, truncating report at 1k items.',
				);
				break;
			}
		}

		// Processa Covers em lotes (se não atingiu o limite)
		if (missingFiles.length < 1000) {
			offset = 0;
			while (true) {
				const covers = await this.coverRepository.find({
					relations: ['book'],
					take: batchSize,
					skip: offset,
				});

				if (covers.length === 0) break;

				for (const cover of covers) {
					const filename = cover.url.replace('/data/', '');
					const fullPath = path.join(this.downloadDir, filename);

					try {
						await fs.access(fullPath);
					} catch {
						missingFiles.push({
							entityType: 'cover',
							entityId: cover.id,
							expectedPath: cover.url,
							bookId: cover.book?.id,
						});
					}
				}

				offset += batchSize;
				if (missingFiles.length >= 1000) break;
			}
		}

		this.logger.log(`Found ${missingFiles.length} missing files`);
		return missingFiles;
	}

	async cleanupOldDeletedFiles(): Promise<CleanupReport> {
		this.logger.log(
			`Cleaning up files deleted more than ${this.retentionDays} days ago...`,
		);

		const cutoffDate = new Date();
		cutoffDate.setDate(cutoffDate.getDate() - this.retentionDays);

		const report: CleanupReport = {
			totalFilesScanned: 0,
			orphanFilesFound: 0,
			filesDeleted: 0,
			spaceRecovered: 0,
			errors: [],
			dryRun: false,
		};

		const oldPages = await this.pageRepository.find({
			where: {
				deletedAt: LessThan(cutoffDate),
			},
			withDeleted: true,
		});

		for (const page of oldPages) {
			try {
				const filename = page.path.replace('/data/', '');
				const fullPath = path.join(this.downloadDir, filename);
				const stats = await fs.stat(fullPath);

				await fs.unlink(fullPath);
				report.filesDeleted++;
				report.spaceRecovered += stats.size;

				await this.pageRepository.remove(page);

				this.logger.log(`Deleted old page file: ${filename}`);
			} catch (error: any) {
				if (error.code !== 'ENOENT') {
					const errorMsg = `Failed to delete page ${page.id}: ${error.message}`;
					this.logger.error(errorMsg);
					report.errors.push(errorMsg);
				}
			}
		}

		const oldCovers = await this.coverRepository.find({
			where: {
				deletedAt: LessThan(cutoffDate),
			},
			withDeleted: true,
		});

		for (const cover of oldCovers) {
			try {
				const filename = cover.url.replace('/data/', '');
				const fullPath = path.join(this.downloadDir, filename);
				const stats = await fs.stat(fullPath);

				await fs.unlink(fullPath);
				report.filesDeleted++;
				report.spaceRecovered += stats.size;

				await this.coverRepository.remove(cover);

				this.logger.log(`Deleted old cover file: ${filename}`);
			} catch (error: any) {
				if (error.code !== 'ENOENT') {
					const errorMsg = `Failed to delete cover ${cover.id}: ${error.message}`;
					this.logger.error(errorMsg);
					report.errors.push(errorMsg);
				}
			}
		}

		const oldChapters = await this.chapterRepository.find({
			where: {
				deletedAt: LessThan(cutoffDate),
			},
			withDeleted: true,
		});

		for (const chapter of oldChapters) {
			await this.chapterRepository.remove(chapter);
		}

		const oldBooks = await this.bookRepository.find({
			where: {
				deletedAt: LessThan(cutoffDate),
			},
			withDeleted: true,
		});

		for (const book of oldBooks) {
			await this.bookRepository.remove(book);
		}

		report.totalFilesScanned = oldPages.length + oldCovers.length;
		report.orphanFilesFound = report.filesDeleted;

		this.logger.log(
			`Cleanup completed: ${report.filesDeleted} files deleted, ${(report.spaceRecovered / 1024 / 1024).toFixed(2)} MB recovered`,
		);
		return report;
	}

	async getStorageStatistics(): Promise<{
		totalFiles: number;
		totalSize: number;
		totalSizeMB: string;
		referencedPages: number;
		referencedCovers: number;
		deletedPages: number;
		deletedCovers: number;
		retentionDays: number;
	}> {
		this.logger.log('Calculating storage statistics (Streaming mode)...');

		let totalSize = 0;
		let fileCount = 0;

		for await (const file of this.getAllFilesGenerator(this.downloadDir)) {
			totalSize += file.size;
			fileCount++;
		}

		const pages = await this.pageRepository.count();
		const covers = await this.coverRepository.count();
		const deletedPages =
			(await this.pageRepository.count({ withDeleted: true })) - pages;
		const deletedCovers =
			(await this.coverRepository.count({ withDeleted: true })) - covers;

		return {
			totalFiles: fileCount,
			totalSize: totalSize,
			totalSizeMB: (totalSize / 1024 / 1024).toFixed(2),
			referencedPages: pages,
			referencedCovers: covers,
			deletedPages,
			deletedCovers,
			retentionDays: this.retentionDays,
		};
	}
}

import { Controller, Get, Inject } from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import {
	DiskHealthIndicator,
	HealthCheck,
	HealthCheckService,
	MemoryHealthIndicator,
	TypeOrmHealthIndicator,
} from '@nestjs/terminus';
import { Redis } from 'ioredis';
import { REDIS_CLIENT } from '../redis/redis.constants';
import { AppConfigService } from '../app-config/app-config.service';

@ApiTags('Health')
@Controller('health')
export class HealthController {
	constructor(
		private health: HealthCheckService,
		private db: TypeOrmHealthIndicator,
		private memory: MemoryHealthIndicator,
		private disk: DiskHealthIndicator,
		private appConfig: AppConfigService,
		@Inject(REDIS_CLIENT) private readonly redis: Redis,
	) {}

	@Get()
	@HealthCheck()
	@ApiOperation({
		summary: 'Health check completo',
		description:
			'Verifica status do banco, Redis, memória detalhada e disco',
	})
	@ApiResponse({
		status: 200,
		description: 'Aplicação saudável',
	})
	check() {
		return this.health.check([
			() => this.db.pingCheck('database'),
			// Redis Check
			async () => {
				try {
					const status = await this.redis.ping();
					return {
						redis: { status: status === 'PONG' ? 'up' : 'down' },
					};
				} catch (e) {
					return { redis: { status: 'down', message: e.message } };
				}
			},
			// Memória Detalhada para diagnóstico
			() => {
				const mem = process.memoryUsage();
				const toMB = (bytes: number) =>
					`${(bytes / 1024 / 1024).toFixed(2)} MB`;

				return {
					memory_detail: {
						status: 'up',
						heapUsed: toMB(mem.heapUsed),
						heapTotal: toMB(mem.heapTotal),
						external: toMB(mem.external), // Memória de módulos C++ (Sharp/Images)
						rss: toMB(mem.rss), // Total ocupado no sistema
						arrayBuffers: toMB(mem.arrayBuffers || 0),
					},
				};
			},
			() =>
				this.memory.checkHeap(
					'memory_heap',
					this.appConfig.healthHeapLimitBytes,
				),
			() =>
				this.disk.checkStorage('storage', {
					path: '/usr/src/app/data',
					thresholdPercent: this.appConfig.healthDiskThresholdPercent,
				}),
		]);
	}

	@Get('liveness')
	@HealthCheck()
	@ApiOperation({
		summary: 'Liveness probe',
		description: 'Verifica se a aplicação está rodando (para Kubernetes)',
	})
	@ApiResponse({
		status: 200,
		description: 'Aplicação está viva',
	})
	liveness() {
		return this.health.check([
			() => Promise.resolve({ liveness: { status: 'up' } }),
		]);
	}

	@Get('readiness')
	@HealthCheck()
	@ApiOperation({
		summary: 'Readiness probe',
		description:
			'Verifica se a aplicação está pronta para receber tráfego (para Kubernetes)',
	})
	@ApiResponse({
		status: 200,
		description: 'Aplicação está pronta',
	})
	@ApiResponse({
		status: 503,
		description: 'Aplicação não está pronta',
	})
	readiness() {
		return this.health.check([
			() => this.db.pingCheck('database'),
			() =>
				this.memory.checkHeap(
					'memory_heap',
					this.appConfig.healthHeapLimitBytes,
				),
		]);
	}

	@Get('startup')
	@HealthCheck()
	@ApiOperation({
		summary: 'Startup probe',
		description:
			'Verifica se a aplicação terminou de inicializar (para Kubernetes)',
	})
	@ApiResponse({
		status: 200,
		description: 'Aplicação inicializada',
	})
	startup() {
		return this.health.check([() => this.db.pingCheck('database')]);
	}
}

import { Module } from '@nestjs/common';
import { LoggerModule } from 'nestjs-pino';
import { AppConfigModule } from '../app-config/app-config.module';
import { AppConfigService } from '../app-config/app-config.service';
import { CustomLogger } from '../custom.logger';
import { LoggerRuleEngine } from './logger-rule-engine';

@Module({
	imports: [
		LoggerModule.forRootAsync({
			imports: [AppConfigModule],
			inject: [AppConfigService],
			useFactory: (config: AppConfigService) => {
				const isProduction = config.nodeEnv === 'production';

				return {
					pinoHttp: {
						level: isProduction ? 'info' : 'debug',

						transport: isProduction
							? undefined
							: {
									target: 'pino-pretty',
									options: {
										colorize: true,
										translateTime: 'SYS:HH:MM:ss.l',
										ignore: 'pid,hostname',
										singleLine: false,
										messageFormat: '[{context}] {msg}',
									},
								},

						serializers: {
							req: (req) => ({
								id: req.id,
								method: req.method,
								url: req.url,
								query: req.query,
								params: req.params,
								headers: {
									host: req.headers.host,
									'user-agent': req.headers['user-agent'],
									'content-type': req.headers['content-type'],
								},
								remoteAddress: req.remoteAddress,
								remotePort: req.remotePort,
							}),
							res: (res) => ({
								statusCode: res.statusCode,
							}),
							err: (err) => ({
								type: err.type,
								message: err.message,
								stack: err.stack,
								code: err.code,
								statusCode: err.statusCode,
							}),
						},

						customLogLevel: (req, res, err) => {
							if (res.statusCode >= 400 && res.statusCode < 500) {
								return 'warn';
							}
							if (res.statusCode >= 500 || err) {
								return 'error';
							}
							if (res.statusCode >= 300 && res.statusCode < 400) {
								return 'silent';
							}
							return 'info';
						},

						base: {
							app: 'gatuno-api',
							environment: config.nodeEnv,
							pid: process.pid,
						},

						timestamp: () =>
							`,"timestamp":"${new Date().toISOString()}"`,

						redact: {
							paths: [
								'req.headers.authorization',
								'req.headers.cookie',
								'req.body.password',
								'req.body.token',
								'res.headers["set-cookie"]',
							],
							remove: true,
						},

						autoLogging: {
							ignore: (req) => {
								return (
									req.url === '/health' ||
									req.url === '/health/liveness' ||
									req.url === '/health/readiness' ||
									req.url === '/metrics'
								);
							},
						},
					},
				};
			},
		}),
		AppConfigModule,
	],
	providers: [
		{
			provide: LoggerRuleEngine,
			useFactory: (config: AppConfigService) => {
				return new LoggerRuleEngine(config.LogLevel);
			},
			inject: [AppConfigService],
		},
		CustomLogger,
	],
	exports: [LoggerModule, CustomLogger],
})
export class LoggingModule {}

import { NestFactory } from '@nestjs/core';
import { NestExpressApplication } from '@nestjs/platform-express';
import cookieParser from 'cookie-parser';
import { AppConfigService } from './app-config/app-config.service';
import { AppModule } from './app.module';
import { configureBodyParser } from './config/body-parser.config';
import { configureCors } from './config/cors.config';
import { configureStaticAssets } from './config/static-assets.config';
import { configureSwagger } from './config/swagger.config';
import { configureValidationPipe } from './config/validation-pipe.config';

async function bootstrap() {
	const app = await NestFactory.create<NestExpressApplication>(AppModule);
	const configService = app.get(AppConfigService);

	configureBodyParser(app);
	configureValidationPipe(app);

	const allowedUrls = process.env.ALLOWED_URL?.split(',') || [
		configService.appUrl,
	];
	configureCors(app, allowedUrls);

	app.enableShutdownHooks();
	app.use(cookieParser());
	app.setGlobalPrefix('api');

	if (configService.nodeEnv === 'development') {
		configureSwagger(app);
	}

	configureStaticAssets(app);

	await app.listen(configService.port);
}

bootstrap();

import { Transform } from 'class-transformer';

