		Array.isArray(value) ? value : value ? [value] : [],
	);
}

import { Injectable, Logger } from '@nestjs/common';
import { Browser, BrowserContext, Page } from 'playwright';
import { chromium as playwrightChromium } from 'playwright-extra';
import StealthPlugin from 'puppeteer-extra-plugin-stealth';
import { PooledBrowser } from '../pool';
import {
	BrowserConfig,
	DEFAULT_BROWSER_CONFIG,
} from './browser-config.interface';
import { IBrowserFactory } from './browser.factory.interface';

/**
 * Extended Browser type with pool metadata
 */
interface PooledBrowserInstance extends Browser {
	__pooled?: boolean;
	__pooledId?: string;
	__pooledRef?: PooledBrowser;
}

/**
 * Factory for creating Playwright browser instances with stealth mode.
 * Uses playwright-extra with stealth plugin to avoid bot detection.
 * Supports browser pooling for resource efficiency.
 */
@Injectable()
export class PlaywrightBrowserFactory implements IBrowserFactory {
	private readonly logger = new Logger(PlaywrightBrowserFactory.name);
	private readonly config: Required<BrowserConfig>;
	private stealthInitialized = false;
	private browserPool?: import('../pool').BrowserPoolService;

	constructor(config?: Partial<BrowserConfig>) {
		this.config = { ...DEFAULT_BROWSER_CONFIG, ...config };
		this.initializeStealth();
	}

	/**
	 * Set the browser pool for resource management.
	 * Should be called by the scraping module during initialization.
	 */
	setBrowserPool(pool: import('../pool').BrowserPoolService): void {
		this.browserPool = pool;
		this.logger.log('Browser pool integration enabled');
	}

	private initializeStealth(): void {
		if (this.config.stealth && !this.stealthInitialized) {
			playwrightChromium.use(StealthPlugin());
			this.stealthInitialized = true;
			this.logger.debug('Stealth plugin initialized');
		}
	}

	async launch(): Promise<Browser> {
		// Try to use browser pool if available
		if (this.browserPool) {
			try {
				const pooledBrowser = await this.browserPool.acquire();
				this.logger.debug(
					`Acquired browser from pool: ${pooledBrowser.id}`,
				);
				// Tag the browser so we know it came from the pool
				const browser = pooledBrowser.browser as PooledBrowserInstance;
				browser.__pooled = true;
				browser.__pooledId = pooledBrowser.id;
				browser.__pooledRef = pooledBrowser;
				return browser;
			} catch (error) {
				this.logger.warn(
					`Failed to acquire from pool, falling back to direct launch: ${error.message}`,
				);
			}
		}

		// Fallback to direct launch
		return this.launchDirect();
	}

	/**
	 * Launch a browser directly (not from pool).
	 */
	private async launchDirect(): Promise<Browser> {
		const isDebug = this.config.debugMode;
		const wsEndpoint = this.config.wsEndpoint;

		this.logger.log(
			`🚀 Preparando navegador (Debug: ${isDebug}, Remote: ${!!wsEndpoint})`,
		);

		// Se estamos em modo debug ou temos um endpoint, tentamos conexão remota primeiro
		if (wsEndpoint) {
			try {
				this.logger.log(
					`Connecting to remote browser at ${wsEndpoint}...`,
				);
				const { chromium } = await import('playwright');
				return await chromium.connectOverCDP(wsEndpoint, {
					timeout: 15000,
				});
			} catch (error) {
				this.logger.error(
					`❌ Failed to connect to remote browser: ${error.message}`,
				);
				if (isDebug) {
					this.logger.warn(
						'⚠️  DEBUG MODE REQUIRES REMOTE BROWSER IN DOCKER!',
					);
				}
			}
		}

		// Fallback para local (apenas se não houver endpoint ou se falhar)
		this.logger.warn('Falling back to local browser instance...');
		const headless = isDebug ? false : this.config.headless;
		const slowMo = isDebug ? this.config.slowMo || 100 : this.config.slowMo;

		return await playwrightChromium.launch({
			headless,
			slowMo,
			args: [
				'--no-sandbox',
				'--disable-setuid-sandbox',
				'--disable-dev-shm-usage',
				'--disable-accelerated-2d-canvas',
				'--disable-gpu',
				'--disable-web-security',
				'--disable-features=IsolateOrigins,site-per-process',
				'--disable-blink-features=AutomationControlled',
				'--disable-infobars',
				'--window-size=1920,1080',
			],
		});
	}

	async createContext(browser: Browser): Promise<BrowserContext> {
		this.logger.debug('Creating browser context...');

		// Increment context count if this is a pooled browser
		const pooledBrowser = browser as PooledBrowserInstance;
		if (pooledBrowser.__pooledRef) {
			this.browserPool?.incrementContextCount(pooledBrowser.__pooledRef);
		}

		const context = await browser.newContext({
			userAgent: this.config.userAgent,
			viewport: this.config.viewport,
			locale: this.config.locale,
			timezoneId: this.config.timezoneId,
			acceptDownloads: true,
			ignoreHTTPSErrors: true,
			javaScriptEnabled: true,
			bypassCSP: true,
			permissions: ['geolocation'],
		});

		// Set default timeouts
		context.setDefaultNavigationTimeout(this.config.navigationTimeout);
		context.setDefaultTimeout(this.config.actionTimeout);

		this.logger.debug('Browser context created');
		return context;
	}

	async createPage(context: BrowserContext): Promise<Page> {
		this.logger.debug('Creating new page...');

		const page = await context.newPage();

		// Add extra stealth measures
		await this.applyStealthMeasures(page);

		this.logger.debug('Page created');
		return page;
	}

	/**
	 * Apply additional stealth measures to the page.
	 */
	private async applyStealthMeasures(page: Page): Promise<void> {
		try {
			await page.addInitScript(() => {
				// Override navigator.webdriver
				Object.defineProperty(navigator, 'webdriver', {
					get: () => undefined,
				});

				// Add fake plugins
				Object.defineProperty(navigator, 'plugins', {
					get: () => [
						{ name: 'Chrome PDF Plugin' },
						{ name: 'Chrome PDF Viewer' },
						{ name: 'Native Client' },
					],
				});

				// Override permissions
				const originalQuery = window.navigator.permissions.query;
				window.navigator.permissions.query = (
					parameters: PermissionDescriptor,
				) =>
					parameters.name === 'notifications'
						? Promise.resolve({
								state: Notification.permission,
							} as PermissionStatus)
						: originalQuery(parameters);

				// Add chrome runtime
				const win = window as unknown as Window & {
					chrome?: { runtime: Record<string, unknown> };
				};
				if (!win.chrome) {
					win.chrome = {
						runtime: {},
					};
				}
			});
		} catch (error) {
			this.logger.warn('Failed to apply stealth measures', error);
		}
	}

	/**
	 * Create a complete browser setup (browser + context + page).
	 * Convenience method for simple use cases.
	 */
	async createBrowserWithPage(): Promise<{
		browser: Browser;
		context: BrowserContext;
		page: Page;
	}> {
		const browser = await this.launch();
		const context = await this.createContext(browser);
		const page = await this.createPage(context);
		return { browser, context, page };
	}

	/**
	 * Release a browser back to the pool or close it if not pooled.
	 * MUST be called after using a browser to prevent resource leaks.
	 */
	async release(browser: Browser): Promise<void> {
		// Check if this is a pooled browser
		const pooledBrowser = browser as PooledBrowserInstance;
		if (pooledBrowser.__pooled && pooledBrowser.__pooledRef) {
			this.logger.debug(
				`Releasing browser ${pooledBrowser.__pooledRef.id} to pool`,
			);
			await this.browserPool?.release(pooledBrowser.__pooledRef);
		} else {
			// Not from pool, close directly
			this.logger.debug('Closing non-pooled browser');
			try {
				await browser.close();
			} catch (error) {
				this.logger.warn(`Error closing browser: ${error.message}`);
			}
		}
	}

	/**
	 * Shutdown the factory and release all resources.
	 * Called during application shutdown.
	 */
	shutdown(): Promise<void> {
		this.logger.log('Shutting down browser factory...');
		// The pool will handle its own shutdown via onModuleDestroy
		this.logger.log('Browser factory shutdown complete');
		return Promise.resolve();
	}

	getConfig(): Required<BrowserConfig> {
		return { ...this.config };
	}
}

import { Logger } from '@nestjs/common';
import Redis from 'ioredis';
import { IConcurrencyManager } from './concurrency-manager.interface';

/**
 * Redis-based distributed concurrency manager.
 * Suitable for multi-instance deployments where global limits are required.
 *
 * Uses Redis EVAL with Lua scripts for atomic check-and-increment operations.
 * Each slot has a TTL to prevent leaks in case of crashes.
 */
export class RedisConcurrencyManager implements IConcurrencyManager {
	private readonly logger = new Logger(RedisConcurrencyManager.name);
	private readonly keyPrefix = 'scraping:concurrency:';
	private readonly slotTtlMs: number;
	private readonly pollIntervalMs: number;
	private readonly maxWaitMs: number;

	constructor(
		private readonly redis: Redis,
		options?: {
			slotTtlMs?: number;
			pollIntervalMs?: number;
			maxWaitMs?: number;
		},
	) {
		// Default: slots expire after 20 minutes (enough for long scraping tasks)
		this.slotTtlMs = options?.slotTtlMs ?? 1_200_000;
		this.pollIntervalMs = options?.pollIntervalMs ?? 500;
		// Default: wait up to 1 hour for a slot
		this.maxWaitMs = options?.maxWaitMs ?? 3_600_000;
	}

	/**
	 * Lua script to atomically check current count and increment if below limit.
	 * Returns the new count if successful, or -1 if limit reached.
	 */
	private readonly acquireScript = `
		local key = KEYS[1]
		local limit = tonumber(ARGV[1])
		local ttl = tonumber(ARGV[2])
		local current = tonumber(redis.call('GET', key) or '0')
		if current < limit then
			local newVal = redis.call('INCR', key)
			redis.call('PEXPIRE', key, ttl)
			return newVal
		else
			return -1
		end
	`;

	async acquire(domain: string, limit?: number | null): Promise<void> {
		if (!limit || limit <= 0) return; // unlimited

		const key = this.keyPrefix + domain;
		const startTime = Date.now();

		while (true) {
			try {
				const result = await this.redis.eval(
					this.acquireScript,
					1,
					key,
					limit.toString(),
					this.slotTtlMs.toString(),
				);

				if (result !== -1) {
					// Successfully acquired slot
					this.logger.debug(
						`Acquired slot for domain ${domain} (current: ${result}/${limit})`,
					);
					return;
				}

				// Limit reached, check timeout
				if (Date.now() - startTime > this.maxWaitMs) {
					throw new Error(
						`Timeout waiting for concurrency slot for domain ${domain} (limit: ${limit})`,
					);
				}

				// Wait before retrying
				await this.sleep(this.pollIntervalMs);
			} catch (error) {
				this.logger.error(
					`Error acquiring slot for domain ${domain}`,
					error,
				);
				throw error;
			}
		}
	}

	async release(domain: string): Promise<void> {
		const key = this.keyPrefix + domain;
		try {
			const newVal = await this.redis.decr(key);
			// If counter goes below 0, reset to 0
			if (newVal < 0) {
				await this.redis.set(key, '0');
			}
			this.logger.debug(
				`Released slot for domain ${domain} (remaining: ${Math.max(0, newVal)})`,
			);
		} catch (error) {
			this.logger.error(
				`Error releasing slot for domain ${domain}`,
				error,
			);
			// Don't throw - releasing should be best-effort
		}
	}

	private sleep(ms: number): Promise<void> {
		return new Promise((resolve) => setTimeout(resolve, ms));
	}

	/**
	 * Optional: Clean up all locks for a domain (useful for testing or manual intervention)
	 */
	async clearDomain(domain: string): Promise<void> {
		const key = this.keyPrefix + domain;
		await this.redis.del(key);
		this.logger.debug(`Cleared concurrency counter for domain ${domain}`);
	}

	/**
	 * Optional: Get current slot usage for a domain
	 */
	async getCurrentCount(domain: string): Promise<number> {
		const key = this.keyPrefix + domain;
		const val = await this.redis.get(key);
		return Number.parseInt(val || '0', 10);
	}
}

import * as fs from 'node:fs/promises';
import * as os from 'node:os';
import * as path from 'node:path';
import { Logger } from '@nestjs/common';
import { Page, Response } from 'playwright';

/**
 * Configuration for URL filtering.
 */
export interface UrlFilterConfig {
	/**
	 * Terms that will cause a URL to be ignored (blacklist).
	 */
	blacklistTerms: string[];

	/**
	 * Terms that a URL must contain to be accepted (whitelist).
	 * If empty, all URLs are accepted (unless blacklisted).
	 */
	whitelistTerms: string[];
}

/**
 * Configuration for memory limits.
 */
export interface MemoryLimits {
	/**
	 * Maximum cache size in bytes.
	 * @default 100 * 1024 * 1024 (100MB)
	 */
	maxCacheSize: number;

	/**
	 * Threshold in bytes above which images are streamed to temp files.
	 * @default 5 * 1024 * 1024 (5MB)
	 */
	largeImageThreshold: number;
}

/**
 * Interface for image compression during interception.
 */
export interface ImageCompressor {
	compress(buffer: Buffer, extension?: string): Promise<Buffer>;
	getOutputExtension(originalExtension: string): string;
}

/**
 * Cached image data.
 */
export interface CachedImage {
	url: string;
	data: Buffer | null; // null if offloaded to temp file
	contentType: string;
	/** Whether the image has been compressed */
	compressed: boolean;
	/** Final extension after compression */
	extension: string;
	/** Temporary file path if offloaded */
	tempFilePath?: string;
	/** Last access time for LRU eviction */
	lastAccess: number;
}

const DEFAULT_MEMORY_LIMITS: MemoryLimits = {
	maxCacheSize: 100 * 1024 * 1024, // 100MB
	largeImageThreshold: 5 * 1024 * 1024, // 5MB
};

/**
 * Helper for intercepting network traffic and caching images.
 * This is more efficient than fetching images separately after the page loads.
 * Optionally compresses images immediately upon caching for memory efficiency.
 * Implements memory management via LRU eviction and temp file offloading.
 */
export class NetworkInterceptor {
	readonly logger = new Logger(NetworkInterceptor.name);
	private readonly imageCache = new Map<string, CachedImage>();
	isIntercepting = false;
	/** Active compression promises; entries are deleted on completion so the set stays small. */
	private readonly compressionQueue = new Set<Promise<void>>();
	private currentCacheSize = 0;
	/** Sum of raw body bytes currently waiting for a compression slot (not yet in cache). */
	private inFlightBytes = 0;
	private tempFiles: Set<string> = new Set();
	private readonly memoryLimits: MemoryLimits;

	/** Named handler stored so it can be removed via page.off() */
	private readonly responseHandler = (response: Response): void => {
		void this.handleResponse(response);
	};

	/** Maximum number of concurrent image compressions */
	private readonly compressionConcurrency: number;
	private activeCompressions = 0;
	private readonly compressionWaiters: Array<() => void> = [];

	/** Set to true by clearCache() to prevent stale compressions from re-populating the cache */
	private _cleared = false;

	constructor(
		private readonly page: Page,
		private readonly filterConfig: UrlFilterConfig = {
			blacklistTerms: [],
			whitelistTerms: [],
		},
		readonly compressor?: ImageCompressor,
		memoryLimits?: Partial<MemoryLimits>,
		compressionConcurrency?: number,
	) {
		this.memoryLimits = { ...DEFAULT_MEMORY_LIMITS, ...memoryLimits };
		this.compressionConcurrency =
			compressionConcurrency ??
			Number(process.env.SCRAPING_COMPRESSION_CONCURRENCY ?? '4');
	}

	/**
	 * Check if a URL should be accepted based on filter configuration.
	 */
	shouldAcceptUrl(url: string): boolean {
		const lowerUrl = url.toLowerCase();

		// Check blacklist first
		if (this.filterConfig.blacklistTerms.length > 0) {
			for (const term of this.filterConfig.blacklistTerms) {
				if (lowerUrl.includes(term.toLowerCase())) {
					return false;
				}
			}
		}

		// Check whitelist (if configured)
		if (this.filterConfig.whitelistTerms.length > 0) {
			for (const term of this.filterConfig.whitelistTerms) {
				if (lowerUrl.includes(term.toLowerCase())) {
					return true;
				}
			}
			// Whitelist is configured but URL doesn't match any term
			return false;
		}

		// No whitelist configured, accept all non-blacklisted URLs
		return true;
	}

	/**
	 * Extract extension from content-type or URL.
	 */
	private getExtensionFromResponse(url: string, contentType: string): string {
		// Try content-type first
		const ct = contentType.toLowerCase();
		if (ct.includes('png')) return '.png';
		if (ct.includes('webp')) return '.webp';
		if (ct.includes('gif')) return '.gif';
		if (ct.includes('svg')) return '.svg';
		if (ct.includes('jpeg') || ct.includes('jpg')) return '.jpg';

		// Fallback to URL
		const urlPath = new URL(url).pathname.toLowerCase();
		if (urlPath.includes('.png')) return '.png';
		if (urlPath.includes('.webp')) return '.webp';
		if (urlPath.includes('.gif')) return '.gif';
		if (urlPath.includes('.svg')) return '.svg';

		return '.jpg';
	}

	/**
	 * Handle a network response and cache image data.
	 * Optionally compresses the image immediately for memory efficiency.
	 */
	private async handleResponse(response: Response): Promise<void> {
		// Ignore responses that arrive after interception was stopped
		if (!this.isIntercepting) return;

		try {
			const request = response.request();
			const resourceType = request.resourceType();

			// Only intercept images
			if (resourceType !== 'image') return;

			// Only cache successful responses
			if (!response.ok()) return;

			const url = response.url();

			// Apply URL filters
			if (!this.shouldAcceptUrl(url)) {
				this.logger.debug(`URL filtered out: ${url}`);
				return;
			}

			// Get response body
			const body = await response.body();

			// Skip empty responses (e.g. 204 no-content, ad trackers)
			if (body.length === 0) {
				this.logger.debug(`Skipping empty-body response: ${url}`);
				return;
			}

			const contentType =
				response.headers()['content-type'] || 'image/jpeg';
			const originalExtension = this.getExtensionFromResponse(
				url,
				contentType,
			);
			const originalSize = body.length;

			// Check if we need to offload to temp file
			if (originalSize > this.memoryLimits.largeImageThreshold) {
				await this.cacheToTempFile(
					url,
					body,
					contentType,
					originalExtension,
					originalSize,
				);
				return;
			}

			// Ensure cache doesn't exceed limit
			await this.ensureCacheSpace(originalSize);

			// If compressor is available, compress immediately (non-blocking, concurrency-limited)
			if (this.compressor) {
				// Guard: count in-flight bytes (queued but not yet in cache) against the
				// same limit as the cache itself. Without this, every image response
				// simultaneously adds its raw body to async closures with no cap.
				if (
					this.currentCacheSize + this.inFlightBytes + originalSize >
					this.memoryLimits.maxCacheSize
				) {
					this.logger.warn(
						`Memory limit reached (cache=${this.currentCacheSize}, in-flight=${this.inFlightBytes}), skipping: ${url}`,
					);
					return;
				}
				this.inFlightBytes += originalSize;
				const compressionTask = this.compressAndCache(
					url,
					body,
					contentType,
					originalExtension,
					originalSize,
				);
				this.compressionQueue.add(compressionTask);
				// Self-cleaning: remove from the set once settled so the set never grows unboundedly.
				void compressionTask.finally(() =>
					this.compressionQueue.delete(compressionTask),
				);
			} else {
				// Cache without compression
				this.addToCache(url, {
					url,
					data: body,
					contentType,
					compressed: false,
					extension: originalExtension,
					lastAccess: Date.now(),
				});
				this.logger.debug(
					`Cached image: ${url} (${originalSize} bytes)`,
				);
			}
		} catch (error) {
			// Silently ignore errors (response might be unavailable)
		}
	}

	/**
	 * Ensure there's enough space in the cache by evicting LRU entries.
	 */
	private ensureCacheSpace(requiredBytes: number): Promise<void> {
		while (
			this.currentCacheSize + requiredBytes >
			this.memoryLimits.maxCacheSize
		) {
			const evicted = this.evictLRU();
			if (!evicted) {
				this.logger.warn(
					'Failed to evict LRU entry, cache may exceed limit',
				);
				break;
			}
		}
		return Promise.resolve();
	}

	/**
	 * Evict the least recently used cache entry.
	 */
	private evictLRU(): boolean {
		let oldestUrl: string | null = null;
		let oldestTime = Number.MAX_SAFE_INTEGER;

		for (const [url, cached] of this.imageCache.entries()) {
			if (cached.lastAccess < oldestTime) {
				oldestTime = cached.lastAccess;
				oldestUrl = url;
			}
		}

		if (oldestUrl) {
			const evicted = this.imageCache.get(oldestUrl);
			this.imageCache.delete(oldestUrl);
			if (evicted?.data) {
				this.currentCacheSize -= evicted.data.length;
			}
			this.logger.debug(
				`Evicted LRU image: ${oldestUrl} (${evicted?.data?.length || 0} bytes)`,
			);
			return true;
		}

		return false;
	}

	/**
	 * Add an image to the cache and update size tracking.
	 */
	private addToCache(url: string, cached: CachedImage): void {
		// Do not re-populate after clearCache() has been called
		if (this._cleared) return;

		// Remove old entry if exists
		const old = this.imageCache.get(url);
		if (old?.data) {
			this.currentCacheSize -= old.data.length;
		}

		// Add new entry
		this.imageCache.set(url, cached);
		if (cached.data) {
			this.currentCacheSize += cached.data.length;
		}
	}

	/**
	 * Cache a large image to a temporary file.
	 */
	private async cacheToTempFile(
		url: string,
		body: Buffer,
		contentType: string,
		extension: string,
		size: number,
	): Promise<void> {
		try {
			const tempDir = await fs.mkdtemp(
				path.join(os.tmpdir(), 'gatuno-cache-'),
			);
			const tempFilePath = path.join(
				tempDir,
				`image-${Date.now()}${extension}`,
			);
			await fs.writeFile(tempFilePath, body);
			this.tempFiles.add(tempFilePath);

			this.imageCache.set(url, {
				url,
				data: null,
				contentType,
				compressed: false,
				extension,
				tempFilePath,
				lastAccess: Date.now(),
			});

			this.logger.debug(
				`Large image offloaded to temp file: ${url} (${size} bytes) -> ${tempFilePath}`,
			);
		} catch (error) {
			this.logger.error(
				`Failed to offload to temp file: ${error.message}`,
			);
		}
	}

	/**
	 * Acquire a compression slot (blocks if concurrency limit is reached).
	 */
	private waitForCompressionSlot(): Promise<void> {
		if (this.activeCompressions < this.compressionConcurrency) {
			this.activeCompressions++;
			return Promise.resolve();
		}
		return new Promise<void>((resolve) => {
			this.compressionWaiters.push(resolve);
		}).then(() => {
			this.activeCompressions++;
		});
	}

	/**
	 * Release a compression slot and wake up the next waiter if any.
	 */
	private releaseCompressionSlot(): void {
		this.activeCompressions = Math.max(0, this.activeCompressions - 1);
		const next = this.compressionWaiters.shift();
		if (next) next();
	}

	/**
	 * Compress and cache an image asynchronously.
	 * Respects the concurrency semaphore and the _cleared flag.
	 */
	private async compressAndCache(
		url: string,
		body: Buffer,
		contentType: string,
		originalExtension: string,
		originalSize: number,
	): Promise<void> {
		await this.waitForCompressionSlot();
		// Slot acquired: the body buffer is now being actively processed, so
		// remove it from the in-flight accounting (it will enter the cache next).
		this.inFlightBytes = Math.max(0, this.inFlightBytes - originalSize);
		try {
			// Session was cleared while we were waiting — discard work
			if (this._cleared) return;

			const compressedData = await this.compressor?.compress(
				body,
				originalExtension,
			);
			const outputExtension =
				this.compressor?.getOutputExtension(originalExtension);

			if (!compressedData || !outputExtension) {
				throw new Error('Compression failed to produce valid data');
			}

			if (this._cleared) return;

			const compressedSize = compressedData.length;
			const savings = ((1 - compressedSize / originalSize) * 100).toFixed(
				1,
			);

			// Ensure cache space before adding
			await this.ensureCacheSpace(compressedSize);

			this.addToCache(url, {
				url,
				data: compressedData,
				contentType: 'image/webp', // After compression
				compressed: true,
				extension: outputExtension,
				lastAccess: Date.now(),
			});

			this.logger.debug(
				`Cached & compressed: ${url} (${originalSize} → ${compressedSize} bytes, -${savings}%)`,
			);
		} catch (error) {
			if (this._cleared) return;

			// Fallback: cache original on compression error
			await this.ensureCacheSpace(originalSize);
			this.addToCache(url, {
				url,
				data: body,
				contentType,
				compressed: false,
				extension: originalExtension,
				lastAccess: Date.now(),
			});
			this.logger.warn(`Compression failed for ${url}, caching original`);
		} finally {
			this.releaseCompressionSlot();
			// Ensure inFlightBytes never drifts negative on unexpected paths.
			this.inFlightBytes = Math.max(0, this.inFlightBytes);
		}
	}

	/**
	 * Wait for all pending compressions to complete.
	 * Call this before accessing the cache to ensure all images are ready.
	 */
	async waitForCompressions(): Promise<void> {
		if (this.compressionQueue.size > 0) {
			this.logger.debug(
				`Waiting for ${this.compressionQueue.size} compressions...`,
			);
			await Promise.allSettled([...this.compressionQueue]);
			this.logger.debug('All compressions complete');
		}
	}

	/**
	 * Start intercepting network traffic.
	 * Call this BEFORE navigating to the page.
	 */
	startInterception(): Promise<void> {
		if (this.isIntercepting) return Promise.resolve();

		this.page.on('response', this.responseHandler);
		this.isIntercepting = true;
		this.logger.debug('Network interception started');
		return Promise.resolve();
	}

	/**
	 * Stop intercepting (cleanup).
	 * Removes the named response listener so no further responses are processed.
	 */
	stopInterception(): void {
		if (!this.isIntercepting) return;
		this.isIntercepting = false;
		this.page.off('response', this.responseHandler);
		this.logger.debug(
			`Network interception stopped. Cached ${this.imageCache.size} images`,
		);
	}

	/**
	 * Get a cached image by URL.
	 */
	getCachedImage(url: string): CachedImage | undefined {
		// Try exact match first
		const cached = this.imageCache.get(url);
		if (cached) return cached;

		// Try matching without query parameters
		const urlWithoutQuery = url.split('?')[0];
		for (const [cachedUrl, image] of this.imageCache) {
			if (cachedUrl.split('?')[0] === urlWithoutQuery) {
				return image;
			}
		}

		return undefined;
	}

	/**
	 * Get a cached image as Buffer (preferred - more efficient).
	 * Loads from temp file if image was offloaded.
	 */
	async getCachedImageAsBuffer(url: string): Promise<Buffer | null> {
		const cached = this.getCachedImage(url);
		if (!cached) return null;

		// Update last access time for LRU
		cached.lastAccess = Date.now();

		// If has data in memory, return it
		if (cached.data) {
			return cached.data;
		}

		// Load from temp file
		if (cached.tempFilePath) {
			try {
				const fileData = await fs.readFile(cached.tempFilePath);
				return fileData;
			} catch (error) {
				this.logger.error(
					`Failed to read temp file ${cached.tempFilePath}: ${error.message}`,
				);
				return null;
			}
		}

		return null;
	}

	/**
	 * Get a cached image as base64.
	 * @deprecated Use getCachedImageAsBuffer for better performance
	 */
	async getCachedImageAsBase64(url: string): Promise<string | null> {
		const buffer = await this.getCachedImageAsBuffer(url);
		if (!buffer) return null;
		return buffer.toString('base64');
	}

	/**
	 * Check if an image is in the cache.
	 */
	hasImage(url: string): boolean {
		return this.getCachedImage(url) !== undefined;
	}

	/**
	 * Check if an image was compressed.
	 */
	isCompressed(url: string): boolean {
		const cached = this.getCachedImage(url);
		return cached?.compressed ?? false;
	}

	/**
	 * Get all cached image URLs.
	 */
	getCachedUrls(): string[] {
		return Array.from(this.imageCache.keys());
	}

	/**
	 * Get cache statistics.
	 */
	getStats(): {
		count: number;
		totalBytes: number;
		compressedCount: number;
		tempFileCount: number;
	} {
		let totalBytes = 0;
		let compressedCount = 0;
		let tempFileCount = 0;
		for (const image of this.imageCache.values()) {
			if (image.data) {
				totalBytes += image.data.length;
			}
			if (image.compressed) compressedCount++;
			if (image.tempFilePath) tempFileCount++;
		}
		return {
			count: this.imageCache.size,
			totalBytes,
			compressedCount,
			tempFileCount,
		};
	}

	/**
	 * Clear the cache and delete temp files.
	 * Awaits all in-flight compressions before clearing to prevent stale re-population.
	 */
	async clearCache(): Promise<void> {
		// Signal that no new entries should be added
		this._cleared = true;

		// Drain all in-flight compressions before wiping the cache
		if (this.compressionQueue.size > 0) {
			this.logger.debug(
				`clearCache: awaiting ${this.compressionQueue.size} in-flight compressions...`,
			);
			await Promise.allSettled([...this.compressionQueue]);
		}
		this.compressionQueue.clear();
		this.compressionWaiters.length = 0;
		this.activeCompressions = 0;
		this.inFlightBytes = 0;

		// Delete temp files
		for (const tempFilePath of this.tempFiles) {
			try {
				await fs.unlink(tempFilePath);
				this.logger.debug(`Deleted temp file: ${tempFilePath}`);
			} catch (error) {
				this.logger.warn(
					`Failed to delete temp file ${tempFilePath}: ${error.message}`,
				);
			}
		}
		this.tempFiles.clear();

		// Clear cache
		this.imageCache.clear();
		this.currentCacheSize = 0;
	}

	/**
	 * Get file extension for a cached image.
	 * Returns the final extension (after compression if applicable).
	 */
	getExtension(url: string): string {
		const cached = this.getCachedImage(url);
		if (cached) {
			return cached.extension;
		}

		// Fallback to URL extension
		const urlPath = new URL(url).pathname.toLowerCase();
		if (urlPath.includes('.png')) return '.png';
		if (urlPath.includes('.webp')) return '.webp';
		if (urlPath.includes('.gif')) return '.gif';
		if (urlPath.includes('.svg')) return '.svg';

		return '.jpg';
	}
}

import {
	Injectable,
	Logger,
	OnModuleDestroy,
	OnModuleInit,
} from '@nestjs/common';
import { Browser } from 'playwright';
import { chromium as playwrightChromium } from 'playwright-extra';
import { BrowserConfig } from '../browser/browser-config.interface';
import {
	BrowserPoolConfig,
	DEFAULT_BROWSER_POOL_CONFIG,
	PooledBrowser,
} from './browser-pool-config.interface';

@Injectable()
export class BrowserPoolService implements OnModuleInit, OnModuleDestroy {
	private readonly logger = new Logger(BrowserPoolService.name);
	private readonly pool: Map<string, PooledBrowser> = new Map();
	private readonly waitQueue: Array<{
		resolve: (browser: PooledBrowser) => void;
		reject: (error: Error) => void;
		timestamp: number;
	}> = [];
	private isShuttingDown = false;
	private poolConfig: BrowserPoolConfig;
	private browserConfig?: Required<BrowserConfig>;
	private healthCheckInterval?: ReturnType<typeof setInterval>;

	constructor(
		poolConfig?: Partial<BrowserPoolConfig>,
		browserConfig?: Required<BrowserConfig>,
	) {
		this.poolConfig = { ...DEFAULT_BROWSER_POOL_CONFIG, ...poolConfig };
		if (browserConfig) {
			this.browserConfig = browserConfig;
		}
	}

	async onModuleInit() {
		if (!this.poolConfig.enabled) {
			this.logger.log('Browser pool is disabled');
			return;
		}

		this.logger.log(
			`🏊 Initializing browser pool (size: ${this.poolConfig.poolSize})`,
		);

		const warmupPromises: Promise<PooledBrowser | undefined>[] = [];
		for (let i = 0; i < this.poolConfig.poolSize; i++) {
			warmupPromises.push(
				this.createBrowser().catch((error) => {
					this.logger.error(
						`Failed to create browser ${i} during warmup: ${error.message}`,
					);
					return undefined;
				}),
			);
		}

		await Promise.allSettled(warmupPromises);
		this.logger.log(
			`✅ Browser pool initialized with ${this.pool.size} browsers`,
		);

		this.healthCheckInterval = setInterval(
			() => this.checkStuckBrowsers(),
			60_000,
		);
	}

	async onModuleDestroy() {
		await this.shutdown();
	}

	async acquire(): Promise<PooledBrowser> {
		if (this.isShuttingDown) {
			throw new Error('Browser pool is shutting down');
		}

		if (!this.poolConfig.enabled) {
			throw new Error(
				'Browser pool is disabled. Use factory.launch() directly.',
			);
		}

		const available = this.findAvailableBrowser();
		if (available) {
			return this.markBrowserInUse(available);
		}

		if (this.pool.size < this.poolConfig.poolSize) {
			const browser = await this.createBrowser();
			return this.markBrowserInUse(browser);
		}

		return this.waitForBrowser();
	}

	release(pooledBrowser: PooledBrowser): Promise<void> {
		const browser = this.pool.get(pooledBrowser.id);
		if (!browser) {
			this.logger.warn(
				`Attempted to release unknown browser: ${pooledBrowser.id}`,
			);
			return Promise.resolve();
		}

		browser.activeContexts = Math.max(0, browser.activeContexts - 1);
		browser.lastUsedAt = new Date();

		this.logger.debug(
			`Released browser ${browser.id} (active contexts: ${browser.activeContexts})`,
		);

		if (
			!browser.isPendingRestart &&
			browser.totalContextsCreated >=
				this.poolConfig.maxContextsBeforeRestart
		) {
			browser.isPendingRestart = true;
			browser.pendingRestartSince = new Date();
			this.logger.log(
				`Browser ${browser.id} reached context limit, draining before restart...`,
			);
		}

		if (
			browser.isPendingRestart &&
			browser.activeContexts === 0 &&
			!browser.isRestarting
		) {
			void this.restartBrowser(browser.id);
			return Promise.resolve();
		}

		this.processWaitQueue();
		return Promise.resolve();
	}

	incrementContextCount(pooledBrowser: PooledBrowser): void {
		const browser = this.pool.get(pooledBrowser.id);
		if (browser) {
			browser.totalContextsCreated++;
			this.logger.debug(
				`Browser ${browser.id} contexts: ${browser.totalContextsCreated}`,
			);
		}
	}

	getStats() {
		const browsers = Array.from(this.pool.values());
		return {
			totalBrowsers: browsers.length,
			activeBrowsers: browsers.filter((b) => b.activeContexts > 0).length,
			idleBrowsers: browsers.filter(
				(b) => b.activeContexts === 0 && !b.isPendingRestart,
			).length,
			unhealthyBrowsers: browsers.filter((b) => !b.isHealthy).length,
			pendingRestartBrowsers: browsers.filter((b) => b.isPendingRestart)
				.length,
			restartingBrowsers: browsers.filter((b) => b.isRestarting).length,
			totalActiveContexts: browsers.reduce(
				(sum, b) => sum + b.activeContexts,
				0,
			),
			totalContextsCreated: browsers.reduce(
				(sum, b) => sum + b.totalContextsCreated,
				0,
			),
			waitQueueLength: this.waitQueue.length,
			poolConfig: this.poolConfig,
		};
	}

	private checkStuckBrowsers(): void {
		const now = Date.now();
		const stuckThresholdMs = this.poolConfig.acquireTimeout * 2;

		for (const browser of this.pool.values()) {
			if (
				browser.isPendingRestart &&
				!browser.isRestarting &&
				browser.pendingRestartSince &&
				now - browser.pendingRestartSince.getTime() > stuckThresholdMs
			) {
				const stuckSeconds = Math.round(
					(now - browser.pendingRestartSince.getTime()) / 1000,
				);
				this.logger.warn(
					`Browser ${browser.id} stuck in pendingRestart for ${stuckSeconds}s (leaked session?), forcing restart`,
				);
				void this.restartBrowser(browser.id);
			}
		}
	}

	async shutdown(): Promise<void> {
		if (this.isShuttingDown) {
			return;
		}

		this.isShuttingDown = true;
		this.logger.log('🛑 Shutting down browser pool...');

		if (this.healthCheckInterval) {
			clearInterval(this.healthCheckInterval);
		}

		for (const waiter of this.waitQueue) {
			waiter.reject(new Error('Browser pool shutting down'));
		}
		this.waitQueue.length = 0;

		const closePromises: Promise<void>[] = [];
		for (const [id, pooledBrowser] of this.pool.entries()) {
			closePromises.push(
				this.closeBrowser(
					id,
					pooledBrowser.browser,
					pooledBrowser.disconnectedHandler,
				).catch((error) => {
					this.logger.error(
						`Failed to close browser ${id}: ${error.message}`,
					);
				}),
			);
		}

		await Promise.allSettled(closePromises);
		this.pool.clear();
		this.logger.log('✅ Browser pool shutdown complete');
	}

	private async createBrowser(): Promise<PooledBrowser> {
		const id = `browser-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

		this.logger.debug(`Creating browser ${id}...`);

		let browser: Browser;
		const wsEndpoint = this.browserConfig?.wsEndpoint;

		if (wsEndpoint) {
			try {
				const { chromium } = await import('playwright');
				browser = await chromium.connectOverCDP(wsEndpoint, {
					timeout: 15000,
				});
				this.logger.debug(`Browser ${id} connected to remote endpoint`);
			} catch (error) {
				this.logger.warn(
					`Failed to connect to remote browser, launching locally: ${error.message}`,
				);
				browser = await this.launchLocalBrowser();
			}
		} else {
			browser = await this.launchLocalBrowser();
		}

		const onDisconnected = (): void => {
			this.logger.warn(`Browser ${id} disconnected unexpectedly`);
			this.handleBrowserCrash(id);
		};
		browser.on('disconnected', onDisconnected);

		const pooledBrowser: PooledBrowser = {
			id,
			browser,
			activeContexts: 0,
			totalContextsCreated: 0,
			createdAt: new Date(),
			lastUsedAt: new Date(),
			isHealthy: true,
			isPendingRestart: false,
			isRestarting: false,
			disconnectedHandler: onDisconnected,
		};

		this.pool.set(id, pooledBrowser);
		this.logger.debug(`✅ Browser ${id} created`);

		return pooledBrowser;
	}

	private async launchLocalBrowser(): Promise<Browser> {
		const headless = this.browserConfig?.headless ?? true;
		const slowMo = this.browserConfig?.slowMo ?? 0;

		return await playwrightChromium.launch({
			headless,
			slowMo,
			args: [
				'--no-sandbox',
				'--disable-setuid-sandbox',
				'--disable-dev-shm-usage',
				'--disable-accelerated-2d-canvas',
				'--disable-gpu',
				'--disable-web-security',
				'--disable-features=IsolateOrigins,site-per-process',
				'--disable-blink-features=AutomationControlled',
				'--disable-infobars',
				'--window-size=1920,1080',
			],
		});
	}

	private findAvailableBrowser(): PooledBrowser | null {
		for (const browser of this.pool.values()) {
			if (
				browser.isHealthy &&
				!browser.isPendingRestart &&
				browser.activeContexts < this.poolConfig.maxContextsPerBrowser
			) {
				return browser;
			}
		}
		return null;
	}

	private markBrowserInUse(pooledBrowser: PooledBrowser): PooledBrowser {
		pooledBrowser.activeContexts++;
		pooledBrowser.lastUsedAt = new Date();
		this.logger.debug(
			`Acquired browser ${pooledBrowser.id} (active contexts: ${pooledBrowser.activeContexts})`,
		);
		return pooledBrowser;
	}

	private async waitForBrowser(): Promise<PooledBrowser> {
		return new Promise((resolve, reject) => {
			const timeout = setTimeout(() => {
				const index = this.waitQueue.findIndex(
					(w) => w.resolve === resolve,
				);
				if (index !== -1) {
					this.waitQueue.splice(index, 1);
				}
				reject(
					new Error(
						`Timeout waiting for browser (${this.poolConfig.acquireTimeout}ms)`,
					),
				);
			}, this.poolConfig.acquireTimeout);

			this.waitQueue.push({
				resolve: (browser) => {
					clearTimeout(timeout);
					resolve(browser);
				},
				reject: (error) => {
					clearTimeout(timeout);
					reject(error);
				},
				timestamp: Date.now(),
			});

			this.logger.debug(
				`Added to wait queue (position: ${this.waitQueue.length})`,
			);
		});
	}

	private processWaitQueue(): void {
		if (this.waitQueue.length === 0) {
			return;
		}

		const available = this.findAvailableBrowser();
		if (!available) {
			return;
		}

		const waiter = this.waitQueue.shift();
		if (waiter) {
			this.logger.debug('Processing wait queue request');
			waiter.resolve(this.markBrowserInUse(available));
			if (this.waitQueue.length > 0) {
				setImmediate(() => this.processWaitQueue());
			}
		}
	}

	private async handleBrowserCrash(id: string): Promise<void> {
		const browser = this.pool.get(id);
		if (!browser) {
			return;
		}

		browser.isHealthy = false;
		this.logger.error(`Browser ${id} crashed, restarting...`);

		await this.restartBrowser(id);
	}

	private async restartBrowser(id: string): Promise<void> {
		const oldBrowser = this.pool.get(id);
		if (!oldBrowser) {
			return;
		}

		if (oldBrowser.isRestarting) {
			this.logger.debug(
				`Browser ${id} already restarting, skipping duplicate call`,
			);
			return;
		}
		oldBrowser.isRestarting = true;

		this.pool.delete(id);
		await this.closeBrowser(
			id,
			oldBrowser.browser,
			oldBrowser.disconnectedHandler,
		);

		if (this.pool.size >= this.poolConfig.poolSize) {
			this.logger.warn(
				`Pool already at capacity (${this.pool.size}/${this.poolConfig.poolSize}), skipping replacement for ${id}`,
			);
			this.processWaitQueue();
			return;
		}

		try {
			const newBrowser = await this.createBrowser();
			this.logger.log(`✅ Browser ${id} replaced with ${newBrowser.id}`);
			this.processWaitQueue();
		} catch (error) {
			this.logger.error(
				`Failed to restart browser ${id}: ${error.message}`,
			);
		}
	}

	private async closeBrowser(
		id: string,
		browser: Browser,
		disconnectedHandler?: () => void,
	): Promise<void> {
		try {
			this.logger.debug(`Closing browser ${id}...`);
			if (disconnectedHandler) {
				browser.off('disconnected', disconnectedHandler);
			}
			await browser.close();
			this.logger.debug(`Browser ${id} closed`);
		} catch (error) {
			this.logger.error(`Error closing browser ${id}: ${error.message}`);
		}
	}
}

import { Logger } from '@nestjs/common';
import { Browser, BrowserContext, Page } from 'playwright';
import { PlaywrightBrowserFactory } from '../browser';
import { IConcurrencyManager } from '../concurrency';
import { WebsiteConfigDto } from '../dto/website-config.dto';
import {
	ImageCompressor,
	NetworkInterceptor,
	StorageConfig,
	StorageInjector,
} from '../helpers';
import { ScrapingContext, ScrapingTask } from './scraping-context.interface';

export class ScrapingSessionRunner {
	private readonly logger = new Logger(ScrapingSessionRunner.name);

	constructor(
		private readonly browserFactory: PlaywrightBrowserFactory,
		private readonly concurrencyManager: IConcurrencyManager,
		private readonly imageCompressor?: ImageCompressor,
	) {}

	async run<T>(
		url: string,
		config: WebsiteConfigDto,
		task: ScrapingTask<T>,
	): Promise<T> {
		const domain = new URL(url).hostname;
		const { concurrencyLimit } = config;

		await this.concurrencyManager.acquire(domain, concurrencyLimit);

		let browser: Browser | null = null;
		let context: BrowserContext | null = null;
		let page: Page | null = null;
		let networkInterceptor: NetworkInterceptor | undefined;

		try {
			browser = await this.browserFactory.launch();
			context = await this.browserFactory.createContext(browser);
			page = await this.browserFactory.createPage(context);

			const storageInjector = this.createStorageInjector(config);

			// Setup Helpers
			if (storageInjector) {
				await storageInjector.injectCookies(context, domain);
				await storageInjector.addInitScriptForStorage(page);
			}

			if (config.useNetworkInterception && !config.useScreenshotMode) {
				networkInterceptor = new NetworkInterceptor(
					page,
					{
						blacklistTerms: config.blacklistTerms,
						whitelistTerms: config.whitelistTerms,
					},
					this.imageCompressor,
				);
				await networkInterceptor.startInterception();
			}

			// Navigation
			await page.goto(url, {
				waitUntil: 'domcontentloaded',
				timeout: 60000,
			});

			// Post-load storage injection
			if (storageInjector) {
				const hasLocalStorage =
					config.localStorage &&
					Object.keys(config.localStorage).length > 0;

				if (hasLocalStorage) {
					await storageInjector.injectLocalStorage(page);
					await storageInjector.injectSessionStorage(page);
					await page.reload({ waitUntil: 'domcontentloaded' });
					await page
						.waitForLoadState('networkidle', { timeout: 10000 })
						.catch(() => undefined);
				} else {
					const reloaded =
						await storageInjector.injectStorageAndReload(page);
					if (reloaded) {
						await page
							.waitForLoadState('networkidle', { timeout: 15000 })
							.catch(() => undefined);
					}
				}
			}

			// Wait for hydration/rendering
			await page
				.waitForFunction(() => document.title.length > 0, {
					timeout: 10000,
				})
				.catch(() => undefined);

			// Execute scraping task
			const scrapingContext: ScrapingContext = {
				page,
				context,
				config,
				networkInterceptor,
				storageInjector,
			};

			return await task(scrapingContext);
		} finally {
			// Cleanup order:
			// 1. Stop interception immediately (no new responses accepted)
			// 2. Drain in-flight compressions while page is still alive
			// 3. Close page
			// 4. Clear cache (safe: _cleared flag set, compressions already drained)
			// 5. Close context
			// 6. Release browser
			// 7. Release concurrency slot
			if (networkInterceptor) {
				try {
					networkInterceptor.stopInterception();
					await networkInterceptor.waitForCompressions();
				} catch (e) {
					this.logger.warn('Error stopping network interceptor', e);
				}
			}

			if (page) {
				try {
					await page.close();
					this.logger.debug('Page closed');
				} catch (e) {
					this.logger.warn('Error closing page', e);
				}
			}

			if (networkInterceptor) {
				try {
					await networkInterceptor.clearCache();
				} catch (e) {
					this.logger.warn(
						'Error clearing network interceptor cache',
						e,
					);
				}
			}

			if (context) {
				try {
					await context.close();
					this.logger.debug('Context closed');
				} catch (e) {
					this.logger.warn('Error closing context', e);
				}
			}

			if (browser) {
				try {
					await this.browserFactory.release(browser);
					this.logger.debug('Browser released');
				} catch (e) {
					this.logger.warn('Error releasing browser', e);
				}
			}

			this.concurrencyManager.release(domain);
		}
	}

	private createStorageInjector(
		config: WebsiteConfigDto,
	): StorageInjector | null {
		const storageConfig: StorageConfig = {
			cookies: config.cookies,
			localStorage: config.localStorage,
			sessionStorage: config.sessionStorage,
			reloadAfterStorageInjection: config.reloadAfterStorageInjection,
		};

		const injector = new StorageInjector(storageConfig);
		return injector.hasStorageConfig() ? injector : null;
	}
}

import * as path from 'node:path';
import {
	Inject,
	Injectable,
	Logger,
	OnApplicationShutdown,
} from '@nestjs/common';
import { Redis } from 'ioredis';
import { Browser, BrowserContext, Page } from 'playwright';
import { AppConfigService } from 'src/app-config/app-config.service';
import { FilesService } from 'src/files/files.service';
import { REDIS_CLIENT } from 'src/redis/redis.constants';
import { PlaywrightBrowserFactory } from './browser';
import { IConcurrencyManager, RedisConcurrencyManager } from './concurrency';
import { WebsiteConfigDto } from './dto/website-config.dto';
import {
	CookieConfig,
	ElementScreenshot,
	ImageCompressor,
	ImageDownloader,
	NetworkInterceptor,
	PageScroller,
	StorageConfig,
	StorageInjector,
} from './helpers';
import {
	detectPageComplexity,
	getComplexityMultipliers,
	PageSize,
} from './helpers/page-complexity-detector';
import {
	DEFAULT_SCROLL_CONFIG,
	getAdaptiveScrollConfig,
} from './helpers/page-scroller';
import { ScrapingContext } from './runner/scraping-context.interface';
import { ScrapingSessionRunner } from './runner/scraping-session.runner';
import { WebsiteService } from './website.service';

@Injectable()
export class ScrapingService implements OnApplicationShutdown {
	readonly logger = new Logger(ScrapingService.name);
	concurrencyManager: IConcurrencyManager;
	private imageCompressor: ImageCompressor | undefined;
	private runner: ScrapingSessionRunner;

	constructor(
		private readonly appConfigService: AppConfigService,
		private readonly filesService: FilesService,
		private readonly webSiteService: WebsiteService,
		private readonly browserFactory: PlaywrightBrowserFactory,
		@Inject(REDIS_CLIENT) private readonly redis: Redis,
	) {
		this.initializeImageCompressor();
		this.initializeConcurrencyManager();
		this.runner = new ScrapingSessionRunner(
			this.browserFactory,
			this.concurrencyManager,
			this.imageCompressor,
		);

		if (this.appConfigService.playwright.debugMode) {
			this.logger.log('🔍 Playwright DEBUG mode enabled');
		}
		this.logger.debug('Scraping service initialized');
	}

	private initializeConcurrencyManager(): void {
		this.concurrencyManager = new RedisConcurrencyManager(this.redis, {
			slotTtlMs: 1_200_000,
			pollIntervalMs: 500,
			maxWaitMs: 3_600_000,
		});
		this.logger.log('✅ Redis concurrency manager initialized');
	}

	private initializeImageCompressor(): void {
		const compressorFactory = this.filesService.getCompressorFactory();

		this.imageCompressor = {
			compress: (buffer: Buffer, extension?: string) =>
				compressorFactory
					.compress(buffer, extension ?? '.jpg')
					.then((r) => r.buffer),
			getOutputExtension: (ext: string) => {
				const compressor = compressorFactory.getCompressor(ext);
				return compressor?.getOutputExtension(ext) ?? ext;
			},
		};

		this.logger.debug(
			'Image compressor initialized for network interception',
		);
	}

	setConcurrencyManager(manager: IConcurrencyManager): void {
		this.concurrencyManager = manager;
		// Re-create runner if dependencies change
		this.runner = new ScrapingSessionRunner(
			this.browserFactory,
			this.concurrencyManager,
			this.imageCompressor,
		);
		this.logger.debug('Concurrency manager replaced');
	}

	setBrowserFactory(factory: PlaywrightBrowserFactory): void {
		this.runner = new ScrapingSessionRunner(
			factory,
			this.concurrencyManager,
			this.imageCompressor,
		);
		this.logger.debug('Browser factory replaced');
	}

	public async getWebsiteConfig(url: string): Promise<WebsiteConfigDto> {
		let selector = 'img';
		let preScript = '';
		let posScript = '';
		let concurrencyLimit: number | null = null;
		let blacklistTerms: string[] = [];
		let whitelistTerms: string[] = [];
		let useNetworkInterception = true;
		let useScreenshotMode = false;
		let chapterListSelector: string | undefined;
		let bookInfoExtractScript: string | undefined;
		let cookies: CookieConfig[] | undefined;
		let localStorage: Record<string, string> | undefined;
		let sessionStorage: Record<string, string> | undefined;
		let reloadAfterStorageInjection: boolean | undefined;
		let enableAdaptiveTimeouts = true;
		let timeoutMultipliers: Record<string, number> | undefined;

		const domain = new URL(url).hostname;
		const website = await this.webSiteService.getByUrl(domain);

		if (website) {
			selector = website.selector || selector;
			preScript = website.preScript || preScript;
			posScript = website.posScript || posScript;
			concurrencyLimit = website.concurrencyLimit ?? null;
			blacklistTerms = website.blacklistTerms || [];
			whitelistTerms = website.whitelistTerms || [];
			useNetworkInterception = website.useNetworkInterception ?? true;
			useScreenshotMode = website.useScreenshotMode ?? false;
			chapterListSelector = website.chapterListSelector || undefined;
			bookInfoExtractScript = website.bookInfoExtractScript || undefined;
			cookies = website.cookies || undefined;
			localStorage = website.localStorage || undefined;
			sessionStorage = website.sessionStorage || undefined;
			reloadAfterStorageInjection =
				website.reloadAfterStorageInjection ?? false;
			enableAdaptiveTimeouts = website.enableAdaptiveTimeouts ?? true;
			timeoutMultipliers = website.timeoutMultipliers || undefined;
		}

		return {
			selector,
			preScript,
			posScript,
			concurrencyLimit,
			blacklistTerms,
			whitelistTerms,
			useNetworkInterception,
			useScreenshotMode,
			chapterListSelector,
			bookInfoExtractScript,
			cookies,
			localStorage,
			sessionStorage,
			reloadAfterStorageInjection,
			enableAdaptiveTimeouts,
			timeoutMultipliers,
		};
	}

	private async executeCustomScript(
		page: Page,
		script: string,
	): Promise<void> {
		if (!script) return;

		try {
			await page.evaluate(script);
			await page.waitForTimeout(3000);
		} catch (error) {
			this.logger.warn('Error executing custom script', error);
		}
	}

	private async downloadAndSaveImages(
		imageDownloader: ImageDownloader,
		imageUrls: string[],
		failedUrls: string[],
		networkInterceptor?: NetworkInterceptor,
	): Promise<(string | null)[]> {
		const results: (string | null)[] = [];

		for (const imageUrl of imageUrls) {
			if (failedUrls.includes(imageUrl)) {
				this.logger.warn(`Image failed to load: ${imageUrl}`);
				results.push(null);
				continue;
			}

			let bufferData: Buffer | null = null;
			let extension = '.jpg';
			let isPreCompressed = false;

			if (networkInterceptor) {
				if (networkInterceptor.hasImage(imageUrl)) {
					bufferData =
						await networkInterceptor.getCachedImageAsBuffer(
							imageUrl,
						);
					extension = networkInterceptor.getExtension(imageUrl);
					isPreCompressed = networkInterceptor.isCompressed(imageUrl);
					this.logger.debug(
						`Cache hit for: ${imageUrl} (compressed: ${isPreCompressed})`,
					);
				} else {
					this.logger.warn(
						`Image not found in network cache: ${imageUrl}`,
					);
				}
			} else {
				bufferData = await imageDownloader.fetchImageAsBuffer(imageUrl);
				if (!bufferData) {
					this.logger.debug(
						`Retrying with page context fetch: ${imageUrl}`,
					);
					bufferData =
						await imageDownloader.fetchImageViaPageContext(
							imageUrl,
						);
				}
				extension = path.extname(new URL(imageUrl).pathname) || '.jpg';
				this.logger.debug(`Cache miss, fetched: ${imageUrl}`);
			}

			if (!bufferData) {
				results.push(null);
				continue;
			}

			const savedPath = isPreCompressed
				? await this.filesService.savePreCompressedFile(
						bufferData,
						extension,
					)
				: await this.filesService.saveBufferFile(bufferData, extension);

			results.push(savedPath);
		}

		return results;
	}

	async scrapePages(url: string, pages = 0): Promise<string[] | null> {
		const config = await this.getWebsiteConfig(url);
		const {
			selector,
			preScript,
			posScript,
			blacklistTerms,
			whitelistTerms,
			useScreenshotMode,
		} = config;

		return this.runner.run(
			url,
			config,
			async ({ page, networkInterceptor }) => {
				if (selector && selector !== 'img') {
					this.logger.debug(`Waiting for selector: ${selector}`);
					await page
						.waitForSelector(selector, { timeout: 15000 })
						.catch(() => {
							this.logger.debug(
								`Selector "${selector}" not found within timeout, proceeding anyway`,
							);
						});
				}

				await this.executeCustomScript(page, preScript);

				const pageComplexity = await detectPageComplexity(
					page,
					selector,
				);
				this.logger.log(
					`📊 Página: ${pageComplexity.scrollHeight}px (${pageComplexity.scrollRatio.toFixed(1)}x viewport), ` +
						`${pageComplexity.elementCount} elementos, tamanho: ${pageComplexity.pageSize}`,
				);

				const multipliers = config.enableAdaptiveTimeouts
					? getComplexityMultipliers(
							pageComplexity,
							config.timeoutMultipliers as
								| Record<PageSize, number>
								| undefined,
						)
					: {
							delayMultiplier: 1,
							stabilityMultiplier: 1,
							timeoutMultiplier: 1,
							scrollStep: 1200,
						};

				let scrollResult = { failedImages: [] as string[] };

				if (!useScreenshotMode) {
					const adaptiveConfig = getAdaptiveScrollConfig(
						{ ...DEFAULT_SCROLL_CONFIG, imageSelector: selector },
						multipliers,
					);
					const scroller = new PageScroller(page, adaptiveConfig);
					scrollResult = await scroller.scrollAndWait();
				}

				await this.executeCustomScript(page, posScript);

				if (networkInterceptor) {
					networkInterceptor.stopInterception();
					await networkInterceptor.waitForCompressions();
				}

				if (useScreenshotMode) {
					this.logger.log(
						'📸 Using screenshot mode for image capture (PNG, lossless)',
					);
					const adaptiveParams = {
						scrollPauseMs: Math.ceil(
							1000 * multipliers.delayMultiplier,
						),
						scrollWaitMs: Math.ceil(
							300 * multipliers.delayMultiplier,
						),
					};
					return await this.captureElementsAsScreenshots(
						page,
						selector,
						pages,
						adaptiveParams,
					);
				}

				const imageDownloader = new ImageDownloader(page, {
					blacklistTerms,
					whitelistTerms,
				});
				const imageUrls = await imageDownloader.getImageUrls(selector);

				if (imageUrls.length <= pages) {
					return null;
				}

				this.logger.log(
					`Found ${imageUrls.length} valid image URLs. Starting downloads.`,
				);

				const successfulPaths = await this.downloadAndSaveImages(
					imageDownloader,
					imageUrls,
					scrollResult.failedImages,
					networkInterceptor,
				);

				return successfulPaths.filter(
					(path): path is string => path !== null,
				);
			},
		);
	}

	private async captureElementsAsScreenshots(
		page: Page,
		selector: string,
		minPages: number,
		pageComplexity?: { scrollPauseMs: number; scrollWaitMs: number },
	): Promise<string[]> {
		const scrollPauseMs = pageComplexity?.scrollPauseMs ?? 1000;
		const scrollWaitMs = pageComplexity?.scrollWaitMs ?? 300;

		const elementScreenshot = new ElementScreenshot(page, {
			selector,
			format: 'png',
			minSize: 50,
			scrollWaitMs,
			scrollPauseMs,
		});

		const count = await elementScreenshot.getElementCount();

		if (count <= minPages) {
			return [];
		}

		this.logger.log(
			`Found ${count} elements. Capturing PNG screenshots...`,
		);

		const results: (string | null)[] = [];

		for await (const buffer of elementScreenshot.captureAllElementsStream()) {
			try {
				const savedPath = await this.filesService.saveBufferFile(
					buffer,
					'.png',
				);
				results.push(savedPath);
			} catch (error) {
				this.logger.warn('Failed to save screenshot', error);
				results.push(null);
			}
		}

		const successfulScreenshots = results.filter(
			(path): path is string => path !== null,
		);

		this.logger.log(
			`Captured ${successfulScreenshots.length}/${count} screenshots`,
		);
		return successfulScreenshots;
	}

	async scrapeSingleImage(url: string, imageUrl: string): Promise<string> {
		const config = await this.getWebsiteConfig(url);

		return this.runner.run(
			url,
			config,
			async ({ page, networkInterceptor }) => {
				await networkInterceptor?.waitForCompressions();

				let bufferData: Buffer | null = null;
				let extension = '.jpg';
				let isPreCompressed = false;

				if (networkInterceptor) {
					if (networkInterceptor.hasImage(imageUrl)) {
						bufferData =
							await networkInterceptor.getCachedImageAsBuffer(
								imageUrl,
							);
						extension = networkInterceptor.getExtension(imageUrl);
						isPreCompressed =
							networkInterceptor.isCompressed(imageUrl);
					} else {
						this.logger.warn(
							`Image not found in network cache: ${imageUrl}`,
						);
					}
				} else {
					const imageDownloader = new ImageDownloader(page);
					bufferData =
						await imageDownloader.fetchImageAsBuffer(imageUrl);

					if (!bufferData) {
						this.logger.debug(
							`Retrying with page context fetch: ${imageUrl}`,
						);
						bufferData =
							await imageDownloader.fetchImageViaPageContext(
								imageUrl,
							);
					}
					extension =
						path.extname(new URL(imageUrl).pathname) || '.jpg';
				}

				if (!bufferData) {
					throw new Error(`Failed to download image: ${imageUrl}`);
				}

				return isPreCompressed
					? this.filesService.savePreCompressedFile(
							bufferData,
							extension,
						)
					: this.filesService.saveBufferFile(bufferData, extension);
			},
		);
	}

	async fetchImageBuffer(pageUrl: string, imageUrl: string): Promise<Buffer> {
		const config = await this.getWebsiteConfig(pageUrl);

		return this.runner.run(
			pageUrl,
			config,
			async ({ page, networkInterceptor }) => {
				await networkInterceptor?.waitForCompressions();

				let bufferData: Buffer | null = null;

				if (networkInterceptor) {
					if (!networkInterceptor.hasImage(imageUrl)) {
						this.logger.debug(
							`Image not in cache, forcing load via DOM: ${imageUrl}`,
						);
						try {
							await this.forceLoadImage(page, imageUrl);
							await networkInterceptor.waitForCompressions();
						} catch (e) {
							this.logger.warn(
								`Failed to force load image via DOM: ${e.message}`,
							);
						}
					}

					if (networkInterceptor.hasImage(imageUrl)) {
						bufferData =
							await networkInterceptor.getCachedImageAsBuffer(
								imageUrl,
							);
					} else {
						this.logger.warn(
							`Image not found in network cache even after force load: ${imageUrl}`,
						);
					}
				} else {
					const imageDownloader = new ImageDownloader(page);
					bufferData =
						await imageDownloader.fetchImageAsBuffer(imageUrl);

					if (!bufferData) {
						this.logger.debug(
							`Retrying with page context fetch: ${imageUrl}`,
						);
						bufferData =
							await imageDownloader.fetchImageViaPageContext(
								imageUrl,
							);
					}
				}

				if (!bufferData) {
					throw new Error(`Failed to download image: ${imageUrl}`);
				}

				return bufferData;
			},
		);
	}

	private async forceLoadImage(page: Page, imageUrl: string): Promise<void> {
		await page.evaluate(async (url) => {
			await new Promise<void>((resolve) => {
				const img = new Image();
				img.src = url;
				img.style.display = 'none';
				img.onload = () => resolve();
				img.onerror = () => resolve();
				document.body.appendChild(img);
			});
		}, imageUrl);
		await page.waitForTimeout(1000);
	}

	async scrapeMultipleImages(
		url: string,
		imageUrls: string[],
	): Promise<(string | null)[]> {
		const config = await this.getWebsiteConfig(url);

		return this.runner.run(
			url,
			config,
			async ({ page, networkInterceptor }) => {
				await networkInterceptor?.waitForCompressions();

				const imageDownloader = new ImageDownloader(page);
				const results: (string | null)[] = [];

				for (const imageUrl of imageUrls) {
					try {
						let bufferData: Buffer | null = null;
						let extension = '.jpg';
						let isPreCompressed = false;

						if (networkInterceptor) {
							if (!networkInterceptor.hasImage(imageUrl)) {
								this.logger.debug(
									`Image not in cache, forcing load via DOM: ${imageUrl}`,
								);
								try {
									await this.forceLoadImage(page, imageUrl);
									await networkInterceptor.waitForCompressions();
								} catch (e) {
									this.logger.warn(
										`Failed to force load image via DOM: ${e.message}`,
									);
								}
							}

							if (networkInterceptor.hasImage(imageUrl)) {
								bufferData =
									await networkInterceptor.getCachedImageAsBuffer(
										imageUrl,
									);
								extension =
									networkInterceptor.getExtension(imageUrl);
								isPreCompressed =
									networkInterceptor.isCompressed(imageUrl);
							} else {
								this.logger.warn(
									`Image not found in network cache even after force load: ${imageUrl}`,
								);
							}
						}

						if (!bufferData) {
							bufferData =
								await imageDownloader.fetchImageAsBuffer(
									imageUrl,
								);

							if (!bufferData) {
								this.logger.debug(
									`Retrying with page context fetch: ${imageUrl}`,
								);
								bufferData =
									await imageDownloader.fetchImageViaPageContext(
										imageUrl,
									);
							}
							extension =
								path.extname(new URL(imageUrl).pathname) ||
								'.jpg';
						}

						if (!bufferData) {
							this.logger.warn(
								`Failed to download image: ${imageUrl}`,
							);
							results.push(null);
							continue;
						}

						const saved = isPreCompressed
							? await this.filesService.savePreCompressedFile(
									bufferData,
									extension,
								)
							: await this.filesService.saveBufferFile(
									bufferData,
									extension,
								);
						results.push(saved);
					} catch (err) {
						this.logger.warn(
							`Error processing image ${imageUrl}`,
							err,
						);
						results.push(null);
					}
				}

				return results;
			},
		);
	}

	async scrapeBookInfo(bookUrl: string): Promise<{
		covers?: { url: string; title?: string }[];
		chapters: {
			title: string;
			url: string;
			index: number;
			isFinal?: boolean;
		}[];
	}> {
		const config = await this.getWebsiteConfig(bookUrl);
		const { chapterListSelector, bookInfoExtractScript, preScript } =
			config;

		if (!chapterListSelector && !bookInfoExtractScript) {
			const domain = new URL(bookUrl).hostname;
			this.logger.warn(
				`No book info configuration for domain: ${domain}`,
			);
			return { chapters: [] };
		}

		return this.runner.run(bookUrl, config, async ({ page }) => {
			if (chapterListSelector) {
				this.logger.debug(
					`Waiting for chapter selector: ${chapterListSelector}`,
				);
				await page
					.waitForSelector(chapterListSelector, { timeout: 15000 })
					.catch(() => {
						this.logger.debug(
							`Chapter selector "${chapterListSelector}" not found within timeout`,
						);
					});
			}

			await this.executeCustomScript(page, preScript);

			let result: {
				covers?: { url: string; title?: string }[];
				chapters: {
					title: string;
					url: string;
					index: number;
					isFinal?: boolean;
				}[];
			} = { chapters: [] };

			if (bookInfoExtractScript) {
				try {
					const rawResult = await page.evaluate(
						bookInfoExtractScript,
					);
					if (!rawResult || typeof rawResult !== 'object') {
						throw new Error('Script must return an object');
					}

					const typedResult = rawResult as {
						covers?: ({ url: string; title?: string } | string)[];
						cover?: { url: string; title?: string } | string;
						chapters?: {
							title: string;
							url: string;
							index: number;
							isFinal?: boolean;
						}[];
					};
					let normalizedCovers: { url: string; title?: string }[] =
						[];

					if (Array.isArray(typedResult.covers)) {
						normalizedCovers = typedResult.covers
							.map((c, i) => {
								if (typeof c === 'string')
									return { url: c, title: `Capa ${i + 1}` };
								return {
									url: c.url,
									title: c.title || `Capa ${i + 1}`,
								};
							})
							.filter((c) => c.url);
					} else if (typedResult.cover) {
						normalizedCovers = [
							typeof typedResult.cover === 'string'
								? {
										url: typedResult.cover,
										title: 'Capa Principal',
									}
								: {
										url: typedResult.cover.url,
										title:
											typedResult.cover.title ||
											'Capa Principal',
									},
						];
					}

					result = {
						covers: normalizedCovers,
						chapters: Array.isArray(typedResult.chapters)
							? typedResult.chapters
							: [],
					};
				} catch (error) {
					this.logger.error(
						`Error executing bookInfoExtractScript: ${error.message}`,
					);
				}
			} else if (chapterListSelector) {
				const chapters = await page.evaluate((selector) => {
					const elements = document.querySelectorAll(selector);
					return Array.from(elements)
						.map((el, index, arr) => {
							const anchor =
								el.tagName === 'A'
									? (el as HTMLAnchorElement)
									: el.querySelector('a');
							return {
								title:
									el.textContent?.trim() ||
									`Chapter ${index + 1}`,
								url: anchor?.href || '',
								index: index + 1,
								isFinal: index === arr.length - 1,
							};
						})
						.filter((ch) => ch.url);
				}, chapterListSelector);
				result = { chapters };
			}

			this.logger.log(
				`Found ${result.chapters.length} chapters on ${bookUrl}${result.covers?.length ? ` (with ${result.covers.length} covers)` : ''}`,
			);
			return result;
		});
	}

	async scrapeChapterList(
		bookUrl: string,
	): Promise<{ title: string; url: string; index: number }[]> {
		const result = await this.scrapeBookInfo(bookUrl);
		return result.chapters;
	}

	async onApplicationShutdown(): Promise<void> {
		this.logger.log('🛑 Shutting down scraping service...');

		// Gracefully shutdown browser factory and pool
		try {
			await Promise.race([
				this.browserFactory.shutdown(),
				new Promise((_, reject) =>
					setTimeout(
						() => reject(new Error('Shutdown timeout')),
						30000,
					),
				),
			]);
			this.logger.log('✅ Scraping service shutdown complete');
		} catch (error) {
			this.logger.error(
				`Error during scraping service shutdown: ${error.message}`,
			);
		}
	}
}

import {
	BadRequestException,
	ConflictException,
	Injectable,
	NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Brackets, In, Repository } from 'typeorm';
import { CreateAccessPolicyDto } from './dto/create-access-policy.dto';
import { CreateGroupDto } from './dto/create-group.dto';
import { CreateRoleDto } from './dto/create-role.dto';
import { ListAccessPoliciesQueryDto } from './dto/list-access-policies-query.dto';
import { SetUserModerationDto } from './dto/set-user-moderation.dto';
import { UpdateGroupDto } from './dto/update-group.dto';
import { UpdateUserRolesDto } from './dto/update-user-roles.dto';
import { UpdateRoleDto } from './dto/update-role.dto';
import { AccessPolicy } from './entities/access-policy.entity';
import { Role } from './entities/role.entity';
import { UserGroup } from './entities/user-group.entity';
import { User } from './entities/user.entity';
import { AccessPolicyEffectEnum } from './enum/access-policy-effect.enum';
import { AccessPolicyScopeEnum } from './enum/access-policy-scope.enum';
import { RolesEnum } from './enum/roles.enum';

@Injectable()
export class AdminUsersService {
	constructor(
		@InjectRepository(User)
		private readonly userRepository: Repository<User>,
		@InjectRepository(Role)
		private readonly roleRepository: Repository<Role>,
		@InjectRepository(UserGroup)
		private readonly groupRepository: Repository<UserGroup>,
		@InjectRepository(AccessPolicy)
		private readonly accessPolicyRepository: Repository<AccessPolicy>,
	) {}

	async listUsers(params: {
		page: number;
		limit: number;
		search?: string;
		role?: string;
		isBanned?: boolean;
		isSuspended?: boolean;
	}) {
		const page = Math.max(1, params.page);
		const limit = Math.min(100, Math.max(1, params.limit));

		const qb = this.userRepository
			.createQueryBuilder('user')
			.leftJoinAndSelect('user.roles', 'role')
			.leftJoinAndSelect('user.groups', 'group');

		if (params.search) {
			qb.andWhere(
				new Brackets((query) => {
					query
						.where('user.userName LIKE :search', {
							search: `%${params.search}%`,
						})
						.orWhere('user.name LIKE :search', {
							search: `%${params.search}%`,
						})
						.orWhere('user.email LIKE :search', {
							search: `%${params.search}%`,
						});
				}),
			);
		}

		if (params.role) {
			qb.andWhere('role.name = :role', { role: params.role });
		}

		if (typeof params.isBanned === 'boolean') {
			qb.andWhere('user.isBanned = :isBanned', {
				isBanned: params.isBanned,
			});
		}

		if (typeof params.isSuspended === 'boolean') {
			const now = new Date();
			if (params.isSuspended) {
				qb.andWhere(
					'user.suspendedUntil IS NOT NULL AND user.suspendedUntil > :now',
					{
						now,
					},
				);
			} else {
				qb.andWhere(
					'(user.suspendedUntil IS NULL OR user.suspendedUntil <= :now)',
					{
						now,
					},
				);
			}
		}

		qb.orderBy('user.createdAt', 'DESC')
			.skip((page - 1) * limit)
			.take(limit);

		const [users, total] = await qb.getManyAndCount();
		return {
			data: users,
			meta: {
				total,
				page,
				limit,
				lastPage: Math.ceil(total / limit),
			},
		};
	}

	async getUserById(userId: string) {
		const user = await this.userRepository.findOne({
			where: { id: userId },
			relations: ['roles', 'groups'],
		});
		if (!user) {
			throw new NotFoundException(`User with id ${userId} not found`);
		}
		return user;
	}

	async updateUserByAdmin(
		userId: string,
		dto: {
			userName?: string;
			name?: string;
			maxWeightSensitiveContent?: number;
			isBanned?: boolean;
			suspendedUntil?: string;
			suspensionReason?: string;
		},
	) {
		const user = await this.getUserById(userId);
		if (dto.userName !== undefined) {
			user.userName = dto.userName;
		}
		if (dto.name !== undefined) {
			user.name = dto.name;
		}
		if (dto.maxWeightSensitiveContent !== undefined) {
			user.maxWeightSensitiveContent = dto.maxWeightSensitiveContent;
		}
		if (dto.isBanned !== undefined) {
			user.isBanned = dto.isBanned;
		}
		if (dto.suspendedUntil !== undefined) {
			user.suspendedUntil = dto.suspendedUntil
				? new Date(dto.suspendedUntil)
				: null;
		}
		if (dto.suspensionReason !== undefined) {
			user.suspensionReason = dto.suspensionReason;
		}
		return this.userRepository.save(user);
	}

	async updateUserRoles(
		targetUserId: string,
		dto: UpdateUserRolesDto,
		currentAdminId: string,
	) {
		const user = await this.getUserById(targetUserId);
		const roles = await this.roleRepository.find({
			where: { name: In(dto.roles) },
		});

		if (roles.length !== dto.roles.length) {
			throw new BadRequestException('One or more roles were not found');
		}

		if (
			targetUserId === currentAdminId &&
			!roles.some((role) => role.name === RolesEnum.ADMIN)
		) {
			throw new BadRequestException(
				'You cannot remove your own admin role',
			);
		}

		user.roles = roles;
		return this.userRepository.save(user);
	}

	async setUserModeration(
		targetUserId: string,
		dto: SetUserModerationDto,
		currentAdminId: string,
	) {
		if (targetUserId === currentAdminId && dto.isBanned === true) {
			throw new BadRequestException('You cannot ban yourself');
		}

		const user = await this.getUserById(targetUserId);
		if (dto.isBanned !== undefined) {
			user.isBanned = dto.isBanned;
		}

		if (dto.suspendedUntil !== undefined) {
			if (!dto.suspendedUntil) {
				user.suspendedUntil = null;
			} else {
				const suspendedUntil = new Date(dto.suspendedUntil);
				if (suspendedUntil <= new Date()) {
					throw new BadRequestException(
						'suspendedUntil must be a future date',
					);
				}
				user.suspendedUntil = suspendedUntil;
			}
		}

		if (dto.suspensionReason !== undefined) {
			user.suspensionReason = dto.suspensionReason;
		}

		return this.userRepository.save(user);
	}

	async deleteUserByAdmin(targetUserId: string, currentAdminId: string) {
		if (targetUserId === currentAdminId) {
			throw new BadRequestException('You cannot delete your own account');
		}

		const user = await this.getUserById(targetUserId);
		await this.userRepository.remove(user);
		return { success: true };
	}

	async listRoles() {
		return this.roleRepository.find({
			order: { name: 'ASC' },
		});
	}

	async createRole(dto: CreateRoleDto) {
		const exists = await this.roleRepository.findOne({
			where: { name: dto.name },
		});
		if (exists) {
			throw new ConflictException(`Role ${dto.name} already exists`);
		}
		const role = this.roleRepository.create(dto);
		return this.roleRepository.save(role);
	}

	async updateRole(roleId: string, dto: UpdateRoleDto) {
		const role = await this.roleRepository.findOne({
			where: { id: roleId },
		});
		if (!role) {
			throw new NotFoundException(`Role with id ${roleId} not found`);
		}

		if (dto.name !== undefined && dto.name !== role.name) {
			const exists = await this.roleRepository.findOne({
				where: { name: dto.name },
			});
			if (exists) {
				throw new ConflictException(`Role ${dto.name} already exists`);
			}
			role.name = dto.name;
		}

		if (dto.maxWeightSensitiveContent !== undefined) {
			role.maxWeightSensitiveContent = dto.maxWeightSensitiveContent;
		}

		return this.roleRepository.save(role);
	}

	async listGroups() {
		return this.groupRepository.find({
			relations: ['members'],
			order: { name: 'ASC' },
		});
	}

	async createGroup(dto: CreateGroupDto) {
		const exists = await this.groupRepository.findOne({
			where: { name: dto.name },
		});
		if (exists) {
			throw new ConflictException(`Group ${dto.name} already exists`);
		}
		const group = this.groupRepository.create({
			...dto,
			description: dto.description ?? null,
		});
		return this.groupRepository.save(group);
	}

	async updateGroup(groupId: string, dto: UpdateGroupDto) {
		const group = await this.groupRepository.findOne({
			where: { id: groupId },
		});
		if (!group) {
			throw new NotFoundException(`Group with id ${groupId} not found`);
		}

		if (dto.name !== undefined && dto.name !== group.name) {
			const exists = await this.groupRepository.findOne({
				where: { name: dto.name },
			});
			if (exists) {
				throw new ConflictException(`Group ${dto.name} already exists`);
			}
			group.name = dto.name;
		}

		if (dto.description !== undefined) {
			group.description = dto.description;
		}

		if (dto.defaultMaxWeightSensitiveContent !== undefined) {
			group.defaultMaxWeightSensitiveContent =
				dto.defaultMaxWeightSensitiveContent;
		}

		return this.groupRepository.save(group);
	}

	async deleteGroup(groupId: string) {
		const group = await this.groupRepository.findOne({
			where: { id: groupId },
		});
		if (!group) {
			throw new NotFoundException(`Group with id ${groupId} not found`);
		}
		await this.groupRepository.remove(group);
		return { success: true };
	}

	async addMembersToGroup(groupId: string, userIds: string[]) {
		const group = await this.groupRepository.findOne({
			where: { id: groupId },
			relations: ['members'],
		});
		if (!group) {
			throw new NotFoundException(`Group with id ${groupId} not found`);
		}

		const users = await this.userRepository.find({
			where: { id: In(userIds) },
		});
		if (users.length !== userIds.length) {
			throw new BadRequestException('One or more users were not found');
		}

		const memberById = new Map((group.members || []).map((m) => [m.id, m]));
		for (const user of users) {
			memberById.set(user.id, user);
		}
		group.members = Array.from(memberById.values());
		return this.groupRepository.save(group);
	}

	async removeMemberFromGroup(groupId: string, userId: string) {
		const group = await this.groupRepository.findOne({
			where: { id: groupId },
			relations: ['members'],
		});
		if (!group) {
			throw new NotFoundException(`Group with id ${groupId} not found`);
		}

		group.members = (group.members || []).filter(
			(member) => member.id !== userId,
		);
		return this.groupRepository.save(group);
	}

	async createAccessPolicy(
		dto: CreateAccessPolicyDto,
		currentAdminId: string,
	) {
		if (!dto.targetUserId && !dto.targetGroupId) {
			throw new BadRequestException(
				'targetUserId or targetGroupId is required',
			);
		}
		if (dto.targetUserId && dto.targetGroupId) {
			throw new BadRequestException(
				'Use either targetUserId or targetGroupId, not both',
			);
		}

		if (dto.scope === AccessPolicyScopeEnum.BOOK && !dto.bookId) {
			throw new BadRequestException('bookId is required for scope book');
		}
		if (dto.scope === AccessPolicyScopeEnum.TAG && !dto.tagId) {
			throw new BadRequestException('tagId is required for scope tag');
		}
		if (
			dto.scope === AccessPolicyScopeEnum.SENSITIVE_CONTENT &&
			!dto.sensitiveContentId
		) {
			throw new BadRequestException(
				'sensitiveContentId is required for scope sensitive_content',
			);
		}
		if (
			dto.scope === AccessPolicyScopeEnum.GLOBAL &&
			(dto.bookId || dto.tagId || dto.sensitiveContentId)
		) {
			throw new BadRequestException(
				'global scope cannot define bookId, tagId or sensitiveContentId',
			);
		}

		const policy = this.accessPolicyRepository.create({
			effect: dto.effect,
			scope: dto.scope,
			targetUserId: dto.targetUserId ?? null,
			targetGroupId: dto.targetGroupId ?? null,
			bookId: dto.bookId ?? null,
			tagId: dto.tagId ?? null,
			sensitiveContentId: dto.sensitiveContentId ?? null,
			isActive: dto.isActive ?? true,
			overrideMaxWeightSensitiveContent:
				dto.overrideMaxWeightSensitiveContent ?? null,
			reason: dto.reason ?? null,
			expiresAt: dto.expiresAt ? new Date(dto.expiresAt) : null,
			createdByUserId: currentAdminId,
		});

		return this.accessPolicyRepository.save(policy);
	}

	async listAccessPolicies(query: ListAccessPoliciesQueryDto) {
		const qb = this.accessPolicyRepository
			.createQueryBuilder('policy')
			.orderBy('policy.createdAt', 'DESC');

		if (query.effect) {
			qb.andWhere('policy.effect = :effect', { effect: query.effect });
		}
		if (query.scope) {
			qb.andWhere('policy.scope = :scope', { scope: query.scope });
		}
		if (query.targetUserId) {
			qb.andWhere('policy.targetUserId = :targetUserId', {
				targetUserId: query.targetUserId,
			});
		}
		if (query.targetGroupId) {
			qb.andWhere('policy.targetGroupId = :targetGroupId', {
				targetGroupId: query.targetGroupId,
			});
		}
		if (query.isActive !== undefined) {
			qb.andWhere('policy.isActive = :isActive', {
				isActive: query.isActive === 'true',
			});
		}

		return qb.getMany();
	}

	async deleteAccessPolicy(policyId: string) {
		const policy = await this.accessPolicyRepository.findOne({
			where: { id: policyId },
		});
		if (!policy) {
			throw new NotFoundException(
				`Access policy with id ${policyId} not found`,
			);
		}
		await this.accessPolicyRepository.remove(policy);
		return { success: true };
	}

	async evaluateListAccessContext(params: {
		userId?: string;
		baseMaxWeightSensitiveContent: number;
	}) {
		const emptyContext = {
			blockedAll: false,
			effectiveMaxWeightSensitiveContent:
				params.baseMaxWeightSensitiveContent,
			denyBookIds: [] as string[],
			denyTagIds: [] as string[],
			allowBookIds: [] as string[],
			allowTagIds: [] as string[],
			denySensitiveContentIds: [] as string[],
			allowSensitiveContentIds: [] as string[],
			allowBookWeightById: {} as Record<string, number>,
			allowTagWeightById: {} as Record<string, number>,
			allowSensitiveContentWeightById: {} as Record<string, number>,
		};

		if (!params.userId) {
			return emptyContext;
		}

		const user = await this.userRepository.findOne({
			where: { id: params.userId },
			relations: ['groups'],
		});

		if (!user) {
			return emptyContext;
		}

		const groupIds = (user.groups || []).map((group) => group.id);
		const policyQb = this.accessPolicyRepository
			.createQueryBuilder('policy')
			.where('policy.isActive = :isActive', { isActive: true })
			.andWhere('(policy.expiresAt IS NULL OR policy.expiresAt > :now)', {
				now: new Date(),
			})
			.andWhere(
				new Brackets((query) => {
					query.where('policy.targetUserId = :userId', {
						userId: params.userId,
					});
					if (groupIds.length > 0) {
						query.orWhere(
							'policy.targetGroupId IN (:...groupIds)',
							{
								groupIds,
							},
						);
					}
				}),
			);

		const policies = await policyQb.getMany();

		if (!policies.length) {
			return emptyContext;
		}

		const getPolicyWeight = (policy: AccessPolicy) =>
			policy.overrideMaxWeightSensitiveContent === null ||
			policy.overrideMaxWeightSensitiveContent === undefined
				? 99
				: policy.overrideMaxWeightSensitiveContent;

		type SourceDecision = {
			globalDecision: 'allow' | 'deny' | null;
			globalAllowWeight: number;
			denyBookIds: Set<string>;
			denyTagIds: Set<string>;
			denySensitiveContentIds: Set<string>;
			allowBookWeightById: Map<string, number>;
			allowTagWeightById: Map<string, number>;
			allowSensitiveContentWeightById: Map<string, number>;
		};

		const buildSourceDecision = (
			sourcePolicies: AccessPolicy[],
		): SourceDecision => {
			let hasGlobalAllow = false;
			let hasGlobalDeny = false;
			let globalAllowWeight = params.baseMaxWeightSensitiveContent;

			const denyBookIds = new Set<string>();
			const denyTagIds = new Set<string>();
			const denySensitiveContentIds = new Set<string>();
			const allowBookWeightById = new Map<string, number>();
			const allowTagWeightById = new Map<string, number>();
			const allowSensitiveContentWeightById = new Map<string, number>();

			for (const policy of sourcePolicies) {
				if (policy.scope === AccessPolicyScopeEnum.GLOBAL) {
					if (policy.effect === AccessPolicyEffectEnum.DENY) {
						hasGlobalDeny = true;
						continue;
					}

					hasGlobalAllow = true;
					globalAllowWeight = Math.max(
						globalAllowWeight,
						getPolicyWeight(policy),
					);
					continue;
				}

				if (policy.effect === AccessPolicyEffectEnum.DENY) {
					if (
						policy.scope === AccessPolicyScopeEnum.BOOK &&
						policy.bookId
					) {
						denyBookIds.add(policy.bookId);
					}
					if (
						policy.scope === AccessPolicyScopeEnum.TAG &&
						policy.tagId
					) {
						denyTagIds.add(policy.tagId);
					}
					if (
						policy.scope ===
							AccessPolicyScopeEnum.SENSITIVE_CONTENT &&
						policy.sensitiveContentId
					) {
						denySensitiveContentIds.add(policy.sensitiveContentId);
					}
					continue;
				}

				if (
					policy.scope === AccessPolicyScopeEnum.BOOK &&
					policy.bookId
				) {
					allowBookWeightById.set(
						policy.bookId,
						Math.max(
							allowBookWeightById.get(policy.bookId) ?? 0,
							getPolicyWeight(policy),
						),
					);
				}

				if (
					policy.scope === AccessPolicyScopeEnum.TAG &&
					policy.tagId
				) {
					allowTagWeightById.set(
						policy.tagId,
						Math.max(
							allowTagWeightById.get(policy.tagId) ?? 0,
							getPolicyWeight(policy),
						),
					);
				}

				if (
					policy.scope === AccessPolicyScopeEnum.SENSITIVE_CONTENT &&
					policy.sensitiveContentId
				) {
					allowSensitiveContentWeightById.set(
						policy.sensitiveContentId,
						Math.max(
							allowSensitiveContentWeightById.get(
								policy.sensitiveContentId,
							) ?? 0,
							getPolicyWeight(policy),
						),
					);
				}
			}

			for (const deniedBookId of denyBookIds) {
				allowBookWeightById.delete(deniedBookId);
			}
			for (const deniedTagId of denyTagIds) {
				allowTagWeightById.delete(deniedTagId);
			}
			for (const deniedSensitiveContentId of denySensitiveContentIds) {
				allowSensitiveContentWeightById.delete(
					deniedSensitiveContentId,
				);
			}

			let globalDecision: 'allow' | 'deny' | null = null;
			if (hasGlobalDeny) {
				globalDecision = 'deny';
			} else if (hasGlobalAllow) {
				globalDecision = 'allow';
			}

			return {
				globalDecision,
				globalAllowWeight,
				denyBookIds,
				denyTagIds,
				denySensitiveContentIds,
				allowBookWeightById,
				allowTagWeightById,
				allowSensitiveContentWeightById,
			};
		};

		const userPolicies = policies.filter(
			(policy) => policy.targetUserId === params.userId,
		);
		const groupPolicies = policies.filter(
			(policy) =>
				!!policy.targetGroupId &&
				groupIds.includes(policy.targetGroupId),
		);

		const userDecision = buildSourceDecision(userPolicies);
		const groupDecision = buildSourceDecision(groupPolicies);

		let blockedAll = false;
		let effectiveMaxWeight = params.baseMaxWeightSensitiveContent;

		if (userDecision.globalDecision === 'deny') {
			blockedAll = true;
		} else if (userDecision.globalDecision === 'allow') {
			effectiveMaxWeight = Math.max(
				effectiveMaxWeight,
				userDecision.globalAllowWeight,
			);
		} else if (groupDecision.globalDecision === 'deny') {
			blockedAll = true;
		} else if (groupDecision.globalDecision === 'allow') {
			effectiveMaxWeight = Math.max(
				effectiveMaxWeight,
				groupDecision.globalAllowWeight,
			);
		}

		const effectiveDenyBookIds = new Set(groupDecision.denyBookIds);
		const effectiveDenyTagIds = new Set(groupDecision.denyTagIds);
		const effectiveDenySensitiveContentIds = new Set(
			groupDecision.denySensitiveContentIds,
		);
		const effectiveAllowBookWeightById = new Map(
			groupDecision.allowBookWeightById,
		);
		const effectiveAllowTagWeightById = new Map(
			groupDecision.allowTagWeightById,
		);
		const effectiveAllowSensitiveContentWeightById = new Map(
			groupDecision.allowSensitiveContentWeightById,
		);

		for (const [bookId, weight] of userDecision.allowBookWeightById) {
			effectiveDenyBookIds.delete(bookId);
			effectiveAllowBookWeightById.set(bookId, weight);
		}

		for (const [tagId, weight] of userDecision.allowTagWeightById) {
			effectiveDenyTagIds.delete(tagId);
			effectiveAllowTagWeightById.set(tagId, weight);
		}

		for (const [
			sensitiveContentId,
			weight,
		] of userDecision.allowSensitiveContentWeightById) {
			effectiveDenySensitiveContentIds.delete(sensitiveContentId);
			effectiveAllowSensitiveContentWeightById.set(
				sensitiveContentId,
				weight,
			);
		}

		for (const bookId of userDecision.denyBookIds) {
			effectiveAllowBookWeightById.delete(bookId);
			effectiveDenyBookIds.add(bookId);
		}

		for (const tagId of userDecision.denyTagIds) {
			effectiveAllowTagWeightById.delete(tagId);
			effectiveDenyTagIds.add(tagId);
		}

		for (const sensitiveContentId of userDecision.denySensitiveContentIds) {
			effectiveAllowSensitiveContentWeightById.delete(sensitiveContentId);
			effectiveDenySensitiveContentIds.add(sensitiveContentId);
		}

		const maxSensitiveContentAllowWeight = Array.from(
			effectiveAllowSensitiveContentWeightById.values(),
		).reduce((maxWeight, weight) => Math.max(maxWeight, weight), 0);

		effectiveMaxWeight = Math.max(
			effectiveMaxWeight,
			maxSensitiveContentAllowWeight,
		);

		return {
			blockedAll,
			effectiveMaxWeightSensitiveContent: effectiveMaxWeight,
			denyBookIds: Array.from(effectiveDenyBookIds),
			denyTagIds: Array.from(effectiveDenyTagIds),
			denySensitiveContentIds: Array.from(
				effectiveDenySensitiveContentIds,
			),
			allowBookIds: Array.from(effectiveAllowBookWeightById.keys()),
			allowTagIds: Array.from(effectiveAllowTagWeightById.keys()),
			allowSensitiveContentIds: Array.from(
				effectiveAllowSensitiveContentWeightById.keys(),
			),
			allowBookWeightById: Object.fromEntries(
				effectiveAllowBookWeightById,
			),
			allowTagWeightById: Object.fromEntries(effectiveAllowTagWeightById),
			allowSensitiveContentWeightById: Object.fromEntries(
				effectiveAllowSensitiveContentWeightById,
			),
		};
	}

	async evaluateAccessForBook(params: {
		userId?: string;
		bookId: string;
		bookTagIds: string[];
		bookSensitiveContentIds: string[];
		baseMaxWeightSensitiveContent: number;
	}) {
		const context = await this.evaluateListAccessContext({
			userId: params.userId,
			baseMaxWeightSensitiveContent: params.baseMaxWeightSensitiveContent,
		});

		if (context.blockedAll) {
			return {
				blocked: true,
				effectiveMaxWeightSensitiveContent:
					context.effectiveMaxWeightSensitiveContent,
			};
		}

		if (
			context.denyBookIds.includes(params.bookId) ||
			params.bookTagIds.some((tagId) =>
				context.denyTagIds.includes(tagId),
			) ||
			params.bookSensitiveContentIds.some((sensitiveContentId) =>
				context.denySensitiveContentIds.includes(sensitiveContentId),
			)
		) {
			return {
				blocked: true,
				effectiveMaxWeightSensitiveContent:
					context.effectiveMaxWeightSensitiveContent,
			};
		}

		let effectiveMaxWeight = context.effectiveMaxWeightSensitiveContent;
		const allowBookWeight = context.allowBookWeightById[params.bookId] ?? 0;
		const allowTagWeight = params.bookTagIds.reduce((maxWeight, tagId) => {
			const tagWeight = context.allowTagWeightById[tagId] ?? 0;
			return Math.max(maxWeight, tagWeight);
		}, 0);
		const allowSensitiveContentWeight =
			params.bookSensitiveContentIds.reduce(
				(maxWeight, sensitiveContentId) => {
					const sensitiveContentWeight =
						context.allowSensitiveContentWeightById[
							sensitiveContentId
						] ?? 0;
					return Math.max(maxWeight, sensitiveContentWeight);
				},
				0,
			);

		if (
			allowBookWeight > 0 ||
			allowTagWeight > 0 ||
			allowSensitiveContentWeight > 0
		) {
			effectiveMaxWeight = Math.max(
				effectiveMaxWeight,
				allowBookWeight,
				allowTagWeight,
				allowSensitiveContentWeight,
			);
		}

		return {
			blocked: false,
			effectiveMaxWeightSensitiveContent: effectiveMaxWeight,
		};
	}
}

import { Injectable } from '@nestjs/common';
import { SaveReadingProgressDto } from '../dto/reading-progress.dto';
import { ReadingProgress } from '../entities/reading-progress.entity';
import {
	SyncResolution,
	SyncResolutionContext,
	SyncStrategy,
} from './sync-strategy.interface';

@Injectable()
export class HighestPageWinsStrategy implements SyncStrategy {
	readonly name = 'HighestPageWinsStrategy';

	canHandle(context: SyncResolutionContext): boolean {
		return !context.lastSyncAt;
	}

	resolve(
		local: SaveReadingProgressDto,
		remote: ReadingProgress,
		_context: SyncResolutionContext,
	): SyncResolution {
		return local.pageIndex >= remote.pageIndex ? 'local' : 'remote';
	}
}

import {
	BadRequestException,
	Injectable,
	Logger,
	NotFoundException,
	OnApplicationBootstrap,
} from '@nestjs/common';
import { FilesService } from 'src/files/files.service';
import { InjectRepository } from '@nestjs/typeorm';
import sharp from 'sharp';
import { DataSource, Repository } from 'typeorm';
import { UpdateUserDto } from './dto/update-user.dto';
import { Role } from './entities/role.entity';
import { User } from './entities/user.entity';
import { RolesEnum } from './enum/roles.enum';
import { UserResourcesMapper } from './user-resources.mapper';

@Injectable()
export class UsersService implements OnApplicationBootstrap {
	private readonly logger = new Logger(UsersService.name);
	private readonly maxAvatarSizeBytes = 5 * 1024 * 1024;
	private readonly maxBannerSizeBytes = 10 * 1024 * 1024;
	private readonly allowedAvatarMimeTypes = new Set([
		'image/png',
		'image/jpeg',
		'image/webp',
	]);
	constructor(
		@InjectRepository(User)
		private readonly userRepository: Repository<User>,
		@InjectRepository(Role)
		private readonly roleRepository: Repository<Role>,
		private readonly dataSource: DataSource,
		private readonly filesService: FilesService,
		private readonly userResourcesMapper: UserResourcesMapper,
	) {}

	async onApplicationBootstrap() {
		const roles = [
			{
				name: RolesEnum.ADMIN,
				maxWeightSensitiveContent: 99,
			},
			{
				name: RolesEnum.USER,
				maxWeightSensitiveContent: 4,
			},
		];

		for (const role of roles) {
			try {
				const exists = await this.roleRepository.findOne({
					where: { name: role.name },
				});

				if (!exists) {
					await this.roleRepository.save(
						this.roleRepository.create(role),
					);
					this.logger.log(`Role '${role.name}' created successfully`);
				} else {
					this.logger.debug(
						`Role '${role.name}' already exists, skipping`,
					);
				}
			} catch (error) {
				if (error.code === 'ER_DUP_ENTRY' || error.errno === 1062) {
					this.logger.warn(
						`Role '${role.name}' already exists (handled race condition)`,
					);
				} else {
					this.logger.error(
						`Error creating role '${role.name}': ${error.message}`,
						error.stack,
					);
					throw error;
				}
			}
		}
	}

	async updateUser(dto: UpdateUserDto, userId: string): Promise<User> {
		const user = await this.userRepository.findOne({
			where: { id: userId },
		});
		if (!user) {
			throw new NotFoundException(`User with id ${userId} not found`);
		}
		return this.userRepository.save(this.userRepository.merge(user, dto));
	}

	async getCurrentUser(userId: string) {
		const user = await this.userRepository.findOne({
			where: { id: userId },
		});

		if (!user) {
			throw new NotFoundException(`User with id ${userId} not found`);
		}

		return this.userResourcesMapper.toUserProfile(user);
	}

	async getPublicUserProfile(userId: string) {
		const user = await this.userRepository.findOne({
			where: { id: userId },
		});

		if (!user) {
			throw new NotFoundException(`User with id ${userId} not found`);
		}

		return this.userResourcesMapper.toPublicUserProfile(user);
	}

	async uploadAvatar(file: Express.Multer.File, userId: string) {
		const user = await this.findUserOrFail(userId);
		const extension = await this.validateAndResolveImageExtension(
			file,
			this.maxAvatarSizeBytes,
			'avatar',
		);
		const publicPath = await this.filesService.saveBufferFile(
			file.buffer,
			extension,
		);

		if (user.profileImagePath) {
			await this.filesService.deleteFile(user.profileImagePath);
		}

		user.profileImagePath = publicPath;
		const savedUser = await this.userRepository.save(user);
		return this.userResourcesMapper.toUserProfile(savedUser);
	}

	async uploadBanner(file: Express.Multer.File, userId: string) {
		const user = await this.findUserOrFail(userId);
		const extension = await this.validateAndResolveImageExtension(
			file,
			this.maxBannerSizeBytes,
			'banner',
		);
		const publicPath = await this.filesService.saveBufferFile(
			file.buffer,
			extension,
		);

		if (user.profileBannerPath) {
			await this.filesService.deleteFile(user.profileBannerPath);
		}

		user.profileBannerPath = publicPath;
		const savedUser = await this.userRepository.save(user);
		return this.userResourcesMapper.toUserProfile(savedUser);
	}

	private async findUserOrFail(userId: string): Promise<User> {
		const user = await this.userRepository.findOne({
			where: { id: userId },
		});

		if (!user) {
			throw new NotFoundException(`User with id ${userId} not found`);
		}

		return user;
	}

	private async validateAndResolveImageExtension(
		file: Express.Multer.File,
		maxSizeBytes: number,
		label: 'avatar' | 'banner',
	): Promise<string> {
		if (!file) {
			throw new BadRequestException(`${label} file is required`);
		}

		if (!file.buffer || file.size === 0) {
			throw new BadRequestException(`${label} file is empty`);
		}

		if (file.size > maxSizeBytes) {
			const maxSizeMb = Math.floor(maxSizeBytes / (1024 * 1024));
			throw new BadRequestException(
				`${label} file is too large. Maximum size is ${maxSizeMb}MB`,
			);
		}

		if (!this.allowedAvatarMimeTypes.has(file.mimetype)) {
			throw new BadRequestException(
				'Unsupported avatar format. Use png, jpeg or webp',
			);
		}

		try {
			const metadata = await sharp(file.buffer).metadata();
			if (!metadata.width || !metadata.height) {
				throw new BadRequestException('Invalid image dimensions');
			}
		} catch {
			throw new BadRequestException('Invalid image content');
		}

		const extensionMap: Record<string, string> = {
			'image/png': '.png',
			'image/jpeg': '.jpg',
			'image/webp': '.webp',
		};

		const extension = extensionMap[file.mimetype];
		if (!extension) {
			throw new BadRequestException('Unsupported image format');
		}

		return extension;
	}
}
